const ROUTE_TO_TAB = Object.entries(TAB_ROUTES).reduce((acc, [tab, href]) => {
  if (tab === 'mockinterview') return acc;
  const path = href.split('?')[0].replace(/\/+$/, '') || '/';
  acc[path] = { tab };
  return acc;
}, {
  '/quickbooks-online-mastery': { tab: 'qbomastery' },
  '/resume-winning-strategy': { tab: 'resumestrategy' },
  '/mock-interview-simulator': { tab: 'interview', interviewSub: 'mock' },
});

const VALID_APP_TABS = new Set(Object.keys(TAB_ROUTES));
// Real tool count for the Dashboard stat strip — every routed tab except Home, the two
// admin-only screens, and the legacy mockinterview alias (a redirect, not a tool). Derived
// so the number can never drift from the actual toolkit again.
const NON_TOOL_TAB_IDS = new Set(['dashboard', 'accessrequests', 'enrollments', 'mockinterview']);
const TOOL_COUNT = Object.keys(TAB_ROUTES).filter((id) => !NON_TOOL_TAB_IDS.has(id)).length;
const INTERVIEW_SUBTAB_IDS = new Set(['winstrat', 'mock', 'common', 'accounting', 'body', 'jdgen', 'salary']);

function normalizePath(pathname = '/') {
  const path = String(pathname || '/').replace(/\/+$/, '');
  return path || '/';
}

function normalizeInterviewSub(value) {
  const raw = String(value || '').trim().toLowerCase();
  const aliases = {
    'interview-winning-strategy': 'winstrat',
    winning: 'winstrat',
    strategy: 'winstrat',
    'mock-interview-simulator': 'mock',
    mockinterview: 'mock',
    questions: 'common',
    qa: 'common',
    qna: 'common',
    'accounting-questions': 'accounting',
    'body-language': 'body',
    jd: 'jdgen',
    'jd-question-generator': 'jdgen',
    'salary-negotiation': 'salary',
  };
  const normalized = aliases[raw] || raw;
  return INTERVIEW_SUBTAB_IDS.has(normalized) ? normalized : null;
}

function tabHref(tabId, opts = {}) {
  const base = TAB_ROUTES[tabId] || `/?tab=${encodeURIComponent(tabId || DEFAULT_APP_TAB)}`;
  const [rawPath, rawQuery = ''] = base.split('?');
  const params = new URLSearchParams(rawQuery);
  const interviewSub = normalizeInterviewSub(opts.interviewSub || opts.sub);
  if (tabId === 'interview' && interviewSub && interviewSub !== 'winstrat') params.set('sub', interviewSub);
  if (opts.courseId) params.set('course', opts.courseId);
  const qs = params.toString();
  return `${rawPath || '/'}${qs ? `?${qs}` : ''}`;
}

function readAppRoute() {
  if (typeof window === 'undefined') {
    return { tab: DEFAULT_APP_TAB, interviewSub: null, explicit: false, courseId: null };
  }
  const path = normalizePath(window.location.pathname);
  const params = new URLSearchParams(window.location.search);
  const route = ROUTE_TO_TAB[path] || null;
  const queryTab = params.get('tab');
  const queryTabIsTopLevel = queryTab && VALID_APP_TABS.has(queryTab);
  const queryTabAsInterviewSub = normalizeInterviewSub(queryTab);
  let tab = queryTabIsTopLevel ? queryTab : (route?.tab || DEFAULT_APP_TAB);
  let interviewSub = normalizeInterviewSub(params.get('sub')) || route?.interviewSub || null;

  if (tab === 'mockinterview') {
    tab = 'interview';
    interviewSub = 'mock';
  } else if (tab === 'interview' && queryTabAsInterviewSub) {
    interviewSub = queryTabAsInterviewSub;
  }

  return {
    tab: VALID_APP_TABS.has(tab) ? tab : DEFAULT_APP_TAB,
    interviewSub,
    explicit: path !== '/' || params.has('tab') || params.has('sub') || params.has('course'),
    courseId: params.get('course') || null,
  };
}

function writeAppRoute(tabId, opts = {}) {
  if (typeof window === 'undefined' || !window.history) return;
  const href = tabHref(tabId, opts);
  const method = opts.replace ? 'replaceState' : 'pushState';
  window.history[method]({ tab: tabId, interviewSub: opts.interviewSub || null }, '', href);
}

function shouldHandleInAppClick(e) {
  return e.button === 0 && !e.metaKey && !e.ctrlKey && !e.shiftKey && !e.altKey && !e.defaultPrevented;
}

// ═══════════════════════════════════════════════════════════════════
// SHARED: ANTHROPIC API HELPER
// ═══════════════════════════════════════════════════════════════════
// Single place every AI feature calls the Claude API. The request is routed
// through the proxy (browser fetch shim in src/main.jsx -> /api/anthropic ->
// Vercel function / Vite dev proxy), which injects the API key server-side.
//
// Unlike the old inline `await res.json()` pattern, this checks res.ok and
// reads the body as text FIRST, so an HTTP error or a non-JSON response (e.g.
// an HTML error page from a misrouted request) throws a *descriptive* error
// that gets logged — instead of silently collapsing into a generic fallback.
async function callClaude({ model = 'claude-sonnet-4-6', max_tokens = 1024, system, messages }, opts = {}) {
  // Attach the Supabase session token so the serverless proxy (api/anthropic/v1/messages.js)
  // can authenticate the caller and gate token spend on admin-or-enrolled — the control that
  // replaces the previously open proxy. Anthropic ignores this header; the proxy consumes it.
  let authHeader = {};
  try {
    const { data } = await supabase.auth.getSession();
    const token = data?.session?.access_token;
    if (token) authHeader = { Authorization: `Bearer ${token}` };
  } catch { /* no session — the proxy will reject with 401 */ }
  const res = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...authHeader },
    body: JSON.stringify({ model, max_tokens, system, messages }),
  });

  const raw = await res.text(); // read once, as text — works for JSON and HTML error pages
  if (!res.ok) {
    console.error('[Claude] HTTP', res.status, raw.slice(0, 500));
    // Surface Anthropic's own error message when the body is JSON.
    let detail = raw.slice(0, 200);
    try {
      const j = JSON.parse(raw);
      if (j?.error?.message) detail = j.error.message;
    } catch {}
    throw new Error(`Claude API ${res.status}: ${detail}`);
  }

  let data;
  try {
    data = JSON.parse(raw);
  } catch {
    console.error('[Claude] non-JSON response (likely a misrouted /api/anthropic request):', raw.slice(0, 500));
    throw new Error('Non-JSON response from the Anthropic proxy');
  }

  const text = (data.content || [])
    .filter(b => b.type === 'text')
    .map(b => b.text)
    .join('\n');

  // Callers that need stop_reason (e.g. to detect max_tokens truncation) pass
  // { returnData: true } and get the full parsed response alongside the text.
  return opts.returnData ? { text, data } : text;
}

