const ROYAL = '#0A84FF';     // = C.primary (literal on purpose)
const CYAN  = '#5AC8FA';     // = C.accent (literal on purpose)
const SKY   = '#6FAAFF';     // = C.soft (literal on purpose)
const ICE   = C.bgSoft;      // ice surface (themes)
