// ── Download helper (browser-safe file download via anchor) ──
function downloadFile(content, filename, mimeType) {
  try {
    const isString = typeof content === 'string';
    // Prepend UTF-8 BOM for CSV/text so Excel opens it correctly
    const needsBom = isString && /csv|text\/plain/.test(mimeType);
    const parts = needsBom ? ['\ufeff', content] : [content];
    const blob = content instanceof Blob ? content : new Blob(parts, { type: mimeType || 'application/octet-stream' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.style.display = 'none';
    document.body.appendChild(a);
    a.click();
    setTimeout(() => {
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    }, 100);
    return true;
  } catch (err) {
    console.error('downloadFile error:', err);
    alert('Download failed: ' + (err.message || 'unknown error'));
    return false;
  }
}

// ── Date helpers (timezone-safe, date-only) ──────────────────────────
// Used by the course platform for the editable cohort/run date (`courses.course_date`).
// We deliberately avoid `new Date('2026-06-17')` (parsed as UTC midnight → shifts a day in
// negative offsets) and `toISOString().slice(0,10)` for "today" (UTC date) — both stay LOCAL
// so the date a creator picks is always the date that displays back.
function todayISODate() {
  const d = new Date();
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
}
// Format a YYYY-MM-DD string with no timezone drift (parse the parts, build a LOCAL date).
function formatCourseDate(iso, opts) {
  if (!iso) return '';
  const [y, m, d] = String(iso).split('-').map(Number);
  if (!y || !m || !d) return '';
  return new Date(y, m - 1, d).toLocaleDateString('en-US', opts || { month: 'long', day: 'numeric', year: 'numeric' });
}
// Auto-derived "June 2026" cohort label from a YYYY-MM-DD course date.
const cohortLabel = (iso) => formatCourseDate(iso, { month: 'long', year: 'numeric' });


// ═══════════════════════════════════════════════════════════════════
// SHARED HOOK: CURRENCY TOGGLE (USD ↔ PHP)
// Persists user's currency preference + FX rate across the entire toolkit
// ═══════════════════════════════════════════════════════════════════
const DEFAULT_FX_RATE = 56.5; // USD to PHP, sensible May 2026 default

function useCurrency() {
  const [currency, setCurrency] = useState('USD');
  const [fxRate, setFxRate] = useState(DEFAULT_FX_RATE);
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    (async () => {
      try {
        const c = await window.storage.get('currency:pref');
        if (c?.value) setCurrency(c.value);
        const r = await window.storage.get('currency:rate');
        if (r?.value) setFxRate(Number(r.value) || DEFAULT_FX_RATE);
      } catch {}
      setLoaded(true);
    })();
  }, []);
  useEffect(() => { if (loaded) window.storage.set('currency:pref', currency).catch(()=>{}); }, [currency, loaded]);
  useEffect(() => { if (loaded) window.storage.set('currency:rate', String(fxRate)).catch(()=>{}); }, [fxRate, loaded]);

  // Convert USD value to display currency
  const convert = (usd) => currency === 'PHP' ? Number(usd) * Number(fxRate) : Number(usd);

  // Format with currency symbol
  const fmt = (usd, decimals = 0) => {
    const val = convert(usd);
    const symbol = currency === 'PHP' ? '₱' : '$';
    return symbol + val.toLocaleString('en-US', { minimumFractionDigits: decimals, maximumFractionDigits: decimals });
  };

  // Format with 2 decimals
  const fmt2 = (usd) => fmt(usd, 2);

  return { currency, setCurrency, fxRate, setFxRate, convert, fmt, fmt2 };
}

// ═══════════════════════════════════════════════════════════════════
// SHARED HOOK: THEME (light / dark / system)
// The resolved theme is the data-theme attribute on <html> — the CSS
// variables in src/index.css do the actual restyling. First paint is
// handled by the inline boot script in index.html, which reads the BARE
// localStorage key 'ui:theme' (raw pref) and stashes it on
// window.__themePref. This hook keeps three places in sync:
//   1. <html data-theme> + the <meta name="theme-color"> tag,
//   2. the bare localStorage mirror (what the boot script + signed-out
//      screens see),
//   3. the per-user window.storage copy (namespaced u:<uid>:ui:theme),
//      so each account keeps its own preference across devices/logins.
// ═══════════════════════════════════════════════════════════════════
const THEME_PREFS = ['light', 'dark', 'system'];

function resolveThemePref(pref) {
  if (pref === 'light' || pref === 'dark') return pref;
  try {
    return window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
  } catch { return 'light'; }
}

function applyResolvedTheme(resolved) {
  document.documentElement.setAttribute('data-theme', resolved);
  const meta = document.querySelector('meta[name="theme-color"]');
  if (meta) meta.setAttribute('content', resolved === 'dark' ? '#06090F' : '#F7FAFF');
}

function useTheme(uid) {
  const [pref, setPref] = useState(() =>
    (typeof window !== 'undefined' && THEME_PREFS.includes(window.__themePref)) ? window.__themePref : 'system');
  const [loaded, setLoaded] = useState(false);
  const prefRef = useRef(pref);
  prefRef.current = pref;

  // Re-read the stored pref whenever the storage namespace changes (sign-in/out).
  // window.storage resolves 'ui:theme' per-user when signed in, bare when signed out.
  // A signed-in account with no saved pref adopts the current (pre-login) choice.
  useEffect(() => {
    let on = true;
    (async () => {
      try {
        if (typeof window !== 'undefined' && window.storage) {
          const r = await window.storage.get('ui:theme').catch(() => null);
          if (!on) return;
          if (r && THEME_PREFS.includes(r.value)) setPref(r.value);
          else if (uid) window.storage.set('ui:theme', prefRef.current).catch(() => {});
        }
      } catch { /* ignore */ }
      if (on) setLoaded(true);
    })();
    return () => { on = false; };
  }, [uid]);

  // Apply + persist on change. The bare mirror always stores the RAW pref
  // ('system', not its resolution) so system-mode users keep following the OS.
  useEffect(() => {
    applyResolvedTheme(resolveThemePref(pref));
    try { localStorage.setItem('ui:theme', pref); } catch { /* ignore */ }
    if (loaded && typeof window !== 'undefined' && window.storage) {
      window.storage.set('ui:theme', pref).catch(() => {});
    }
  }, [pref, loaded]);

  // Follow live OS changes while in system mode.
  useEffect(() => {
    if (pref !== 'system' || typeof window === 'undefined' || !window.matchMedia) return;
    const mq = window.matchMedia('(prefers-color-scheme: dark)');
    const onChange = () => applyResolvedTheme(mq.matches ? 'dark' : 'light');
    mq.addEventListener('change', onChange);
    return () => mq.removeEventListener('change', onChange);
  }, [pref]);

  const cycleTheme = () => setPref(p => (p === 'light' ? 'dark' : p === 'dark' ? 'system' : 'light'));
  return { pref, cycleTheme };
}

// Compact icon-only theme switcher (sidebar profile area + auth screen).
// Cycles light → dark → system; the icon shows the CURRENT preference.
const THEME_META = {
  light:  { Icon: Sun,     label: 'Light theme',  next: 'dark' },
  dark:   { Icon: Moon,    label: 'Dark theme',   next: 'system' },
  system: { Icon: Monitor, label: 'System theme', next: 'light' },
};
function ThemeToggle({ pref, onCycle, fixed, size = 15 }) {
  const meta = THEME_META[pref] || THEME_META.system;
  const Icon = meta.Icon;
  const title = `${meta.label} — switch to ${meta.next} mode`;
  return (
    <button onClick={onCycle} title={title} aria-label={title}
      className={fixed
        ? 'fixed top-4 right-4 z-50 p-2.5 rounded-xl glass-card transition hover:opacity-80'
        : 'flex-shrink-0 p-1.5 rounded-lg transition hover:opacity-80'}
      style={{ color: C.textMute }}>
      <Icon size={size} />
    </button>
  );
}

// ═══════════════════════════════════════════════════════════════════
// LAZY DATA MODULES (src/data/*.js)
// The bulky static content (question banks, playbooks, templates) lives in
// pure-data modules under src/data/ and stays OUT of the main bundle — Vite
// code-splits each dynamic import below into its own chunk, fetched once on
// the first visit of the consuming tab (keep-alive keeps it mounted after).
// Pattern for a consuming tool: a thin wrapper component calls
// useLazyData(loader) and renders <DataLoadingCard/> until the module
// arrives, then hands the module to the real component as `data`.
// ═══════════════════════════════════════════════════════════════════
const loadInterviewQAData = () => import('./data/interview-qa.js');
const loadBrandingData = () => import('./data/branding.js');
const loadEmailTemplatesData = () => import('./data/email-templates.js');
const loadSalaryData = () => import('./data/salary.js');
const loadIndustryAccountingData = () => import('./data/industry-accounting.js');
const loadUsTaxData = () => import('./data/us-tax.js');
const loadWorkflowsData = () => import('./data/workflows.js');
const loadNicheData = () => import('./data/niche.js');
const loadDifficultClientsData = () => import('./data/difficult-clients.js');

function useLazyData(loader) {
  const [mod, setMod] = useState(null);
  const [err, setErr] = useState(null);
  useEffect(() => {
    let on = true;
    loader()
      .then(m => { if (on) setMod(m); })
      .catch(e => { console.error('[data] lazy module failed to load', e); if (on) setErr(e); });
    return () => { on = false; };
    // loader is a module-scope arrow — identity is stable, mount-only is correct
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);
  return { mod, err };
}

function DataLoadingCard({ err }) {
  return (
    <div className="glass-card p-10 flex items-center justify-center gap-3" style={{ minHeight: 180 }}>
      {err ? (
        <>
          <AlertTriangle size={18} style={{ color: C.amber, flexShrink: 0 }} />
          <span style={{ color: C.textSoft, fontSize: 14 }}>Couldn't load this section — check your connection and reload the page.</span>
        </>
      ) : (
        <>
          <Loader2 size={18} className="animate-spin" style={{ color: C.primary, flexShrink: 0 }} />
          <span style={{ color: C.textSoft, fontSize: 14 }}>Loading…</span>
        </>
      )}
    </div>
  );
}

