// COMPONENT: ACCOUNTING 101 COURSE
// ═══════════════════════════════════════════════════════════════════

function Course() {
  const [openIdx, setOpenIdx] = useState(0);
  const [completed, setCompleted] = useState(new Set());
  const [revealAnswer, setRevealAnswer] = useState(new Set());

  const toggleComplete = (i) => {
    const next = new Set(completed);
    if (next.has(i)) next.delete(i); else next.add(i);
    setCompleted(next);
  };
  const toggleAnswer = (i) => {
    const next = new Set(revealAnswer);
    if (next.has(i)) next.delete(i); else next.add(i);
    setRevealAnswer(next);
  };

  const progress = Math.round((completed.size / COURSE_MODULES.length) * 100);

  return (
    <div>
      <SectionHead eyebrow="Tool 02" title="Accounting 101 · Short Course" desc="Eight modules that cover everything a beginner remote bookkeeper needs to think — and work — like a US accountant." />

      {/* Progress */}
      <div style={{ background: SHEEN }} className="glass-card p-6 rounded-2xl mt-6">
        <div className="flex items-center justify-between mb-3">
          <div>
            <div className="text-xs uppercase tracking-[0.2em] font-bold text-slate-600">Your Progress</div>
            <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-3xl font-bold">{completed.size} / {COURSE_MODULES.length} <span className="text-base text-slate-500 font-normal">modules complete</span></div>
          </div>
          <div style={{ color: ROYAL, fontFamily: fontDisplay }} className="text-5xl font-bold">{progress}%</div>
        </div>
        <div className="w-full h-3 bg-slate-200 rounded-full overflow-hidden">
          <div className="h-full transition-all duration-700 relative"
            style={{ width: `${progress}%`, background: `linear-gradient(90deg, ${ROYAL} 0%, ${CYAN} 50%, ${GOLD} 100%)` }}>
            <div className="absolute inset-0 shimmer" />
          </div>
        </div>
      </div>

      <div className="mt-6 space-y-3">
        {COURSE_MODULES.map((m, i) => {
          const open = openIdx === i;
          const done = completed.has(i);
          const shown = revealAnswer.has(i);
          return (
            <div key={i} className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm transition-all hover:shadow-md">
              <button onClick={() => setOpenIdx(open ? -1 : i)}
                className="w-full px-6 py-4 flex items-center gap-4 text-left">
                <button onClick={(e) => { e.stopPropagation(); toggleComplete(i); }}
                  className="flex-shrink-0 transition-transform hover:scale-110">
                  {done
                    ? <CheckCircle2 size={26} style={{ color: ROYAL }} />
                    : <Circle size={26} className="text-slate-300" />}
                </button>
                <div className="flex-1">
                  <div className="text-xs font-bold tracking-wider uppercase text-blue-700">Module {i + 1}</div>
                  <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-lg font-bold leading-tight">{m.title}</div>
                </div>
                {open ? <ChevronDown size={20} className="text-slate-400" /> : <ChevronRight size={20} className="text-slate-400" />}
              </button>

              {open && (
                <div className="px-6 pb-6 fade-in">
                  <div className="border-t border-slate-100 pt-4">
                    <div className="text-slate-700 whitespace-pre-line leading-relaxed text-[15px]">{m.body}</div>

                    <div className="mt-5 p-5 rounded-xl" style={{ background: 'var(--status-info-bg)' }}>
                      <div className="text-xs font-bold tracking-wider uppercase mb-2" style={{ color: ROYAL }}>💡 Quick Quiz</div>
                      <div className="text-slate-800 font-medium">{m.quiz}</div>
                      <button onClick={() => toggleAnswer(i)}
                        className="mt-3 text-xs font-bold px-4 py-1.5 rounded-lg bg-white border border-blue-300 text-blue-700 hover:bg-blue-50">
                        {shown ? 'Hide Answer' : 'Reveal Answer'}
                      </button>
                      {shown && (
                        <div className="mt-3 p-4 rounded-lg bg-white border border-blue-200 text-sm text-slate-700 fade-in leading-relaxed">
                          <span className="font-bold" style={{ color: ROYAL }}>Answer: </span>{m.answer}
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════
// COMPONENT: QUICKBOOKS ONLINE MASTERING PROGRAMME (cloud video course)
// ═══════════════════════════════════════════════════════════════════
// A Thinkific-style course backed by Supabase (see COURSE_SETUP.md):
//   courses → course_modules → course_lessons, per-user lesson_progress,
//   and a course_completions stamp that fixes the certificate's issue date.
// Students watch lessons + earn a downloadable PDF certificate; admins
// (profiles.is_admin) get an in-app builder to author modules/lessons and
// link or upload videos. All writes are also enforced server-side by RLS.

// Parse a pasted URL into a known provider + an embeddable URL.
function parseVideoUrl(url) {
  if (!url) return { provider: null, embedUrl: null };
  const u = String(url).trim();
  const yt = u.match(/(?:youtube\.com\/(?:watch\?v=|embed\/|shorts\/|v\/)|youtu\.be\/)([\w-]{11})/);
  if (yt) return { provider: 'youtube', embedUrl: `https://www.youtube.com/embed/${yt[1]}` };
  const vm = u.match(/vimeo\.com\/(?:video\/)?(\d+)/);
  if (vm) return { provider: 'vimeo', embedUrl: `https://player.vimeo.com/video/${vm[1]}` };
  return { provider: 'mp4', embedUrl: u };
}

// Certificate copy is module-specific: pick the training-description paragraph + ID code by the
// course's slug prefix (qbo-/interview-/resume-), with a general fallback for any other course.
const CERT_DESCRIPTIONS = {
  qbo: 'This training covered end-to-end QuickBooks Online bookkeeping processes, workflow organization, financial task management, and client-ready bookkeeping skills, preparing the student to apply QuickBooks knowledge confidently in real-world bookkeeping and accounting support roles.',
  interview: 'This training covered practical interview preparation strategies, confident communication, question-answering frameworks, professional presentation, and job interview readiness, preparing the student to approach interviews with clarity, confidence, and structure.',
  resume: 'This training covered resume positioning, professional summary development, achievement-based writing, job-focused resume structure, and career profile presentation, preparing the student to create stronger resumes for job applications and career opportunities.',
  general: 'This training covered practical course lessons, guided learning activities, and career-focused skill development designed to help the student apply the knowledge confidently in real-world professional situations.',
};
const CERT_CODES = { qbo: 'QBO', interview: 'INT', resume: 'RES', general: 'GEN' };
function certModuleType(slug = '') {
  if (slug.startsWith('qbo-')) return 'qbo';
  if (slug.startsWith('interview-')) return 'interview';
  if (slug.startsWith('resume-')) return 'resume';
  return 'general';
}

// Certificates always present each course as "… Program" — e.g. "Resume Winning Strategy" →
// "Resume Winning Strategy Program" and "QuickBooks Mastery Course" → "QuickBooks Mastery Program".
// We strip any trailing Course/Program/Programme on the stored title (course.title, editable in
// Supabase) and append a single " Program". This affects ONLY the certificate's displayed title and
// the downloaded PDF filename; catalog cards and the course-player header keep the stored title.
function certificateTitle(rawTitle = '') {
  const base = String(rawTitle).replace(/\s*(course|programme|program)\s*$/i, '').trim();
  return base ? `${base} Program` : 'Program';
}

const COURSE_ROW_SELECT = 'id,slug,title,subtitle,description,month,course_date,published,position,cover_path,source_course_id,access_tier,created_at,updated_at';
const COURSE_MODULE_SELECT = 'id,course_id,title,position';
const COURSE_LESSON_SELECT = 'id,module_id,course_id,title,type,video_url,video_provider,storage_path,text_content,duration_label,position';
// course_completions has only (user_id, course_id, completed_at) — composite PK, no id/created_at
// columns (see COURSE_SETUP.md). Selecting non-existent columns returns a PostgREST 400, so request
// only what the table actually has (the code only ever reads completed_at).
const COURSE_COMPLETION_SELECT = 'user_id,course_id,completed_at';
const FEATURE_GUIDE_SELECT = 'feature_key,title,description,video_url,video_path,video_provider,external_url,is_active,updated_by,created_at,updated_at';

// PAID lesson videos live in a PRIVATE bucket (course-videos) and are served via short-lived
// signed URLs gated by is_enrolled() RLS. Course covers + feature-guide videos stay in the
// PUBLIC course-media bucket. See db/2026-07-08-course-videos-private.sql.
const LESSON_VIDEO_BUCKET = 'course-videos';

// Renders an uploaded lesson video from the private bucket via a signed URL. Falls back to the
// course-media public URL for legacy videos uploaded before the bucket split, so nothing breaks
// during the transition. Re-signs when the lesson changes.
function SignedLessonVideo({ lesson }) {
  const [src, setSrc] = useState(null);
  const [failed, setFailed] = useState(false);
  useEffect(() => {
    let cancelled = false;
    setSrc(null); setFailed(false);
    (async () => {
      const path = lesson?.storage_path;
      if (!path) return;
      const { data, error } = await supabase.storage.from(LESSON_VIDEO_BUCKET).createSignedUrl(path, 3600);
      if (cancelled) return;
      if (data?.signedUrl) { setSrc(data.signedUrl); return; }
      // Legacy object still in the public bucket (pre-split upload) — fall back to its public URL.
      const pub = supabase.storage.from('course-media').getPublicUrl(path)?.data?.publicUrl;
      if (pub) setSrc(pub); else { setFailed(true); if (error) console.error('[course-videos] sign failed', error); }
    })();
    return () => { cancelled = true; };
  }, [lesson?.id, lesson?.storage_path]);
  if (failed) {
    return <div className="rounded-xl border-2 border-dashed border-slate-200 p-10 text-center text-slate-400">This video isn’t available. Refresh, or contact support if it persists.</div>;
  }
  if (!src) {
    return <div className="rounded-xl bg-black/80 flex items-center justify-center text-white/70 text-sm" style={{ height: 240 }}>Loading video…</div>;
  }
  return <video key={lesson.id} controls className="w-full rounded-xl bg-black" style={{ maxHeight: 460 }} src={src} />;
}

function CourseProgram({
  slug = 'qbo-mastery',
  courseId = null,                                       // catalog mode: load by id instead of slug
  onBack = null,                                         // catalog mode: show "← All courses" + its own course header
  eyebrow = 'Video Course',
  courseTitle = 'QuickBooks Online Mastery Program',
  defaultSubtitle = 'From setup to month-end — the complete QBO workflow for remote bookkeepers.',
  certFileName = 'QBO-Mastery-Certificate.pdf',
  comingSoonText = 'Your QuickBooks Online Mastery Program is being prepared. Check back soon.',
  embedded = false,                                      // hide the sticky SectionHead when nested inside a subtab
  initialNotice = null,                                  // one-time success banner (e.g. after duplicating a course)
} = {}) {
  const { user, profile } = useAuth();
  const isAdmin = !!profile?.is_admin;
  const ent = useContext(EntitlementContext);            // plan scope — a deep-link guard for restricted courses
  const showHead = !embedded && !onBack;                 // the catalog/suite supplies its own header instead

  const [course, setCourse] = useState(null);
  const [courseDraft, setCourseDraft] = useState({ title: '', subtitle: '', description: '', month: '', course_date: '' });
  const [notice, setNotice] = useState(initialNotice);   // dismissible green banner shown once on arrival
  const [modules, setModules] = useState([]);            // [{ ...module, lessons: [...] }]
  const [doneIds, setDoneIds] = useState(new Set());
  const [completion, setCompletion] = useState(null);
  const [activeLessonId, setActiveLessonId] = useState(null);
  const [loading, setLoading] = useState(true);
  const [err, setErr] = useState('');
  const [notConfigured, setNotConfigured] = useState(false); // Supabase course tables not created yet
  const [creating, setCreating] = useState(false);       // admin bootstrapping the course row
  const [mode, setMode] = useState(initialNotice ? 'edit' : 'learn'); // 'learn' | 'edit' | 'certificate' (open builder when arriving via duplicate)

  // Builder state
  const [editingLesson, setEditingLesson] = useState(null);  // draft copy of a lesson row
  const [savingLesson, setSavingLesson] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [previewUrl, setPreviewUrl] = useState(null);        // local object URL while authoring
  const [metaBusy, setMetaBusy] = useState(false);           // saving course details / toggling publish
  const [structBusy, setStructBusy] = useState(false);       // adding a module or lesson

  // Certificate state
  const [studentName, setStudentName] = useState(
    user?.user_metadata?.full_name || user?.user_metadata?.name ||
    (user?.email ? user.email.split('@')[0] : '')
  );
  const [certBusy, setCertBusy] = useState(false);
  const certRef = useRef(null);
  const certScaleRef = useRef(null);   // outer responsive wrapper (measured)
  const [certScale, setCertScale] = useState(1);
  const [certBoxH, setCertBoxH]   = useState(0);

  const courseDraftFromRow = (row) => ({
    title: row?.title || '',
    subtitle: row?.subtitle || '',
    description: row?.description || '',
    month: row?.month || '',
    course_date: row?.course_date || '',
  });
  const courseMetaDraftKey = (id) => `course:${id}:metaDraft`;
  const lessonEditorDraftKey = (id) => `course:${id}:lessonDraft`;
  const courseModeKey = (id) => `course:${id}:mode`;
  const activeLessonKey = (id) => `course:${id}:activeLessonId`;

  // Scale the fixed-width (900px) certificate card down to fit its container, so the on-screen
  // preview is smaller/responsive while certRef keeps its intrinsic size for full-quality PDF/print.
  useLayoutEffect(() => {
    if (mode !== 'certificate') return;
    const wrap = certScaleRef.current, card = certRef.current;
    if (!wrap || !card) return;
    const INTRINSIC = 900, PAD = 18;   // PAD leaves room for the card's drop-shadow halo
    const recompute = () => {
      const s = Math.min(1, (wrap.clientWidth - PAD * 2) / INTRINSIC);
      setCertScale(s);
      setCertBoxH(card.offsetHeight * s + PAD * 2);   // offsetHeight is unaffected by the transform
    };
    recompute();
    const ro = new ResizeObserver(recompute);
    ro.observe(wrap); ro.observe(card);
    return () => ro.disconnect();
  }, [mode, studentName, course, completion]);

  // ── Load course + curriculum + this user's progress ──
  async function load() {
    setLoading(true); setErr(''); setNotConfigured(false);
    try {
      let cq = supabase.from('courses').select(COURSE_ROW_SELECT);
      cq = courseId ? cq.eq('id', courseId) : cq.eq('slug', slug);
      const { data: courseRow, error: cErr } = await cq.maybeSingle();
      if (cErr) throw cErr;
      if (!courseRow) { setCourse(null); setModules([]); setLoading(false); return; }
      setCourse(courseRow);
      let nextCourseDraft = courseDraftFromRow(courseRow);
      if (isAdmin && typeof window !== 'undefined' && window.storage) {
        try {
          const stored = await window.storage.get(courseMetaDraftKey(courseRow.id));
          if (stored?.value) {
            const parsed = JSON.parse(stored.value);
            if (parsed?.courseUpdatedAt === (courseRow.updated_at || '') && parsed?.draft) {
              nextCourseDraft = { ...nextCourseDraft, ...parsed.draft };
              setNotice(n => n || 'Restored unsaved course changes from this browser.');
            }
          }
        } catch {}
      }
      setCourseDraft(nextCourseDraft);

      const [{ data: mods, error: mErr }, { data: lessons, error: lErr }] = await Promise.all([
        supabase.from('course_modules').select(COURSE_MODULE_SELECT).eq('course_id', courseRow.id).order('position'),
        supabase.from('course_lessons').select(COURSE_LESSON_SELECT).eq('course_id', courseRow.id).order('position'),
      ]);
      if (mErr) throw mErr;
      if (lErr) throw lErr;
      const nested = (mods || []).map(m => ({
        ...m, lessons: (lessons || []).filter(l => l.module_id === m.id),
      }));
      setModules(nested);

      const [{ data: prog }, { data: comp }] = await Promise.all([
        supabase.from('lesson_progress').select('lesson_id')
          .eq('course_id', courseRow.id).eq('user_id', user.id),
        supabase.from('course_completions').select(COURSE_COMPLETION_SELECT)
          .eq('course_id', courseRow.id).eq('user_id', user.id).maybeSingle(),
      ]);
      const done = new Set((prog || []).map(p => p.lesson_id));
      setDoneIds(done);
      setCompletion(comp || null);

      const all = nested.flatMap(m => m.lessons);
      let storedActiveLessonId = null;
      if (typeof window !== 'undefined' && window.storage) {
        try { storedActiveLessonId = (await window.storage.get(activeLessonKey(courseRow.id)))?.value || null; } catch {}
      }
      setActiveLessonId(prev => {
        if (prev && all.some(l => l.id === prev)) return prev;
        if (storedActiveLessonId && all.some(l => l.id === storedActiveLessonId)) return storedActiveLessonId;
        return (all.find(l => !done.has(l.id)) || all[0])?.id || null;
      });
      if (!initialNotice && typeof window !== 'undefined' && window.storage) {
        try {
          const storedMode = (await window.storage.get(courseModeKey(courseRow.id)))?.value;
          if (['learn', 'edit', 'certificate'].includes(storedMode)) setMode(storedMode);
        } catch {}
      }
      if (isAdmin && typeof window !== 'undefined' && window.storage) {
        try {
          const storedLessonDraft = await window.storage.get(lessonEditorDraftKey(courseRow.id));
          if (storedLessonDraft?.value) {
            const parsed = JSON.parse(storedLessonDraft.value);
            if (parsed?.id && all.some(l => l.id === parsed.id)) {
              setEditingLesson(parsed);
              setNotice(n => n || 'Restored an unsaved lesson draft from this browser.');
            }
          }
        } catch {}
      }
    } catch (e) {
      logDbError('[CourseProgram] load', e, { slug, courseId });
      const msg = e?.message || '';
      // The course tables don't exist yet (COURSE_SETUP.md not run) — treat as "not configured"
      // and show a friendly setup/coming-soon state instead of a raw red Postgres error.
      if (e?.code === 'PGRST205' || /schema cache|could not find the table|does not exist/i.test(msg)) {
        setNotConfigured(true);
        setCourse(null);
      } else {
        setErr(msg || 'Failed to load the course.');
      }
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => { if (user?.id) load(); /* eslint-disable-next-line */ }, [user?.id, courseId, isAdmin]);
  // Revoke the local preview object URL when it changes / on unmount.
  useEffect(() => () => { if (previewUrl) URL.revokeObjectURL(previewUrl); }, [previewUrl]);

  // ── Derived ──
  const allLessons = modules.flatMap(m => m.lessons || []);
  const totalLessons = allLessons.length;
  const completedCount = allLessons.filter(l => doneIds.has(l.id)).length;
  const progressPct = totalLessons ? Math.round((completedCount / totalLessons) * 100) : 0;
  const isComplete = totalLessons > 0 && completedCount === totalLessons;
  const activeLesson = allLessons.find(l => l.id === activeLessonId) || null;
  const savedCourseDraft = courseDraftFromRow(course);
  const courseMetaDirty = !!(isAdmin && course && JSON.stringify(courseDraft) !== JSON.stringify(savedCourseDraft));
  const originalEditingLesson = editingLesson ? allLessons.find(l => l.id === editingLesson.id) : null;
  const lessonComparable = (l = {}) => ({
    title: l.title || '',
    type: l.type || 'video',
    video_url: l.video_url || '',
    video_provider: l.video_provider || null,
    storage_path: l.storage_path || null,
    text_content: l.text_content || '',
    duration_label: l.duration_label || '',
  });
  const lessonDraftDirty = !!(isAdmin && editingLesson && originalEditingLesson &&
    JSON.stringify(lessonComparable(editingLesson)) !== JSON.stringify(lessonComparable(originalEditingLesson)));
  const hasUnsavedCourseWork = courseMetaDirty || lessonDraftDirty;

  const clearStoredValue = (key) => {
    if (typeof window !== 'undefined' && window.storage && key) window.storage.set(key, '').catch(() => {});
  };
  const clearLessonDraft = () => course?.id && clearStoredValue(lessonEditorDraftKey(course.id));
  const closeLessonEditor = () => {
    if (savingLesson) return;
    if (lessonDraftDirty && !window.confirm('Discard unsaved lesson changes?')) return;
    clearLessonDraft();
    if (previewUrl) { URL.revokeObjectURL(previewUrl); setPreviewUrl(null); }
    setEditingLesson(null);
  };
  const confirmLeaveCourse = () => !hasUnsavedCourseWork || window.confirm('You have unsaved course changes. Leave this course without saving?');

  useEffect(() => {
    if (!course?.id || !isAdmin || typeof window === 'undefined' || !window.storage) return;
    const key = courseMetaDraftKey(course.id);
    if (!courseMetaDirty) {
      clearStoredValue(key);
      return;
    }
    const timer = setTimeout(() => {
      window.storage.set(key, JSON.stringify({
        courseUpdatedAt: course.updated_at || '',
        draft: courseDraft,
        savedAt: new Date().toISOString(),
      })).catch(() => {});
    }, 350);
    return () => clearTimeout(timer);
  }, [course?.id, course?.updated_at, isAdmin, courseMetaDirty, courseDraft]);

  useEffect(() => {
    if (!course?.id || !isAdmin || !editingLesson || typeof window === 'undefined' || !window.storage) return;
    window.storage.set(lessonEditorDraftKey(course.id), JSON.stringify(editingLesson)).catch(() => {});
  }, [course?.id, isAdmin, editingLesson]);

  useEffect(() => {
    if (!hasUnsavedCourseWork) return;
    const onBeforeUnload = (e) => {
      e.preventDefault();
      e.returnValue = '';
    };
    window.addEventListener('beforeunload', onBeforeUnload);
    return () => window.removeEventListener('beforeunload', onBeforeUnload);
  }, [hasUnsavedCourseWork]);

  useEffect(() => {
    if (!course?.id || !activeLessonId || typeof window === 'undefined' || !window.storage) return;
    window.storage.set(activeLessonKey(course.id), activeLessonId).catch(() => {});
  }, [course?.id, activeLessonId]);

  useEffect(() => {
    if (!course?.id || typeof window === 'undefined' || !window.storage) return;
    window.storage.set(courseModeKey(course.id), mode).catch(() => {});
  }, [course?.id, mode]);

  // Display + certificate metadata. Prefer the loaded course row, fall back to the prop defaults
  // (which the catalog supplies per-prefix). This keeps a course opened from the Resume/Interview
  // catalogs from showing the QBO defaults, and names the certificate after the actual course.
  const displayTitle = course?.title || courseTitle;
  const displaySubtitle = course?.subtitle || defaultSubtitle;
  const certName = course?.title
    ? `${certificateTitle(course.title).replace(/[^\w]+/g, '-').replace(/^-+|-+$/g, '')}-Certificate.pdf`
    : certFileName;

  // ── Learner actions ──
  function goAdjacent(lesson, delta) {
    const idx = allLessons.findIndex(l => l.id === lesson.id);
    const next = allLessons[idx + delta];
    if (next) setActiveLessonId(next.id);
  }

  async function markComplete(lesson) {
    if (!lesson) return;
    if (doneIds.has(lesson.id)) { goAdjacent(lesson, 1); return; }
    try {
      const { error } = await supabase.from('lesson_progress').upsert(
        { user_id: user.id, lesson_id: lesson.id, course_id: course.id },
        { onConflict: 'user_id,lesson_id', ignoreDuplicates: true }
      );
      if (error) throw error;
      const next = new Set(doneIds); next.add(lesson.id); setDoneIds(next);
      const newCount = allLessons.filter(l => next.has(l.id)).length;
      if (totalLessons > 0 && newCount === totalLessons && !completion) {
        const { error: cErr } = await supabase.from('course_completions').upsert(
          { user_id: user.id, course_id: course.id },
          { onConflict: 'user_id,course_id', ignoreDuplicates: true }
        );
        if (cErr) throw cErr;
        const { data: c2 } = await supabase.from('course_completions').select(COURSE_COMPLETION_SELECT)
          .eq('user_id', user.id).eq('course_id', course.id).maybeSingle();
        setCompletion(c2 || { completed_at: new Date().toISOString() });
      }
      goAdjacent(lesson, 1);
    } catch (e) {
      logDbError('[CourseProgram] progress', e, { courseId: course?.id });
      setErr(describeDbError(e, 'Could not save your progress.'));
    }
  }

  // ── Builder: bootstrap the course row (admin-only; RLS restricts inserts to is_admin()) ──
  async function createCourse() {
    setCreating(true); setErr('');
    try {
      const { error } = await supabase.from('courses').insert({
        slug, title: displayTitle, subtitle: displaySubtitle, published: false,
        course_date: todayISODate(),
      });
      if (error) throw error;
      await load();
      setMode('edit');
    } catch (e) {
      logDbError('[CourseProgram] create', e, { slug });
      setErr(describeDbError(e, 'Could not create the course.'));
    } finally { setCreating(false); }
  }

  // ── Builder: course meta ──
  async function saveCourseMeta() {
    setMetaBusy(true); setErr('');
    try {
      const { error } = await supabase.from('courses').update({
        title: courseDraft.title, subtitle: courseDraft.subtitle,
        description: courseDraft.description, course_date: courseDraft.course_date || null,
        updated_at: new Date().toISOString(),
      }).eq('id', course.id);
      if (error) throw error;
      clearStoredValue(courseMetaDraftKey(course.id));
      await load();
    } catch (e) { logDbError('[CourseProgram] saveMeta', e, { courseId: course.id }); setErr(describeDbError(e, 'Could not save course details.')); }
    finally { setMetaBusy(false); }
  }
  async function togglePublished() {
    setMetaBusy(true); setErr('');
    try {
      const { error } = await supabase.from('courses')
        .update({ published: !course.published, updated_at: new Date().toISOString() }).eq('id', course.id);
      if (error) throw error;
      await load();
    } catch (e) { logDbError('[CourseProgram] togglePublished', e, { courseId: course.id }); setErr(describeDbError(e, 'Could not change publish state.')); }
    finally { setMetaBusy(false); }
  }

  // ── Builder: modules ──
  async function addModule() {
    setStructBusy(true); setErr('');
    try {
      const { error } = await supabase.from('course_modules')
        .insert({ course_id: course.id, title: 'New module', position: modules.length });
      if (error) throw error;
      await load();
    } catch (e) { logDbError('[CourseProgram] addModule', e, { courseId: course.id }); setErr(describeDbError(e, 'Could not add module.')); }
    finally { setStructBusy(false); }
  }
  async function renameModule(m, title) {
    if (title === m.title) return;
    try {
      const { error } = await supabase.from('course_modules').update({ title }).eq('id', m.id);
      if (error) throw error;
      setModules(ms => ms.map(x => x.id === m.id ? { ...x, title } : x));
    } catch (e) { logDbError('[CourseProgram] renameModule', e, { moduleId: m.id }); setErr(describeDbError(e, 'Could not rename module.')); }
  }
  async function deleteModule(m) {
    if (!window.confirm(`Delete "${m.title}" and all its lessons? This cannot be undone.`)) return;
    try {
      const { error } = await supabase.from('course_modules').delete().eq('id', m.id);
      if (error) throw error;
      await load();
    } catch (e) { logDbError('[CourseProgram] deleteModule', e, { moduleId: m.id }); setErr(describeDbError(e, 'Could not delete module.')); }
  }
  async function moveModule(idx, dir) {
    const j = idx + dir;
    if (j < 0 || j >= modules.length) return;
    const arr = [...modules];
    [arr[idx], arr[j]] = [arr[j], arr[idx]];
    try {
      await Promise.all(arr.map((m, i) => supabase.from('course_modules').update({ position: i }).eq('id', m.id)));
      await load();
    } catch (e) { logDbError('[CourseProgram] moveModule', e, { courseId: course.id }); setErr(describeDbError(e, 'Could not reorder modules.')); }
  }

  // ── Builder: lessons ──
  async function addLesson(m) {
    setStructBusy(true); setErr('');
    try {
      const { data, error } = await supabase.from('course_lessons').insert({
        module_id: m.id, course_id: course.id, title: 'New lesson',
        type: 'video', position: (m.lessons?.length || 0),
      }).select(COURSE_LESSON_SELECT).single();
      if (error) throw error;
      await load();
      setEditingLesson({ ...data });
    } catch (e) { logDbError('[CourseProgram] addLesson', e, { courseId: course.id, moduleId: m.id }); setErr(describeDbError(e, 'Could not add lesson.')); }
    finally { setStructBusy(false); }
  }
  async function deleteLesson(l) {
    if (!window.confirm(`Delete lesson "${l.title}"?`)) return;
    try {
      const { error } = await supabase.from('course_lessons').delete().eq('id', l.id);
      if (error) throw error;
      // Purge the uploaded video AFTER the row delete — and only if no other course (e.g. a
      // duplicate that reused this path) still references it. Order matters: deleting first means
      // this lesson's own reference is gone before the check.
      if (l.video_provider === 'upload' && l.storage_path) await removeMediaIfUnreferenced([l.storage_path]);
      setActiveLessonId(prev => (prev === l.id ? null : prev)); // don't keep a deleted lesson active
      await load();
    } catch (e) { logDbError('[CourseProgram] deleteLesson', e, { courseId: course.id, lessonId: l.id }); setErr(describeDbError(e, 'Could not delete lesson.')); }
  }
  async function moveLesson(m, idx, dir) {
    const j = idx + dir;
    if (j < 0 || j >= m.lessons.length) return;
    const arr = [...m.lessons];
    [arr[idx], arr[j]] = [arr[j], arr[idx]];
    try {
      await Promise.all(arr.map((l, i) => supabase.from('course_lessons').update({ position: i }).eq('id', l.id)));
      await load();
    } catch (e) { logDbError('[CourseProgram] moveLesson', e, { courseId: course.id, moduleId: m.id }); setErr(describeDbError(e, 'Could not reorder lessons.')); }
  }

  async function uploadVideo(file) {
    if (!file || !course) return;
    const MAX_MB = 50;
    if (!/^video\//i.test(file.type)) { setErr('Please choose a video file (MP4, MOV, WebM…), or paste a YouTube/Vimeo link instead.'); return; }
    if (file.size > MAX_MB * 1024 * 1024) {
      setErr(`That video is ${(file.size / 1024 / 1024).toFixed(0)} MB — the upload limit is ${MAX_MB} MB. Compress it, or host it on YouTube/Vimeo and paste the link.`);
      return;
    }
    setUploading(true); setErr('');
    if (previewUrl) URL.revokeObjectURL(previewUrl);
    setPreviewUrl(URL.createObjectURL(file));
    try {
      const safe = file.name.replace(/[^\w.\-]+/g, '_');
      const path = `lessons/${course.id}/${crypto.randomUUID()}-${safe}`;
      // Paid lesson videos go to the PRIVATE course-videos bucket (served via signed URLs).
      const { error } = await supabase.storage.from(LESSON_VIDEO_BUCKET)
        .upload(path, file, { upsert: false, contentType: file.type || 'video/mp4' });
      if (error) throw error;
      setEditingLesson(d => ({ ...d, storage_path: path, video_provider: 'upload', video_url: '' }));
    } catch (e) {
      logDbError('[CourseProgram] video upload', e, { courseId: course.id });
      setErr(describeDbError(e, 'Video upload failed — check the file size and that you have admin access.'));
    } finally {
      setUploading(false);
    }
  }

  async function saveLesson() {
    if (!editingLesson) return;
    const d = editingLesson;
    const isVideo = d.type === 'video';
    const isUpload = isVideo && d.video_provider === 'upload' && !!d.storage_path;
    const hasLink = isVideo && !isUpload && !!(d.video_url || '').trim();
    const hasText = !!(d.text_content || '').trim();
    // Don't let an empty lesson be saved (it would show "No video added yet" to students).
    if (isVideo && !isUpload && !hasLink && !hasText) {
      setErr('Add a video link, upload a file, or write some lesson notes before saving.'); return;
    }
    if (!isVideo && !hasText) { setErr('Add some lesson content before saving.'); return; }
    setSavingLesson(true); setErr('');
    try {
      const oldPath = allLessons.find(x => x.id === d.id)?.storage_path; // for cleanup if the video changed
      const payload = {
        title: (d.title || '').trim() || 'Untitled lesson',
        type: d.type || 'video',
        video_url: isVideo && !isUpload ? (d.video_url || null) : null,
        video_provider: isVideo ? (isUpload ? 'upload' : parseVideoUrl(d.video_url).provider) : null,
        storage_path: isUpload ? d.storage_path : null,
        text_content: d.text_content || null,
        duration_label: (d.duration_label || '').trim() || null,
      };
      const { error } = await supabase.from('course_lessons').update(payload).eq('id', d.id);
      if (error) throw error;
      // If a previously-uploaded file was replaced or removed, purge the old object — but only if no
      // other course (e.g. a duplicate that reused this path) still references it (copy-on-write).
      if (oldPath && oldPath !== payload.storage_path) await removeMediaIfUnreferenced([oldPath]);
      if (previewUrl) { URL.revokeObjectURL(previewUrl); setPreviewUrl(null); }
      clearLessonDraft();
      setEditingLesson(null);
      await load();
    } catch (e) { logDbError('[CourseProgram] saveLesson', e, { courseId: course?.id, lessonId: d.id }); setErr(describeDbError(e, 'Could not save lesson.')); }
    finally { setSavingLesson(false); }
  }

  // ── Certificate ──
  async function downloadCertificate() {
    if (!certRef.current) return;
    setCertBusy(true); setErr('');
    try {
      const [{ jsPDF }, h2c] = await Promise.all([import('jspdf'), import('html2canvas')]);
      const html2canvas = h2c.default;
      const canvas = await html2canvas(certRef.current, { scale: 2, backgroundColor: '#ffffff', useCORS: true });
      const img = canvas.toDataURL('image/png');
      const pdf = new jsPDF({ orientation: 'landscape', unit: 'pt', format: 'a4' });
      const pw = pdf.internal.pageSize.getWidth();
      const ph = pdf.internal.pageSize.getHeight();
      const ratio = Math.min(pw / canvas.width, ph / canvas.height);
      const w = canvas.width * ratio, h = canvas.height * ratio;
      pdf.addImage(img, 'PNG', (pw - w) / 2, (ph - h) / 2, w, h);
      downloadFile(pdf.output('blob'), certName, 'application/pdf');
    } catch (e) {
      console.error('[CourseProgram] certificate failed:', e);
      setErr('Certificate download failed: ' + (e.message || 'unknown error'));
    } finally { setCertBusy(false); }
  }
  function printCertificate() {
    if (!certRef.current) return;
    const w = window.open('', '_blank');
    if (!w) { setErr('Pop-up blocked — allow pop-ups for this site to print.'); return; }
    w.document.write(
      '<!doctype html><html><head><title>Certificate</title>' +
      // <base> makes the relative /logo-alex.png <img> resolve inside the about:blank window.
      '<base href="' + window.location.origin + '/">' +
      '<style>@page{size:A4 landscape;margin:0}html,body{margin:0;padding:0;display:flex;justify-content:center;align-items:center;min-height:100vh;background:#fff}</style>' +
      '</head><body>' + certRef.current.outerHTML + '</body></html>'
    );
    w.document.close();
    setTimeout(() => { try { w.focus(); w.print(); } catch (_) { /* ignore */ } }, 350);
  }

  // ── Video / content renderer ──
  function renderVideo(lesson) {
    if (!lesson) return null;
    if (lesson.type === 'text') {
      return lesson.text_content
        ? <div className="text-slate-700 whitespace-pre-line leading-relaxed text-[15px]">{lesson.text_content}</div>
        : <div className="rounded-xl border-2 border-dashed border-slate-200 p-10 text-center text-slate-400">No content yet.</div>;
    }
    if (lesson.video_provider === 'upload' && lesson.storage_path) {
      // Private bucket → signed URL (with legacy public-bucket fallback) via SignedLessonVideo.
      return <SignedLessonVideo key={lesson.id} lesson={lesson} />;
    }
    if (lesson.video_provider === 'mp4' && lesson.video_url) {
      return <video key={lesson.id} controls className="w-full rounded-xl bg-black" style={{ maxHeight: 460 }} src={lesson.video_url} />;
    }
    if ((lesson.video_provider === 'youtube' || lesson.video_provider === 'vimeo') && lesson.video_url) {
      const { embedUrl } = parseVideoUrl(lesson.video_url);
      if (embedUrl) return (
        <div style={{ position: 'relative', paddingBottom: '56.25%', height: 0 }} className="rounded-xl overflow-hidden bg-black">
          <iframe src={embedUrl} title={lesson.title} loading="lazy"
            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" allowFullScreen
            style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', border: 0 }} />
        </div>
      );
    }
    return (
      <div className="rounded-xl border-2 border-dashed border-slate-200 p-10 text-center text-slate-400">
        <Video size={28} className="mx-auto mb-2 opacity-60" />
        No video added yet.
      </div>
    );
  }

  // ── Sub-views ──
  function renderLearner() {
    if (totalLessons === 0) {
      return (
        <div className="mt-6 glass-card rounded-2xl p-10 text-center" style={{ background: SHEEN }}>
          <GraduationCap size={36} className="mx-auto mb-3" style={{ color: ROYAL }} />
          <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-lg font-bold">
            {isAdmin ? 'Your course is empty' : 'Curriculum coming soon'}
          </div>
          <div className="text-slate-500 mt-1 text-sm">
            {isAdmin ? 'Open the builder to add your first module and lessons.' : 'Lessons are being added. Check back shortly.'}
          </div>
          {isAdmin && (
            <button onClick={() => setMode('edit')} className="mt-4 px-5 py-2.5 rounded-xl text-white font-semibold inline-flex items-center gap-2"
              style={{ background: `linear-gradient(180deg, ${C.primaryHi}, ${C.primary})` }}>
              <Edit3 size={16} /> Open the builder
            </button>
          )}
        </div>
      );
    }
    const activeIdx = activeLesson ? allLessons.findIndex(l => l.id === activeLesson.id) : -1;
    return (
      <div className="mt-6 grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Curriculum — below the player on mobile, sticky sidebar on desktop */}
        <div className="order-2 lg:order-1 lg:col-span-1 space-y-4 lg:sticky lg:top-24 lg:self-start lg:max-h-[calc(100vh-7rem)] lg:overflow-y-auto">
          <div style={{ background: SHEEN }} className="glass-card p-5 rounded-2xl">
            <div className="flex items-center justify-between mb-2">
              <div className="text-xs uppercase tracking-[0.2em] font-bold text-slate-600">Your Progress</div>
              <div style={{ color: ROYAL, fontFamily: fontDisplay }} className="text-2xl font-bold">{progressPct}%</div>
            </div>
            <div className="w-full h-3 bg-slate-200 rounded-full overflow-hidden">
              <div className="h-full transition-all duration-700 relative"
                style={{ width: `${progressPct}%`, background: `linear-gradient(90deg, ${ROYAL} 0%, ${CYAN} 50%, ${GOLD} 100%)` }}>
                <div className="absolute inset-0 shimmer" />
              </div>
            </div>
            <div className="text-xs text-slate-500 mt-2">{completedCount} of {totalLessons} lessons complete</div>
            {isComplete && (
              <button onClick={() => setMode('certificate')} className="mt-3 w-full px-4 py-2.5 rounded-xl text-white font-semibold inline-flex items-center justify-center gap-2"
                style={{ background: `linear-gradient(135deg, ${C.primary}, ${C.accent})` }}>
                <Award size={16} /> Get your certificate
              </button>
            )}
          </div>
          {modules.map((m, mi) => (
            <div key={m.id} className="bg-white rounded-2xl border border-slate-200 overflow-hidden">
              <div className="px-4 py-3 border-b border-slate-100">
                <div className="text-[11px] font-bold tracking-wider uppercase text-blue-700">Module {mi + 1}</div>
                <div style={{ fontFamily: fontDisplay, color: NAVY }} className="font-bold leading-tight text-[15px]">{m.title}</div>
              </div>
              <div className="p-2">
                {(m.lessons || []).length === 0 && <div className="px-3 py-2 text-xs text-slate-400 italic">No lessons yet</div>}
                {(m.lessons || []).map((l) => {
                  const done = doneIds.has(l.id);
                  const active = l.id === activeLessonId;
                  return (
                    <button key={l.id} onClick={() => setActiveLessonId(l.id)}
                      className="w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-left transition-colors hover:bg-slate-50"
                      style={active ? { background: ICE } : undefined}>
                      {done ? <CheckCircle2 size={18} style={{ color: ROYAL }} className="flex-shrink-0" />
                            : <Circle size={18} className="text-slate-300 flex-shrink-0" />}
                      <span className="flex-1 text-sm truncate" style={{ color: active ? NAVY : C.text, fontWeight: active ? 700 : 500 }}>{l.title}</span>
                      {l.type === 'video' ? <Play size={13} className="text-slate-400 flex-shrink-0" /> : <FileText size={13} className="text-slate-400 flex-shrink-0" />}
                      {l.duration_label && <span className="text-[11px] text-slate-400 flex-shrink-0">{l.duration_label}</span>}
                    </button>
                  );
                })}
              </div>
            </div>
          ))}
        </div>

        {/* Player */}
        <div className="order-1 lg:order-2 lg:col-span-2">
          {activeLesson ? (
            <div className="glass-card rounded-2xl p-5 sm:p-6" style={{ background: '#fff' }}>
              {renderVideo(activeLesson)}
              <div className="mt-5">
                <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-xl font-bold">{activeLesson.title}</div>
                {activeLesson.duration_label && <div className="text-xs text-slate-400 mt-0.5">{activeLesson.duration_label}</div>}
                {activeLesson.type === 'video' && activeLesson.text_content && (
                  <div className="mt-4 text-slate-700 whitespace-pre-line leading-relaxed text-[15px]">{activeLesson.text_content}</div>
                )}
              </div>
              <div className="mt-5 pt-4 border-t border-slate-100">
                <div className="text-[11px] font-bold uppercase tracking-wider text-slate-400 mb-3">Lesson {activeIdx + 1} of {totalLessons}</div>
                <div className="flex items-center justify-between gap-2 flex-wrap">
                  <button onClick={() => goAdjacent(activeLesson, -1)} disabled={activeIdx <= 0}
                    className="px-4 py-2.5 rounded-xl text-sm font-semibold text-slate-600 border border-slate-200 disabled:opacity-40 inline-flex items-center gap-1.5">
                    <ArrowLeft size={15} /> Previous
                  </button>
                  <div className="flex items-center gap-2">
                    {doneIds.has(activeLesson.id) ? (
                      <span className="px-4 py-2.5 rounded-xl text-sm font-semibold inline-flex items-center gap-2" style={{ background: 'var(--status-ok-bg)', color: 'var(--status-ok-fg)' }}>
                        <Check size={16} /> Completed
                      </span>
                    ) : (
                      <button onClick={() => markComplete(activeLesson)}
                        className="px-5 py-2.5 rounded-xl text-white text-sm font-semibold inline-flex items-center gap-2"
                        style={{ background: `linear-gradient(180deg, ${C.primaryHi}, ${C.primary})` }}>
                        <CheckCircle2 size={16} /> Mark complete
                      </button>
                    )}
                    <button onClick={() => goAdjacent(activeLesson, 1)} disabled={activeIdx >= totalLessons - 1}
                      className="px-5 py-2.5 rounded-xl text-sm font-semibold inline-flex items-center gap-2 disabled:opacity-40"
                      style={doneIds.has(activeLesson.id)
                        ? { background: `linear-gradient(180deg, ${C.primaryHi}, ${C.primary})`, color: '#fff' }
                        : { background: 'var(--wash-strong)', color: C.textSoft }}>
                      Next <ArrowRight size={15} />
                    </button>
                  </div>
                </div>
              </div>
            </div>
          ) : (
            <div className="glass-card rounded-2xl p-10 text-center text-slate-400">Select a lesson to begin.</div>
          )}
        </div>
      </div>
    );
  }

  function renderBuilder() {
    return (
      <div className="mt-6 space-y-5">
        {/* Course settings */}
        <div className="glass-card rounded-2xl p-5" style={{ background: SHEEN }}>
          <div className="flex items-center justify-between mb-4 flex-wrap gap-3">
            <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-lg font-bold flex items-center gap-2"><Edit3 size={18} /> Course settings</div>
            <button onClick={togglePublished} disabled={metaBusy} className="px-4 py-2 rounded-xl text-sm font-semibold inline-flex items-center gap-2 disabled:opacity-60"
              style={course.published ? { background: 'var(--status-ok-bg)', color: 'var(--status-ok-fg)' } : { background: 'var(--status-warn-bg)', color: 'var(--status-warn-fg)' }}>
              {metaBusy ? <Loader2 size={15} className="animate-spin" /> : course.published ? <Eye size={15} /> : <Lock size={15} />}
              {course.published ? 'Published' : 'Draft'}
              <span className="opacity-60 font-normal">· click to {course.published ? 'unpublish' : 'publish'}</span>
            </button>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            <label className="block">
              <span className="text-xs font-semibold text-slate-500">Title</span>
              <input value={courseDraft.title} onChange={e => setCourseDraft(d => ({ ...d, title: e.target.value }))}
                className="mt-1 w-full px-3 py-2 rounded-lg border border-slate-200 text-sm" />
            </label>
            <label className="block">
              <span className="text-xs font-semibold text-slate-500">Subtitle</span>
              <input value={courseDraft.subtitle} onChange={e => setCourseDraft(d => ({ ...d, subtitle: e.target.value }))}
                className="mt-1 w-full px-3 py-2 rounded-lg border border-slate-200 text-sm" />
            </label>
            <label className="block sm:col-span-2">
              <span className="text-xs font-semibold text-slate-500 inline-flex items-center gap-1.5"><CalendarClock size={13} /> Course Date / Cohort Date</span>
              <div className="mt-1 flex flex-wrap items-center gap-2">
                <input type="date" value={courseDraft.course_date || ''}
                  onChange={e => setCourseDraft(d => ({ ...d, course_date: e.target.value }))}
                  className="px-3 py-2 rounded-lg border border-slate-200 text-sm" />
                <button type="button" onClick={() => setCourseDraft(d => ({ ...d, course_date: todayISODate() }))}
                  className="px-3 py-2 rounded-lg border border-slate-200 text-xs font-semibold text-slate-600 hover:bg-slate-50">Today</button>
                {courseDraft.course_date
                  ? <span className="text-xs font-semibold px-2 py-1 rounded-full" style={{ background: 'var(--status-info-bg)', color: 'var(--status-info-fg)' }}>Cohort: {cohortLabel(courseDraft.course_date)}</span>
                  : course.month ? <span className="text-xs text-slate-400">Legacy label: {course.month}</span> : null}
              </div>
              <span className="block mt-1 text-[11px] text-slate-400">Defaults to today. Update this for monthly cohorts or future course runs.</span>
            </label>
            <label className="block sm:col-span-2">
              <span className="text-xs font-semibold text-slate-500">Description</span>
              <textarea value={courseDraft.description} onChange={e => setCourseDraft(d => ({ ...d, description: e.target.value }))} rows={2}
                className="mt-1 w-full px-3 py-2 rounded-lg border border-slate-200 text-sm" />
            </label>
          </div>
          <button onClick={saveCourseMeta} disabled={metaBusy} className="mt-3 px-4 py-2 rounded-xl text-white text-sm font-semibold inline-flex items-center gap-2 disabled:opacity-60"
            style={{ background: `linear-gradient(180deg, ${C.primaryHi}, ${C.primary})` }}>{metaBusy ? <Loader2 size={15} className="animate-spin" /> : <Save size={15} />} Save details</button>
        </div>

        {/* Modules */}
        {modules.map((m, mi) => (
          <div key={m.id} className="bg-white rounded-2xl border border-slate-200 p-4">
            <div className="flex items-center gap-2">
              <span className="text-[11px] font-bold tracking-wider uppercase text-blue-700 flex-shrink-0">Module {mi + 1}</span>
              <input defaultValue={m.title} onBlur={e => renameModule(m, e.target.value)}
                className="flex-1 min-w-0 px-2 py-1.5 rounded-lg border border-transparent hover:border-slate-200 focus:border-slate-300 focus:outline-none font-bold text-[15px]"
                style={{ fontFamily: fontDisplay, color: NAVY }} />
              <button onClick={() => moveModule(mi, -1)} disabled={mi === 0} className="p-1.5 rounded-lg text-slate-400 hover:bg-slate-100 disabled:opacity-30"><ChevronUp size={16} /></button>
              <button onClick={() => moveModule(mi, 1)} disabled={mi === modules.length - 1} className="p-1.5 rounded-lg text-slate-400 hover:bg-slate-100 disabled:opacity-30"><ChevronDown size={16} /></button>
              <button onClick={() => deleteModule(m)} className="p-1.5 rounded-lg text-red-400 hover:bg-red-50"><Trash2 size={16} /></button>
            </div>
            <div className="mt-2 space-y-1.5">
              {(m.lessons || []).map((l, li) => (
                <div key={l.id} className="flex items-center gap-2 px-3 py-2 rounded-xl bg-slate-50 border border-slate-100">
                  {l.type === 'video' ? <Play size={14} className="text-slate-400 flex-shrink-0" /> : <FileText size={14} className="text-slate-400 flex-shrink-0" />}
                  <span className="flex-1 min-w-0 text-sm font-medium text-slate-700 truncate">{l.title}</span>
                  {l.video_provider && <span className="text-[10px] uppercase font-bold text-slate-400 flex-shrink-0">{l.video_provider}</span>}
                  <button onClick={() => moveLesson(m, li, -1)} disabled={li === 0} className="p-1 rounded text-slate-400 hover:bg-slate-200 disabled:opacity-30"><ChevronUp size={14} /></button>
                  <button onClick={() => moveLesson(m, li, 1)} disabled={li === (m.lessons.length - 1)} className="p-1 rounded text-slate-400 hover:bg-slate-200 disabled:opacity-30"><ChevronDown size={14} /></button>
                  <button onClick={() => setEditingLesson({ ...l })} className="p-1 rounded text-blue-500 hover:bg-blue-50"><Edit3 size={14} /></button>
                  <button onClick={() => deleteLesson(l)} className="p-1 rounded text-red-400 hover:bg-red-50"><Trash2 size={14} /></button>
                </div>
              ))}
              <button onClick={() => addLesson(m)} disabled={structBusy} className="mt-1 text-sm font-semibold text-blue-600 inline-flex items-center gap-1.5 px-3 py-1.5 hover:bg-blue-50 rounded-lg disabled:opacity-50"><Plus size={15} /> Add lesson</button>
            </div>
          </div>
        ))}

        <button onClick={addModule} disabled={structBusy} className="w-full py-3 rounded-2xl border-2 border-dashed border-slate-300 text-slate-500 font-semibold inline-flex items-center justify-center gap-2 hover:border-blue-300 hover:text-blue-600 disabled:opacity-50">
          {structBusy ? <Loader2 size={18} className="animate-spin" /> : <Plus size={18} />} Add module
        </button>
      </div>
    );
  }

  function renderLessonEditor() {
    const d = editingLesson;
    const detected = d.type === 'video' && d.video_provider !== 'upload' ? parseVideoUrl(d.video_url).provider : null;
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4" style={{ background: 'rgba(15,18,23,0.45)' }} onClick={closeLessonEditor}>
        <div className="bg-white rounded-2xl w-full max-w-xl max-h-[88vh] overflow-y-auto shadow-2xl" onClick={e => e.stopPropagation()}>
          <div className="px-5 py-4 border-b border-slate-100 flex items-center justify-between sticky top-0 bg-white">
            <div style={{ fontFamily: fontDisplay, color: NAVY }} className="font-bold">Edit lesson</div>
            <button onClick={closeLessonEditor} className="text-slate-400 hover:text-slate-600"><X size={18} /></button>
          </div>
          <div className="p-5 space-y-4">
            <label className="block">
              <span className="text-xs font-semibold text-slate-500">Lesson title</span>
              <input value={d.title || ''} onChange={e => setEditingLesson(s => ({ ...s, title: e.target.value }))}
                className="mt-1 w-full px-3 py-2 rounded-lg border border-slate-200 text-sm" />
            </label>
            <div className="flex gap-2">
              {['video', 'text'].map(t => (
                <button key={t} onClick={() => setEditingLesson(s => ({ ...s, type: t }))}
                  className="px-4 py-2 rounded-xl text-sm font-semibold capitalize inline-flex items-center gap-2"
                  style={d.type === t ? { background: `linear-gradient(180deg, ${C.primaryHi}, ${C.primary})`, color: '#fff' } : { background: 'var(--wash-strong)', color: C.textSoft }}>
                  {t === 'video' ? <Play size={14} /> : <FileText size={14} />} {t}
                </button>
              ))}
            </div>

            {d.type === 'video' && (
              <>
                <label className="block">
                  <span className="text-xs font-semibold text-slate-500">Video link (YouTube, Vimeo, or MP4 URL)</span>
                  <input value={d.video_provider === 'upload' ? '' : (d.video_url || '')} placeholder="https://youtube.com/watch?v=…"
                    onChange={e => setEditingLesson(s => ({ ...s, video_url: e.target.value, video_provider: parseVideoUrl(e.target.value).provider, storage_path: null }))}
                    className="mt-1 w-full px-3 py-2 rounded-lg border border-slate-200 text-sm" />
                  {detected && d.video_url && <span className="text-[11px] text-slate-400 mt-1 inline-block">Detected: {detected}</span>}
                </label>
                <div className="flex items-center gap-2 text-xs text-slate-400"><div className="flex-1 h-px bg-slate-200" /> or upload a file <div className="flex-1 h-px bg-slate-200" /></div>
                <div className="flex items-center">
                  <label className="inline-flex items-center gap-2 px-4 py-2 rounded-xl border border-slate-200 text-sm font-semibold text-slate-600 cursor-pointer hover:bg-slate-50">
                    <Upload size={15} /> {uploading ? 'Uploading…' : 'Choose video file'}
                    <input type="file" accept="video/*" className="hidden" disabled={uploading}
                      onChange={e => { const f = e.target.files?.[0]; if (f) uploadVideo(f); e.target.value = ''; }} />
                  </label>
                  {uploading && <Loader2 size={16} className="animate-spin ml-2 text-blue-500" />}
                  {d.video_provider === 'upload' && d.storage_path && !uploading && <span className="text-[11px] text-green-600 ml-2 inline-flex items-center gap-1"><Check size={12} /> Uploaded</span>}
                </div>
                {(previewUrl || (d.video_provider && (d.video_url || d.storage_path))) && (
                  <div className="rounded-xl overflow-hidden">
                    {previewUrl
                      ? <video controls src={previewUrl} className="w-full rounded-xl bg-black" style={{ maxHeight: 220 }} />
                      : renderVideo(d)}
                  </div>
                )}
              </>
            )}

            <label className="block">
              <span className="text-xs font-semibold text-slate-500">{d.type === 'video' ? 'Lesson notes (optional)' : 'Lesson content'}</span>
              <textarea value={d.text_content || ''} onChange={e => setEditingLesson(s => ({ ...s, text_content: e.target.value }))} rows={d.type === 'text' ? 6 : 3}
                className="mt-1 w-full px-3 py-2 rounded-lg border border-slate-200 text-sm" />
            </label>
            <label className="block">
              <span className="text-xs font-semibold text-slate-500">Duration label (optional, e.g. 8:32)</span>
              <input value={d.duration_label || ''} onChange={e => setEditingLesson(s => ({ ...s, duration_label: e.target.value }))}
                className="mt-1 w-40 px-3 py-2 rounded-lg border border-slate-200 text-sm" />
            </label>
          </div>
          <div className="px-5 py-4 border-t border-slate-100 flex justify-end gap-2 sticky bottom-0 bg-white">
            <button onClick={closeLessonEditor} disabled={savingLesson} className="px-4 py-2 rounded-xl text-sm font-semibold text-slate-600 border border-slate-200">Cancel</button>
            <button onClick={saveLesson} disabled={savingLesson} className="px-5 py-2 rounded-xl text-white text-sm font-semibold inline-flex items-center gap-2"
              style={{ background: `linear-gradient(180deg, ${C.primaryHi}, ${C.primary})` }}>
              {savingLesson ? <Loader2 size={15} className="animate-spin" /> : <Save size={15} />} Save lesson
            </button>
          </div>
        </div>
      </div>
    );
  }

  function renderCertificate() {
    const unlocked = isComplete || !!completion || isAdmin;
    if (!unlocked) {
      return (
        <div className="mt-6 glass-card rounded-2xl p-10 text-center" style={{ background: SHEEN }}>
          <Lock size={32} className="mx-auto mb-3 text-slate-400" />
          <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-lg font-bold">Certificate locked</div>
          <div className="text-slate-500 text-sm mt-1">Complete all {totalLessons} lessons to unlock your certificate.</div>
          <button onClick={() => setMode('learn')} className="mt-4 px-5 py-2.5 rounded-xl text-white font-semibold" style={{ background: `linear-gradient(180deg, ${C.primaryHi}, ${C.primary})` }}>Back to course</button>
        </div>
      );
    }
    const issued = new Date(completion?.completed_at || Date.now());
    const dateStr = issued.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
    const mod = certModuleType(course.slug || '');
    const certDesc = CERT_DESCRIPTIONS[mod];
    const ymd = `${issued.getFullYear()}${String(issued.getMonth() + 1).padStart(2, '0')}${String(issued.getDate()).padStart(2, '0')}`;
    const hex = (s, n) => (s || '').replace(/-/g, '').slice(0, n).toUpperCase();
    const certId = `CERT-${CERT_CODES[mod]}-${hex(course.id, 4)}-${hex(user?.id, 6)}-${ymd}`;
    return (
      <div className="mt-6">
        <div className="flex flex-wrap items-center gap-3 mb-5">
          <label className="text-sm text-slate-600 flex items-center gap-2">
            Name on certificate:
            <input value={studentName} onChange={e => setStudentName(e.target.value)} className="px-3 py-1.5 rounded-lg border border-slate-200 text-sm w-64" />
          </label>
          {isAdmin && !isComplete && <span className="text-[11px] px-2 py-1 rounded-full bg-slate-100 text-slate-500">admin preview</span>}
          <div className="flex-1" />
          <button onClick={() => setMode('learn')} className="px-4 py-2 rounded-xl text-sm font-semibold text-slate-600 border border-slate-200">Back to course</button>
          <button onClick={printCertificate} className="px-4 py-2 rounded-xl text-sm font-semibold text-slate-700 border border-slate-200 inline-flex items-center gap-2"><Printer size={15} /> Print</button>
          <button onClick={downloadCertificate} disabled={certBusy} className="px-5 py-2 rounded-xl text-white text-sm font-semibold inline-flex items-center gap-2" style={{ background: `linear-gradient(135deg, ${C.primary}, ${C.accent})` }}>
            {certBusy ? <Loader2 size={15} className="animate-spin" /> : <Download size={15} />} Download PDF
          </button>
        </div>

        <div ref={certScaleRef} style={{ width: '100%', maxWidth: 756, margin: '0 auto', padding: 18, boxSizing: 'border-box', height: certBoxH || undefined, overflow: 'hidden' }}>
          <div style={{ width: 900, transform: `scale(${certScale})`, transformOrigin: 'top left' }}>
          {/* Certificate uses the frozen INK palette (literal hex, never var()) — printCertificate
              copies this subtree's outerHTML into a bare window with no stylesheet, and the PDF
              capture must stay light regardless of the app theme. */}
          <div ref={certRef} data-theme="light" style={{
            width: 900, margin: '0 auto', background: '#ffffff', position: 'relative',
            padding: 24, boxSizing: 'border-box', fontFamily: fontBody, color: INK.text,
            border: `2px solid ${INK.primary}`, borderRadius: 18,
            boxShadow: '0 10px 40px rgba(10,132,255,0.12)',
          }}>
            <div style={{ border: `1px solid ${INK.accent}`, borderRadius: 12, padding: '26px 44px', textAlign: 'center', background: 'linear-gradient(180deg,#ffffff,#F7FAFF)' }}>
              <img src={LOGO_DATA_URI} alt="" style={{ width: 56, height: 56, objectFit: 'contain', margin: '0 auto 4px' }} />
              <div style={{ fontFamily: fontDisplay, fontSize: 13, letterSpacing: '0.32em', textTransform: 'uppercase', color: INK.primary, fontWeight: 700 }}>Certificate of Completion</div>
              <div style={{ height: 2, width: 64, background: `linear-gradient(90deg, ${INK.primary}, ${INK.accent})`, margin: '10px auto 14px', borderRadius: 2 }} />
              <div style={{ fontSize: 12, letterSpacing: '0.18em', textTransform: 'uppercase', color: INK.textSoft, fontWeight: 600 }}>This certificate is awarded to</div>
              <div style={{ fontFamily: fontDisplay, fontSize: 38, fontWeight: 800, color: INK.navy, margin: '6px 0 4px', maxWidth: 760, marginLeft: 'auto', marginRight: 'auto', overflowWrap: 'break-word' }}>{studentName || 'Your Name'}</div>
              <div style={{ width: 380, height: 1, background: INK.border, margin: '8px auto 14px' }} />
              <div style={{ fontSize: 12, letterSpacing: '0.18em', textTransform: 'uppercase', color: INK.textSoft, fontWeight: 600 }}>For successfully completing the course</div>
              <div style={{ fontFamily: fontDisplay, fontSize: 24, fontWeight: 700, color: INK.primary, margin: '6px auto 2px', maxWidth: 760, overflowWrap: 'break-word' }}>{certificateTitle(course.title)}</div>
              {course.subtitle && <div style={{ fontSize: 13, color: INK.textMute, maxWidth: 520, margin: '6px auto 0' }}>{course.subtitle}</div>}
              <div style={{ fontSize: 13, lineHeight: 1.6, color: INK.textSoft, maxWidth: 620, margin: '12px auto 0' }}>{certDesc}</div>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginTop: 24, padding: '0 12px' }}>
                <div style={{ textAlign: 'center' }}>
                  <div style={{ fontFamily: fontDisplay, fontSize: 20, color: INK.navy, fontWeight: 700 }}>Alex Sagun</div>
                  <div style={{ width: 160, height: 1, background: INK.border, margin: '4px auto' }} />
                  <div style={{ fontSize: 11, color: INK.textMute, letterSpacing: '0.08em', textTransform: 'uppercase' }}>Instructor · Get Hired With Alex</div>
                </div>
                <Award size={40} style={{ color: INK.accent, flexShrink: 0 }} />
                <div style={{ textAlign: 'center' }}>
                  <div style={{ fontFamily: fontDisplay, fontSize: 16, color: INK.navy, fontWeight: 700 }}>{dateStr}</div>
                  <div style={{ width: 160, height: 1, background: INK.border, margin: '4px auto' }} />
                  <div style={{ fontSize: 11, color: INK.textMute, letterSpacing: '0.08em', textTransform: 'uppercase' }}>Date Completed</div>
                </div>
              </div>
              <div style={{ marginTop: 14, paddingTop: 10, borderTop: `1px solid ${INK.border}`, display: 'flex', justifyContent: 'space-between', alignItems: 'center', fontSize: 10.5, letterSpacing: '0.04em', color: INK.textMute, textTransform: 'uppercase' }}>
                <span>Certificate ID:&nbsp;<span style={{ fontFamily: fontMono, letterSpacing: 0 }}>{certId}</span></span>
                <span>Issued: {dateStr}</span>
              </div>
            </div>
          </div>
          </div>
        </div>
      </div>
    );
  }

  // ── Shell ──
  const errorBanner = err ? (
    <div className="mt-4 flex items-start gap-3 p-4 rounded-xl border" style={{ background: 'var(--status-danger-bg)', borderColor: 'var(--status-danger-bd)' }}>
      <AlertTriangle size={18} className="text-red-500 mt-0.5 flex-shrink-0" />
      <div className="text-sm text-red-700 flex-1">{err}</div>
      <button onClick={() => setErr('')} className="text-red-400 hover:text-red-600"><X size={16} /></button>
    </div>
  ) : null;

  const noticeBanner = notice ? (
    <div className="mt-4 flex items-start gap-3 p-4 rounded-xl border" style={{ background: 'var(--status-ok-bg)', borderColor: 'var(--status-ok-bd)' }}>
      <CheckCircle2 size={18} className="text-emerald-600 mt-0.5 flex-shrink-0" />
      <div className="text-sm text-emerald-800 flex-1">{notice}</div>
      <button onClick={() => setNotice(null)} className="text-emerald-500 hover:text-emerald-700"><X size={16} /></button>
    </div>
  ) : null;

  // In catalog mode, give the open course a back button + its own compact header (the catalog supplies the page title).
  const backBar = onBack ? (
    <div className="mb-4 flex items-center gap-3 flex-wrap">
      <button onClick={() => { if (confirmLeaveCourse()) onBack(); }} className="inline-flex items-center gap-2 text-sm font-semibold text-slate-600 hover:text-slate-900 px-3 py-1.5 rounded-lg border border-slate-200 bg-white shadow-sm">
        <ArrowLeft size={16} /> All courses
      </button>
      {course && (
        <div className="min-w-0">
          <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-lg sm:text-xl font-bold leading-tight truncate">{course.title}</div>
          {displaySubtitle && <div className="text-xs text-slate-500 truncate">{displaySubtitle}</div>}
        </div>
      )}
    </div>
  ) : null;

  if (loading) {
    return (
      <div>
        {showHead && <SectionHead eyebrow={eyebrow} title={courseTitle} desc="Loading…" gold />}
        {backBar}
        <div className="flex items-center justify-center py-24 text-slate-400"><Loader2 className="animate-spin" size={28} /></div>
      </div>
    );
  }

  if (!course) {
    return (
      <div>
        {showHead && <SectionHead eyebrow={eyebrow} title={courseTitle} desc="" gold />}
        {backBar}
        {errorBanner}
        <div className="mt-6 glass-card rounded-2xl p-10 text-center" style={{ background: SHEEN }}>
          <GraduationCap size={40} className="mx-auto mb-3" style={{ color: ROYAL }} />
          <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-xl font-bold">
            {!isAdmin ? 'Course coming soon' : notConfigured ? 'Finish backend setup' : 'No course yet'}
          </div>
          <div className="text-slate-500 mt-2 text-sm max-w-md mx-auto">
            {!isAdmin
              ? comingSoonText
              : notConfigured
                ? 'The course tables aren’t in Supabase yet. Open COURSE_SETUP.md and run the SQL, create the public course-media bucket, then refresh this page.'
                : 'No course exists yet. Click “Create course” to set it up, then add your modules and lessons in the builder.'}
          </div>
          {isAdmin && notConfigured && (
            <div className="mt-4 inline-flex items-center gap-2 text-xs font-semibold px-3 py-1.5 rounded-full" style={{ background: 'var(--status-warn-bg)', color: 'var(--status-warn-fg)' }}>
              <AlertTriangle size={13} /> See COURSE_SETUP.md
            </div>
          )}
          {isAdmin && !notConfigured && (
            <button onClick={createCourse} disabled={creating}
              className="mt-5 inline-flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-semibold text-white shadow-sm disabled:opacity-60"
              style={{ background: `linear-gradient(180deg, ${C.primaryHi}, ${C.primary})` }}>
              {creating ? <Loader2 size={15} className="animate-spin" /> : <Plus size={15} />}
              {creating ? 'Creating…' : 'Create course'}
            </button>
          )}
        </div>
      </div>
    );
  }

  // Plan deep-link guard (defense-in-depth). RLS is the real boundary — a restricted
  // course normally returns no row (→ the "coming soon" state above). This only fires if
  // a course the plan can't open still reaches the client; it never blocks admins.
  if (!ent.allowsCourse(course)) {
    return (
      <div>
        {showHead && <SectionHead eyebrow={eyebrow} title={courseTitle} desc="" gold />}
        {backBar}
        <div className="mt-6 glass-card rounded-2xl p-10 text-center" style={{ background: SHEEN }}>
          <Lock size={38} className="mx-auto mb-3" style={{ color: C.primary }} />
          <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-xl font-bold">This course isn’t part of your plan</div>
          <div className="text-slate-500 mt-2 text-sm max-w-md mx-auto">
            Your plan ({ent.scopeLabel}) includes the Essentials course. Upgrade or renew from the Dashboard membership panel to unlock the full QuickBooks program.
          </div>
        </div>
      </div>
    );
  }

  return (
    <div>
      {showHead && <SectionHead eyebrow={eyebrow} title={courseTitle}
        desc={course.subtitle || defaultSubtitle} gold />}
      {backBar}
      <div className="flex items-center justify-between gap-3 flex-wrap">
        <div className="flex items-center gap-2 text-sm text-slate-500">
          <BookMarked size={15} /> {modules.length} modules · {totalLessons} lessons
          {!course.published && isAdmin && (
            <span className="ml-1 px-2 py-0.5 rounded-full text-xs font-bold" style={{ background: 'var(--status-warn-bg)', color: 'var(--status-warn-fg)' }}>Draft — not published</span>
          )}
        </div>
        {isAdmin && (
          <div className="inline-flex p-1 rounded-xl border border-slate-200 bg-white shadow-sm">
            {[['learn', 'Learn', Play], ['edit', 'Edit course', Edit3]].map(([key, lbl, Icon]) => (
              <button key={key} onClick={() => setMode(key)}
                className="px-4 py-2 rounded-lg text-sm font-semibold inline-flex items-center gap-2 transition-all"
                style={mode === key ? { background: `linear-gradient(180deg, ${C.primaryHi}, ${C.primary})`, color: '#fff' } : { color: C.textSoft }}>
                <Icon size={15} /> {lbl}
              </button>
            ))}
          </div>
        )}
      </div>
      {noticeBanner}
      {errorBanner}

      {mode === 'certificate'
        ? renderCertificate()
        : (mode === 'edit' && isAdmin)
          ? renderBuilder()
          : renderLearner()}

      {editingLesson && isAdmin && renderLessonEditor()}
    </div>
  );
}

// Turn a human title into a unique-ish, catalog-scoped slug. The `prefix` groups the course
// into one catalog without any schema change ("qbo-" → QuickBooks Online Mastery,
// "interview-" → Interview Winning Strategy, etc.).
function slugify(title, prefix = 'qbo-') {
  const base = String(title || '').toLowerCase().normalize('NFKD')
    .replace(/[^\w\s-]/g, '').trim().replace(/[\s_-]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 48);
  return prefix + (base || 'course');
}

// Delete storage objects ONLY if no surviving course still references them. Course duplication
// reuses the original's video/cover paths (copy-on-write), so a path can be shared by several
// courses; blindly removing it when one course is deleted/edited would break the others. A path
// is "still used" if it appears as a lesson's storage_path or a course's cover_path anywhere.
// ALWAYS call this AFTER the relevant row update/delete, so the just-changed row no longer counts.
// Shared by CourseCatalog (deleteCourse/uploadCover) and CourseProgram (saveLesson/deleteLesson).
async function removeMediaIfUnreferenced(rawPaths) {
  const paths = [...new Set((rawPaths || []).filter(Boolean))];
  if (!paths.length) return;
  const chunk = (arr, n) => { const out = []; for (let i = 0; i < arr.length; i += n) out.push(arr.slice(i, i + n)); return out; };
  const referenced = new Set();
  try {
    for (const part of chunk(paths, 100)) {
      const [{ data: lh, error: le }, { data: ch, error: ce }] = await Promise.all([
        supabase.from('course_lessons').select('storage_path').in('storage_path', part),
        supabase.from('courses').select('cover_path').in('cover_path', part),
      ]);
      // supabase-js returns query errors as { data:null, error } WITHOUT throwing, so an
      // unchecked failure would leave `referenced` empty and delete every candidate —
      // including files a duplicated course still uses. On any error, keep the files.
      if (le || ce) { console.error('[course-media] reference check failed — leaving files in place:', le || ce); return; }
      (lh || []).forEach(r => r.storage_path && referenced.add(r.storage_path));
      (ch || []).forEach(r => r.cover_path && referenced.add(r.cover_path));
    }
  } catch (e) {
    // If we can't confirm references, err on the safe side and keep the files (no orphan cleanup).
    console.error('[course-media] reference check failed — leaving files in place:', e);
    return;
  }
  const orphans = paths.filter(p => !referenced.has(p));
  // Route each orphan to its bucket: lesson VIDEO files live in the private course-videos
  // bucket; covers (and any legacy lesson videos) in course-media. We sweep both buckets for
  // lessons/* paths so a video uploaded before the split is cleaned up too (remove is a no-op
  // when the object is absent).
  const videoOrphans = orphans.filter(p => p.startsWith('lessons/'));
  const mediaOrphans = orphans.filter(p => !p.startsWith('lessons/'));
  for (const part of chunk(videoOrphans, 100)) {
    try { await supabase.storage.from(LESSON_VIDEO_BUCKET).remove(part); } catch (_) { /* best-effort */ }
    try { await supabase.storage.from('course-media').remove(part); } catch (_) { /* legacy sweep */ }
  }
  for (const part of chunk(mediaOrphans, 100)) {
    try { await supabase.storage.from('course-media').remove(part); } catch (_) { /* best-effort */ }
  }
}

// Pull the underlying PostgrestError fields off a thrown error. Our multi-step flows wrap the real
// error on `.cause` (with a friendly prefix as `.message`), so unwrap to that for code/details/hint.
function dbErrorFields(e) {
  const root = (e && e.cause) || e || {};
  return {
    code: root.code || e?.code,
    message: root.message || e?.message,
    details: root.details,
    hint: root.hint,
  };
}

// Structured console logging for a Supabase failure — replaces terse `console.error('… failed', e)`
// (which renders as an unhelpful "Object undefined") with the operation, its context (module/course),
// and the Postgrest code/message/details/hint, so failures are debuggable from the console alone.
function logDbError(tag, e, context) {
  const { code, message, details, hint } = dbErrorFields(e);
  console.error(`${tag} failed`, { code, message, details, hint, ...(context || {}) });
}

// Turn a thrown error into a human-readable banner string. Unwraps our friendly-wrapped errors
// (which stash the real PostgrestError on `.cause`) and pulls through the underlying message,
// details, hint, and code — so a create/duplicate/cover/delete failure shows WHY instead of an opaque
// "[object Object]". A missing-column code (PGRST204 / 42703 — the course-platform migration not yet
// applied) gets a targeted next-step hint. `fallback` is an operation-specific default message used
// only when the error carries no usable text.
function describeDbError(e, fallback) {
  const generic = fallback || 'Something went wrong. Please try again.';
  if (!e) return generic;
  const root = e.cause || e;                        // unwrap to the underlying Postgres error
  const code = root.code || e.code;
  const parts = [];
  if (e.message && e.message !== root.message) parts.push(e.message);   // our friendly prefix, if any
  if (root.message) parts.push(root.message);
  if (root.details && root.details !== root.message) parts.push(root.details);
  if (root.hint) parts.push(`Hint: ${root.hint}`);
  if (code === 'PGRST204' || code === '42703') {
    parts.push('The course database migration hasn’t been applied yet — run the SQL in db/2026-06-17-course-date-source-id.sql (or the migration block in COURSE_SETUP.md, which adds course_date / month / source_course_id / updated_at), then “notify pgrst, \'reload schema\';”.');
  }
  // Storage upload/playback failure when the bucket was never created (COURSE_SETUP.md Step 2).
  const hay = [e.message, root.message, root.details, root.hint].filter(Boolean).join(' ');
  if (/bucket/i.test(hay) && /not found|does not exist/i.test(hay)) {
    parts.push('The “course-media” storage bucket may be missing — create it as a public bucket and add the storage policies from COURSE_SETUP.md Step 2, then retry.');
  }
  if (code) parts.push(`(code ${code})`);
  return parts.filter(Boolean).join(' — ') || generic;
}

// ── Multi-course catalog (prefix-scoped) ──
// A Thinkific-style library: admins create/manage many courses from one dashboard
// (cover, reorder, publish, delete); students browse published courses and open one to
// learn. Courses are grouped by a `prefix` on `courses.slug`, so each catalog is its own
// namespace with zero schema change ("qbo-" → QuickBooks Online Mastery, "interview-" →
// Interview Winning Strategy). All copy is prop-driven and defaults to the QBO catalog, so
// `<CourseCatalog />` with no props behaves exactly as before. Pass `embedded` to drop the
// big SectionHead when the catalog is nested inside a subtab that already shows a header.
// Opening a course hands off to the shared CourseProgram engine via courseId + onBack.
function CourseCatalog({
  prefix = 'qbo-',
  embedded = false,
  eyebrow = 'Video Courses',
  title = 'QuickBooks Online Mastery',
  adminDesc = 'Create and manage your QuickBooks Online video courses — add modules, upload or embed lessons, set covers, and publish.',
  studentDesc = 'Master QuickBooks Online with structured, on-demand video courses. Choose a course to start learning.',
  newCourseTitle = 'New QuickBooks Course',
  comingSoonDesc = 'Your QuickBooks Online training is being prepared. Check back soon.',
} = {}) {
  const { user, profile } = useAuth();
  const isAdmin = !!profile?.is_admin;
  const ent = useContext(EntitlementContext);   // plan scope — drives which course cards a student sees
  const catalogTabId = prefix === 'resume-' ? 'resumestrategy' : prefix === 'interview-' ? 'interview' : 'qbomastery';
  const catalogInterviewSub = prefix === 'interview-' ? 'winstrat' : null;
  const initialCatalogRouteRef = useRef(null);
  if (!initialCatalogRouteRef.current) initialCatalogRouteRef.current = readAppRoute();
  const initialSelectedId = initialCatalogRouteRef.current.tab === catalogTabId ? initialCatalogRouteRef.current.courseId : null;

  const [courses, setCourses] = useState([]);
  const [counts, setCounts] = useState({});            // course_id -> total lessons
  const [done, setDone] = useState({});                // course_id -> lessons this user completed
  const [loading, setLoading] = useState(true);
  const [err, setErr] = useState('');
  const [notConfigured, setNotConfigured] = useState(false);
  const [selectedId, setSelectedId] = useState(initialSelectedId);  // null = grid; otherwise the open course
  const [busy, setBusy] = useState(false);             // create / delete / reorder / cover / duplicate in flight
  const [menuOpenId, setMenuOpenId] = useState(null);  // which card's ⋮ action menu is open
  const [lastDuplicatedId, setLastDuplicatedId] = useState(null); // highlight + open the fresh copy in the builder

  // Open a course in the builder, clearing any transient menu/highlight UI. (The post-duplicate
  // auto-open uses setSelectedId directly so its one-time success banner still shows.)
  function writeCatalogRoute(courseId, replace = false) {
    writeAppRoute(catalogTabId, { courseId, interviewSub: catalogInterviewSub, replace });
  }
  function openCourse(id, opts = {}) {
    setMenuOpenId(null);
    setLastDuplicatedId(null);
    setSelectedId(id);
    writeCatalogRoute(id, !!opts.replace);
  }
  function closeCourse() {
    setMenuOpenId(null);
    setSelectedId(null);
    writeCatalogRoute(null, true);
    loadCatalog();
  }
  useEffect(() => {
    const onPopState = () => {
      const route = readAppRoute();
      if (route.tab === catalogTabId) setSelectedId(route.courseId || null);
    };
    window.addEventListener('popstate', onPopState);
    return () => window.removeEventListener('popstate', onPopState);
  }, [catalogTabId]);
  // Close the ⋮ menu on Escape while one is open.
  useEffect(() => {
    if (!menuOpenId) return;
    const onKey = (e) => { if (e.key === 'Escape') setMenuOpenId(null); };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [menuOpenId]);

  async function loadCatalog() {
    setLoading(true); setErr(''); setNotConfigured(false);
    try {
      const { data: rows, error: cErr } = await supabase
        .from('courses').select(COURSE_ROW_SELECT).ilike('slug', `${prefix}%`).order('position').order('created_at');
      if (cErr) throw cErr;
      const list = rows || [];
      setCourses(list);
      const ids = list.map(c => c.id);
      if (ids.length) {
        const [{ data: lessons }, { data: prog }] = await Promise.all([
          supabase.from('course_lessons').select('id,course_id').in('course_id', ids),
          supabase.from('lesson_progress').select('lesson_id,course_id').in('course_id', ids).eq('user_id', user.id),
        ]);
        const cnt = {}, dn = {};
        (lessons || []).forEach(l => { cnt[l.course_id] = (cnt[l.course_id] || 0) + 1; });
        (prog || []).forEach(p => { dn[p.course_id] = (dn[p.course_id] || 0) + 1; });
        setCounts(cnt); setDone(dn);
      } else { setCounts({}); setDone({}); }
    } catch (e) {
      logDbError('[CourseCatalog] load', e, { module: prefix });
      const msg = e?.message || '';
      if (e?.code === 'PGRST205' || /schema cache|could not find the table|does not exist/i.test(msg)) {
        setNotConfigured(true); setCourses([]);
      } else { setErr(msg || 'Failed to load courses.'); }
    } finally { setLoading(false); }
  }

  useEffect(() => { if (user?.id) loadCatalog(); /* eslint-disable-next-line */ }, [user?.id, prefix]);

  // ── Admin actions (RLS also enforces is_admin server-side) ──
  async function createCourse() {
    const title = (window.prompt('New course title:', newCourseTitle) || '').trim();
    if (!title) return;
    setBusy(true); setErr('');
    try {
      const existing = new Set(courses.map(c => c.slug));
      const base = slugify(title, prefix);
      let slug = base, n = 2;
      while (existing.has(slug)) slug = `${base}-${n++}`;
      const position = courses.length ? Math.max(...courses.map(c => c.position ?? 0)) + 1 : 0;
      let res = await supabase.from('courses').insert({ slug, title, subtitle: '', published: false, position, course_date: todayISODate() }).select(COURSE_ROW_SELECT).single();
      if (res.error && res.error.code === '23505') {           // slug collision race — retry once with a unique suffix
        slug = `${base}-${Date.now().toString(36).slice(-4)}`;
        res = await supabase.from('courses').insert({ slug, title, subtitle: '', published: false, position, course_date: todayISODate() }).select(COURSE_ROW_SELECT).single();
      }
      if (res.error) throw res.error;
      await loadCatalog();
      openCourse(res.data.id);                                 // drop the admin straight into the new course (builder)
    } catch (e) {
      logDbError('[CourseCatalog] create', e, { module: prefix });
      setErr(describeDbError(e, 'Could not create the course.'));
    } finally { setBusy(false); }
  }

  // ── Duplicate a course (structure + lessons + reused video/cover references) into a new DRAFT ──
  // Reuses the original's storage_path/video_url/cover_path (copy-on-write — no file bytes copied),
  // skips per-user progress/completions, and stamps source_course_id for lineage. Multi-step but
  // safe: if anything after the course insert fails, the half-built copy is rolled back (cascade).
  async function duplicateCourse(c) {
    setMenuOpenId(null);
    setBusy(true); setErr('');
    let newCourseId = null;
    try {
      // 1. Load the source fresh (its row + ordered modules + ordered lessons).
      const [{ data: src, error: e1 }, { data: mods, error: e2 }, { data: lessons, error: e3 }] = await Promise.all([
        supabase.from('courses').select(COURSE_ROW_SELECT).eq('id', c.id).single(),
        supabase.from('course_modules').select(COURSE_MODULE_SELECT).eq('course_id', c.id).order('position'),
        supabase.from('course_lessons').select(COURSE_LESSON_SELECT).eq('course_id', c.id).order('position'),
      ]);
      if (e1) throw e1;
      if (e2 || e3) throw (e2 || e3);

      // 2. Unique, catalog-scoped slug for the copy (mirror createCourse's collision handling).
      const newTitle = `Copy of ${src.title}`;
      const existing = new Set(courses.map(x => x.slug));
      const base = slugify(newTitle, prefix);
      let slug = base, n = 2;
      while (existing.has(slug)) slug = `${base}-${n++}`;
      const position = courses.length ? Math.max(...courses.map(x => x.position ?? 0)) + 1 : 0;

      // 3. Insert the new course as a DRAFT (reuse cover, keep month, record lineage).
      const coursePayload = {
        slug, title: newTitle,
        subtitle: src.subtitle ?? '', description: src.description ?? null,
        course_date: todayISODate(), cover_path: src.cover_path ?? null,  // default the cohort date to today, not the source's (avoids a June re-run inheriting May)
        access_tier: src.access_tier ?? 'standard',  // a re-run of an Essentials course stays Sampler-accessible
        source_course_id: src.id, published: false, position,
      };
      let res = await supabase.from('courses').insert(coursePayload).select(COURSE_ROW_SELECT).single();
      if (res.error && res.error.code === '23505') {           // slug collision race — retry once with a unique suffix
        slug = `${base}-${Date.now().toString(36).slice(-4)}`;
        res = await supabase.from('courses').insert({ ...coursePayload, slug }).select(COURSE_ROW_SELECT).single();
      }
      if (res.error) throw res.error;
      newCourseId = res.data.id;

      // 4. Copy modules — pre-generate ids so we can remap lessons in one batch (3 inserts total).
      const moduleIdMap = new Map();
      const modulePayloads = (mods || []).map(m => {
        const id = crypto.randomUUID();
        moduleIdMap.set(m.id, id);
        return { id, course_id: newCourseId, title: m.title, position: m.position };
      });
      if (modulePayloads.length) {
        const { error } = await supabase.from('course_modules').insert(modulePayloads);
        if (error) { const wrap = new Error('Couldn’t copy the modules for this course.'); wrap.cause = error; throw wrap; }
      }

      // 5. Copy lessons under the remapped modules (reuse video/storage references verbatim).
      const lessonPayloads = (lessons || [])
        .filter(l => moduleIdMap.has(l.module_id))
        .map(l => ({
          module_id: moduleIdMap.get(l.module_id), course_id: newCourseId,
          title: l.title, type: l.type, video_url: l.video_url, video_provider: l.video_provider,
          storage_path: l.storage_path, text_content: l.text_content,
          duration_label: l.duration_label, position: l.position,
        }));
      if (lessonPayloads.length) {
        const { error } = await supabase.from('course_lessons').insert(lessonPayloads);
        if (error) { const wrap = new Error('Couldn’t copy the lessons for this course.'); wrap.cause = error; throw wrap; }
      }

      // 6. Refresh, then open the fresh copy straight in the builder for editing.
      await loadCatalog();
      setLastDuplicatedId(newCourseId);
      setSelectedId(newCourseId);
      writeCatalogRoute(newCourseId, false);
    } catch (e) {
      logDbError('[CourseCatalog] duplicate', e, { module: prefix, sourceId: c.id });
      // Roll back a partially-built copy so we never leave a course without its lessons.
      if (newCourseId) { try { await supabase.from('courses').delete().eq('id', newCourseId); } catch (_) { /* best-effort */ } }
      setErr(describeDbError(e, 'Could not duplicate the course.'));
    } finally { setBusy(false); }
  }

  async function uploadCover(c, file) {
    if (!file) return;
    if (!/^image\//i.test(file.type)) { setErr('Please choose an image file for the cover.'); return; }
    if (file.size > 5 * 1024 * 1024) { setErr('Cover image is too large (max 5 MB).'); return; }
    setBusy(true); setErr('');
    try {
      const safe = file.name.replace(/[^\w.\-]+/g, '_');
      const path = `covers/${c.id}/${crypto.randomUUID()}-${safe}`;
      const { error: upErr } = await supabase.storage.from('course-media').upload(path, file, { upsert: false, contentType: file.type });
      if (upErr) throw upErr;
      const { error } = await supabase.from('courses').update({ cover_path: path, updated_at: new Date().toISOString() }).eq('id', c.id);
      if (error) throw error;
      // Purge the old cover only if no other course (e.g. a duplicate that reused it) still points to it.
      if (c.cover_path && c.cover_path !== path) await removeMediaIfUnreferenced([c.cover_path]);
      await loadCatalog();
    } catch (e) {
      logDbError('[CourseCatalog] cover upload', e, { module: prefix, courseId: c.id });
      setErr(describeDbError(e, 'Could not upload the cover image.'));
    } finally { setBusy(false); }
  }

  async function deleteCourse(c) {
    setMenuOpenId(null);
    if (!window.confirm(`Delete the course “${c.title}” and ALL of its modules, lessons, and student progress? This cannot be undone.\n\nVideos shared with a duplicated course are kept.`)) return;
    setBusy(true); setErr('');
    try {
      // Gather every storage object this course owns/uses BEFORE deleting the row: physical files
      // under its folders, plus the paths its lesson rows + cover reference (a duplicate may reuse
      // a path that physically lives under the ORIGINAL's folder). We remove only the orphans after.
      const candidates = new Set();
      // Covers live in course-media; lesson videos in the private course-videos bucket (with
      // possible legacy copies still in course-media). List each from the right bucket(s).
      try {
        const { data: objs } = await supabase.storage.from('course-media').list(`covers/${c.id}`, { limit: 1000 });
        (objs || []).forEach(o => candidates.add(`covers/${c.id}/${o.name}`));
      } catch (_) { /* ignore — row delete still proceeds */ }
      for (const bkt of [LESSON_VIDEO_BUCKET, 'course-media']) {
        try {
          const { data: objs } = await supabase.storage.from(bkt).list(`lessons/${c.id}`, { limit: 1000 });
          (objs || []).forEach(o => candidates.add(`lessons/${c.id}/${o.name}`));
        } catch (_) { /* ignore — row delete still proceeds */ }
      }
      try {
        const { data: ls } = await supabase.from('course_lessons').select('storage_path').eq('course_id', c.id);
        (ls || []).forEach(r => r.storage_path && candidates.add(r.storage_path));
      } catch (_) { /* best-effort */ }
      if (c.cover_path) candidates.add(c.cover_path);

      const { error } = await supabase.from('courses').delete().eq('id', c.id); // FK ON DELETE CASCADE clears children
      if (error) throw error;
      // After the row (and its lessons) are gone, drop only files no surviving course references.
      await removeMediaIfUnreferenced([...candidates]);
      if (selectedId === c.id) { setSelectedId(null); writeCatalogRoute(null, true); }
      if (lastDuplicatedId === c.id) setLastDuplicatedId(null);
      await loadCatalog();
    } catch (e) {
      logDbError('[CourseCatalog] delete', e, { module: prefix, courseId: c.id });
      setErr(describeDbError(e, 'Could not delete the course.'));
    } finally { setBusy(false); }
  }

  async function reorderCourse(idx, dir) {
    const j = idx + dir;
    if (j < 0 || j >= courses.length) return;
    setMenuOpenId(null); setLastDuplicatedId(null);
    const arr = [...courses];
    [arr[idx], arr[j]] = [arr[j], arr[idx]];
    setCourses(arr);                                           // optimistic
    setBusy(true); setErr('');
    try {
      await Promise.all(arr.map((c, i) => supabase.from('courses').update({ position: i, updated_at: new Date().toISOString() }).eq('id', c.id)));
      await loadCatalog();
    } catch (e) { logDbError('[CourseCatalog] reorder', e, { module: prefix }); setErr(describeDbError(e, 'Could not reorder courses.')); await loadCatalog(); }
    finally { setBusy(false); }
  }

  // Toggle a course's plan tier. `essentials` = unlocked for the Sampler plan; `standard`
  // (the default) = premium (Sampler can't open it). Mirrors the SQL courses.access_tier
  // rule in db/2026-07-11-sampler-essentials-access.sql. Admin-only (RLS also enforces it).
  async function setCourseTier(c, next) {
    setMenuOpenId(null);
    setBusy(true); setErr('');
    try {
      const { error } = await supabase.from('courses').update({ access_tier: next, updated_at: new Date().toISOString() }).eq('id', c.id);
      if (error) throw error;
      await loadCatalog();
    } catch (e) {
      logDbError('[CourseCatalog] set tier', e, { module: prefix, courseId: c.id });
      setErr(describeDbError(e, 'Could not update the course tier.'));
    } finally { setBusy(false); }
  }

  // ── Open one course in the shared engine (key forces clean state per course) ──
  if (selectedId) {
    return <CourseProgram key={selectedId} courseId={selectedId}
      eyebrow={eyebrow} courseTitle={title} comingSoonText={comingSoonDesc}
      initialNotice={selectedId === lastDuplicatedId
        ? '✓ Course duplicated as a draft. Edit the title, month, and lessons below, then publish when ready.'
        : null}
      onBack={closeCourse} />;
  }

  const errorBanner = err ? (
    <div className="mt-4 flex items-start gap-3 p-4 rounded-xl border" style={{ background: 'var(--status-danger-bg)', borderColor: 'var(--status-danger-bd)' }}>
      <AlertTriangle size={18} className="text-red-500 mt-0.5 flex-shrink-0" />
      <div className="text-sm text-red-700 flex-1">{err}</div>
      <button onClick={() => setErr('')} className="text-red-400 hover:text-red-600"><X size={16} /></button>
    </div>
  ) : null;

  // Students only see courses their plan can open (e.g. a Sampler sees Essentials, not
  // Mastery); admins always see all. RLS is the real boundary — this drives card display.
  const visibleCourses = isAdmin ? courses : courses.filter(c => ent.allowsCourse(c));

  return (
    <div>
      {!embedded && <SectionHead eyebrow={eyebrow} title={title}
        desc={isAdmin ? adminDesc : studentDesc} gold />}
      {errorBanner}

      {isAdmin && !notConfigured && !loading && courses.length > 0 && (
        <div className="flex items-center justify-between gap-3 flex-wrap mb-4">
          <div className="text-sm text-slate-500 inline-flex items-center gap-2"><BookMarked size={15} /> {courses.length} course{courses.length === 1 ? '' : 's'}</div>
          <button onClick={createCourse} disabled={busy}
            className="px-4 py-2.5 rounded-xl text-white text-sm font-semibold inline-flex items-center gap-2 disabled:opacity-60"
            style={{ background: `linear-gradient(180deg, ${C.primaryHi}, ${C.primary})` }}>
            {busy ? <Loader2 size={15} className="animate-spin" /> : <Plus size={15} />} New course
          </button>
        </div>
      )}

      {loading ? (
        <div className="flex items-center justify-center py-24 text-slate-400"><Loader2 className="animate-spin" size={28} /></div>
      ) : notConfigured ? (
        <div className="mt-6 glass-card rounded-2xl p-10 text-center" style={{ background: SHEEN }}>
          <GraduationCap size={40} className="mx-auto mb-3" style={{ color: ROYAL }} />
          <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-xl font-bold">{isAdmin ? 'Finish backend setup' : 'Courses coming soon'}</div>
          <div className="text-slate-500 mt-2 text-sm max-w-md mx-auto">
            {isAdmin
              ? 'The course tables aren’t in Supabase yet. Open COURSE_SETUP.md, run the SQL, create the public course-media bucket, then refresh this page.'
              : comingSoonDesc}
          </div>
          {isAdmin && (
            <div className="mt-4 inline-flex items-center gap-2 text-xs font-semibold px-3 py-1.5 rounded-full" style={{ background: 'var(--status-warn-bg)', color: 'var(--status-warn-fg)' }}>
              <AlertTriangle size={13} /> See COURSE_SETUP.md
            </div>
          )}
        </div>
      ) : visibleCourses.length === 0 ? (
        <div className="mt-6 glass-card rounded-2xl p-10 text-center" style={{ background: SHEEN }}>
          <GraduationCap size={40} className="mx-auto mb-3" style={{ color: ROYAL }} />
          <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-xl font-bold">{isAdmin ? 'No courses yet' : 'Courses coming soon'}</div>
          <div className="text-slate-500 mt-2 text-sm max-w-md mx-auto">
            {isAdmin ? 'Create your first course, then add modules and video lessons in the builder.' : comingSoonDesc}
          </div>
          {isAdmin && (
            <button onClick={createCourse} disabled={busy}
              className="mt-5 inline-flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-semibold text-white shadow-sm disabled:opacity-60"
              style={{ background: `linear-gradient(180deg, ${C.primaryHi}, ${C.primary})` }}>
              {busy ? <Loader2 size={15} className="animate-spin" /> : <Plus size={15} />} Create your first course
            </button>
          )}
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
          {visibleCourses.map((c, idx) => {
            const total = counts[c.id] || 0;
            const dn = Math.min(done[c.id] || 0, total);
            const pct = total ? Math.round((dn / total) * 100) : 0;
            const cover = c.cover_path ? supabase.storage.from('course-media').getPublicUrl(c.cover_path)?.data?.publicUrl : null;
            const menuOpen = menuOpenId === c.id;
            const highlight = lastDuplicatedId === c.id;
            return (
              <div key={c.id}
                className={`bg-white rounded-2xl border flex flex-col shadow-sm hover:shadow-md transition-shadow relative ${menuOpen ? 'z-50 ' : ''}${highlight ? 'border-emerald-300 ring-2 ring-emerald-300' : 'border-slate-200'}`}>
                <button onClick={() => openCourse(c.id)} className="block w-full text-left relative rounded-t-2xl overflow-hidden" style={{ aspectRatio: '16 / 9' }}>
                  {cover
                    ? <img src={cover} alt="" className="absolute inset-0 w-full h-full object-cover" />
                    : <div className="absolute inset-0 flex items-center justify-center" style={{ background: `linear-gradient(135deg, ${ROYAL}, ${CYAN})` }}><GraduationCap size={44} className="text-white/90" /></div>}
                  {isAdmin && !c.published && <span className="absolute top-2 left-2 px-2 py-0.5 rounded-full text-[10px] font-bold" style={{ background: 'var(--status-warn-bg)', color: 'var(--status-warn-fg)' }}>Draft</span>}
                  {total > 0 && pct === 100 && <span className={`absolute top-2 ${isAdmin ? 'right-11' : 'right-2'} px-2 py-0.5 rounded-full text-[10px] font-bold inline-flex items-center gap-1`} style={{ background: 'var(--status-ok-bg)', color: 'var(--status-ok-fg)' }}><Award size={11} /> Done</span>}
                </button>

                {/* Admin ⋮ action menu (Edit / Duplicate / cover / reorder / Delete) */}
                {isAdmin && (
                  <>
                    <button title="Course options" aria-label="Course options" aria-haspopup="menu" aria-expanded={menuOpen} disabled={busy}
                      onClick={() => setMenuOpenId(menuOpen ? null : c.id)}
                      className="absolute top-2 right-2 z-10 p-1.5 rounded-lg bg-white/90 backdrop-blur border border-slate-200 text-slate-600 hover:bg-white shadow-sm disabled:opacity-50">
                      <MoreVertical size={16} />
                    </button>
                    {menuOpen && (
                      <>
                        <div className="fixed inset-0 z-40" aria-hidden="true" onClick={() => setMenuOpenId(null)} />
                        <div role="menu" aria-label="Course options" className="absolute top-11 right-2 z-50 w-48 rounded-xl border border-slate-200 bg-white shadow-lg py-1 overflow-hidden">
                          <button role="menuitem" onClick={() => openCourse(c.id)} className="w-full text-left px-3 py-2 text-sm text-slate-700 hover:bg-slate-50 inline-flex items-center gap-2"><Edit3 size={14} /> Edit course</button>
                          <button role="menuitem" disabled={busy} onClick={() => duplicateCourse(c)} className="w-full text-left px-3 py-2 text-sm text-slate-700 hover:bg-slate-50 inline-flex items-center gap-2 disabled:opacity-50"><Copy size={14} /> Duplicate course</button>
                          <label role="menuitem" className="w-full text-left px-3 py-2 text-sm text-slate-700 hover:bg-slate-50 inline-flex items-center gap-2 cursor-pointer">
                            <ImageIcon size={14} /> Set cover image
                            <input type="file" accept="image/*" className="hidden" disabled={busy}
                              onChange={e => { const f = e.target.files?.[0]; setMenuOpenId(null); if (f) uploadCover(c, f); e.target.value = ''; }} />
                          </label>
                          <div className="h-px bg-slate-100 my-1" />
                          <button role="menuitemcheckbox" aria-checked={c.access_tier === 'essentials'} disabled={busy}
                            onClick={() => setCourseTier(c, c.access_tier === 'essentials' ? 'standard' : 'essentials')}
                            className="w-full text-left px-3 py-2 text-sm text-slate-700 hover:bg-slate-50 inline-flex items-center gap-2 disabled:opacity-50">
                            {c.access_tier === 'essentials' ? <CheckCircle2 size={14} style={{ color: C.primary }} /> : <Circle size={14} />} Sampler tier (Essentials)
                          </button>
                          <div className="h-px bg-slate-100 my-1" />
                          <button role="menuitem" disabled={idx === 0 || busy} onClick={() => reorderCourse(idx, -1)} className="w-full text-left px-3 py-2 text-sm text-slate-700 hover:bg-slate-50 inline-flex items-center gap-2 disabled:opacity-30"><ChevronUp size={14} /> Move up</button>
                          <button role="menuitem" disabled={idx === courses.length - 1 || busy} onClick={() => reorderCourse(idx, 1)} className="w-full text-left px-3 py-2 text-sm text-slate-700 hover:bg-slate-50 inline-flex items-center gap-2 disabled:opacity-30"><ChevronDown size={14} /> Move down</button>
                          <div className="h-px bg-slate-100 my-1" />
                          <button role="menuitem" disabled={busy} onClick={() => deleteCourse(c)} className="w-full text-left px-3 py-2 text-sm text-red-600 hover:bg-red-50 inline-flex items-center gap-2 disabled:opacity-50"><Trash2 size={14} /> Delete course</button>
                        </div>
                      </>
                    )}
                  </>
                )}

                <div className="p-4 flex-1 flex flex-col">
                  <button onClick={() => openCourse(c.id)} className="text-left flex-1">
                    <div className="mb-1.5 flex flex-wrap items-center gap-1.5">
                      {(c.course_date || c.month) && <span className="inline-flex items-center gap-1 text-[10px] font-bold uppercase tracking-wide px-2 py-0.5 rounded-full" style={{ background: 'var(--status-info-bg)', color: 'var(--status-info-fg)' }}><CalendarClock size={11} /> {c.course_date ? cohortLabel(c.course_date) : c.month}</span>}
                      {isAdmin && c.access_tier === 'essentials' && <span className="inline-flex items-center gap-1 text-[10px] font-bold uppercase tracking-wide px-2 py-0.5 rounded-full" style={{ background: 'var(--status-ok-bg)', color: 'var(--status-ok-fg)' }}><Sparkles size={11} /> Essentials · Sampler</span>}
                    </div>
                    <div style={{ fontFamily: fontDisplay, color: NAVY }} className="font-bold text-[15px] leading-tight">{c.title}</div>
                    {c.subtitle && <div className="text-xs text-slate-500 mt-1 line-clamp-2">{c.subtitle}</div>}
                  </button>
                  <div className="mt-3 text-[11px] text-slate-400 inline-flex items-center gap-1"><Play size={11} /> {total} lesson{total === 1 ? '' : 's'}</div>
                  {total > 0 && (
                    <div className="mt-2">
                      <div className="w-full h-1.5 bg-slate-100 rounded-full overflow-hidden">
                        <div className="h-full transition-all duration-500" style={{ width: `${pct}%`, background: `linear-gradient(90deg, ${ROYAL}, ${CYAN})` }} />
                      </div>
                      <div className="text-[11px] text-slate-400 mt-1">{dn} of {total} complete</div>
                    </div>
                  )}
                  <div className="mt-3">
                    <button onClick={() => openCourse(c.id)} className="w-full px-3 py-2 rounded-xl text-white text-sm font-semibold inline-flex items-center justify-center gap-2"
                      style={{ background: `linear-gradient(180deg, ${C.primaryHi}, ${C.primary})` }}>
                      {isAdmin ? 'Open' : (pct > 0 ? 'Continue' : 'Start')} <ArrowRight size={14} />
                    </button>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// Thin wrappers. QBO Mastery, Resume Winning Strategy, and Interview Winning Strategy are all
// multi-course catalogs (CourseCatalog, each scoped to its own slug prefix). QBO and Resume are
// top-level tabs (their own SectionHead); Interview is embedded as a subtab. Any pre-existing
// `resume-strategy` course matches `resume-%`, so it shows in the Resume catalog automatically —
// nothing is orphaned.
function QBOMastery() { return <CourseCatalog />; }

// Resume Winning Strategy — the `resumestrategy` tab in Profile Optimization. A multi-course
// catalog scoped to the `resume-` slug prefix, so tutors can add many resume-strategy courses
// over time (structure, summaries, achievement bullets, ATS, positioning, etc.).
function ResumeStrategy() {
  return (
    <CourseCatalog
      prefix="resume-"
      eyebrow="Resume Training"
      title="Resume Winning Strategy"
      adminDesc="Create and manage resume strategy video courses — add modules, upload or embed lessons, set covers, and publish."
      studentDesc="Build a stronger resume — structure, professional summary, achievement-driven bullets, ATS optimization, and positioning that wins interviews. Pick a course to start."
      newCourseTitle="New Resume Strategy Course"
      comingSoonDesc="Your Resume Winning Strategy training is being prepared. Check back soon."
    />
  );
}

// Rendered as the 7th subtab inside InterviewPrep — a multi-course catalog scoped to the
// `interview-` slug prefix (so tutors can add many interview-strategy courses over time).
// Forwards `embedded` so the catalog drops its own SectionHead (the suite header above it
// already covers the title). The pre-existing `interview-winning-strategy` course, if any,
// matches `interview-%` and shows here automatically — nothing is orphaned.
function InterviewStrategyCatalog({ embedded = false }) {
  return (
    <CourseCatalog
      prefix="interview-"
      embedded={embedded}
      eyebrow="Strategy Courses"
      title="Interview Winning Strategy"
      adminDesc="Create and manage interview strategy video courses — add modules, upload or embed lessons, set covers, and publish."
      studentDesc="Practical strategies to win the offer — confidence, storytelling, tough questions, presence, and real-interview prep. Pick a course to start."
      newCourseTitle="New Interview Strategy Course"
      comingSoonDesc="Your Interview Winning Strategy training is being prepared. Check back soon."
    />
  );
}

// ═══════════════════════════════════════════════════════════════════
// COMPONENT: BANK FEED CATEGORIZATION
// ═══════════════════════════════════════════════════════════════════

function BankFeed() {
  const [input, setInput] = useState('');
  const [ctx, setCtx] = useState('General');
  const [results, setResults] = useState([]);
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState('');

  // First try local regex pattern match, then call Claude for anything unmatched/low-confidence
  const analyze = async () => {
    const lines = input.split('\n').map(l => l.trim()).filter(l => l);
    if (lines.length === 0) return;
    setBusy(true);
    setErr('');

    // Pass 1: local fast match
    const initialResults = lines.map(line => {
      let match = VENDOR_PATTERNS.find(p => p.regex.test(line));
      let date = '';
      let amount = '';
      const dateMatch = line.match(/\b(\d{1,2}\/\d{1,2}\/?\d{0,4})\b/);
      const amtMatch = line.match(/-?\$?(\d{1,3}(?:,\d{3})*(?:\.\d{2})?)/);
      if (dateMatch) date = dateMatch[1];
      if (amtMatch) amount = amtMatch[0];

      if (!match) {
        return { line, date, amount, vendor: 'Pending AI…', account: 'Pending AI…', type: 'AI', conf: 0, note: 'Sending to ProAdvisor AI for nearest match…', needsAI: true };
      }

      let account = match.account;
      let note = match.note;

      if (ctx === 'Construction' && /home depot|lowes|menards|ace hardware|hardware/i.test(line)) {
        account = 'Job Materials'; note = 'Contractor context — coded to Job Materials COGS, not R&M.';
      }
      if (ctx === 'Restaurant' && /home depot|lowes/i.test(line)) {
        account = 'Repairs & Maintenance'; note = 'Restaurant context — likely facility repairs.';
      }
      if (ctx === 'Trucking' && /shell|chevron|exxon|mobil|bp|valero|pilot|loves/i.test(line)) {
        account = 'Fuel - Trucks'; note = 'Trucking context — fuel goes to COGS.';
      }
      if (ctx === 'Real Estate' && /home depot|lowes/i.test(line)) {
        account = 'Property R&M'; note = 'Real estate context — code to specific property R&M (use Classes).';
      }

      return { line, date, amount, vendor: match.vendor, account, type: match.type, conf: match.conf, note, needsAI: false };
    });

    setResults(initialResults);

    // Pass 2: send unmatched lines to Claude for nearest-match suggestion
    const unmatched = initialResults.filter(r => r.needsAI);
    if (unmatched.length === 0) {
      setBusy(false);
      return;
    }

    try {
      const memos = unmatched.map((r, i) => `${i + 1}. ${r.line}`).join('\n');
      const sys = `You are a 15-year US QuickBooks ProAdvisor. The user pastes raw bank memo lines from a bank feed. For each line, suggest the NEAREST/CLOSEST matching vendor name (cleaning up the cryptic memo) AND the most appropriate Chart of Account name. Use standard QBO account names (e.g., "Office Supplies", "Advertising & Marketing", "Dues & Subscriptions", "Travel", "Meals - 50% Deductible", "Bank Fees", "Telephone & Internet", "Utilities", "Rent Expense", "Wages & Salaries", "Contract Labor", "Repairs & Maintenance", "Insurance", "Owner's Draws", "Legal & Professional Fees", "Sales Income", "Service Income", "Merchant Processing Fees", "Job Materials", "Subcontractor Expense", "Vehicle Expense", "Shipping Costs", etc.).

Industry context provided: ${ctx}

Return ONLY a JSON array, no other text, no markdown fences. Format:
[{"i":1,"vendor":"...","account":"...","conf":0.85,"note":"short 1-sentence rationale"},...]

Confidence (conf) 0.0-1.0: use 0.9+ if vendor is unambiguous, 0.6-0.8 if you're making a reasoned guess, below 0.5 if it really needs human review. If you cannot determine vendor/account at all, set vendor and account to "NEEDS REVIEW" and conf to 0.2 with a note explaining what's missing.`;

      const raw = (await callClaude({ max_tokens: 1500, system: sys, messages: [{ role: 'user', content: memos }] })).trim();
      const cleaned = raw.replace(/```json|```/g, '').trim();
      const aiResults = JSON.parse(cleaned);

      // Merge AI results back
      const merged = [...initialResults];
      // Precompute each unmatched row's array index BEFORE the loop mutates `merged`. We flip
      // needsAI=false as we assign, so re-deriving the index from the mutated array (the old
      // approach) shifted later suggestions onto the wrong transaction and dropped the rest.
      // The AI returns i = 1..N against the ORIGINAL unmatched order, so map i-1 → saved index.
      const aiTargetIdx = [];
      initialResults.forEach((r, i) => { if (r.needsAI) aiTargetIdx.push(i); });
      aiResults.forEach(ai => {
        const targetIdx = aiTargetIdx[ai.i - 1] ?? -1;
        if (targetIdx >= 0 && merged[targetIdx]?.needsAI) {
          merged[targetIdx] = {
            ...merged[targetIdx],
            vendor: ai.vendor,
            account: ai.account,
            conf: ai.conf,
            note: '🤖 ' + ai.note,
            needsAI: false,
            type: 'AI',
          };
        }
      });
      setResults(merged);
    } catch (e) {
      setErr('AI matching failed for some rows — they are flagged for review. You can still use the local matches.');
      setResults(initialResults.map(r => r.needsAI ? { ...r, vendor: 'NEEDS REVIEW', account: 'NEEDS REVIEW', note: '⚠️ AI unavailable — please review manually.', conf: 0.1 } : r));
    }
    setBusy(false);
  };

  const sample = `01/05/2024  AMZN MKTP US*A123XY  -$87.45
01/06/2024  STARBUCKS STORE #4521  -$14.20
01/06/2024  SHELL OIL 12345  -$62.00
01/07/2024  HOME DEPOT #1234  -$245.78
01/08/2024  STRIPE TRANSFER  +$3,420.00
01/09/2024  ZELLE PAYMENT TO JOHN SMITH  -$500.00
01/10/2024  GUSTO PAYROLL DDA  -$8,420.55
01/11/2024  VERIZON WIRELESS  -$185.00
01/12/2024  GOOGLE *ADS123456  -$420.00
01/13/2024  ACME PLUMBING SVC INC  -$650.00
01/14/2024  SQUARE INC *COFFEE SH  +$1,240.00
01/15/2024  CHECK #1042  -$1,200.00`;

  return (
    <div>
      <SectionHead eyebrow="Tool 03" title="Bank Feed AI · Categorization Assistant" desc="Paste the raw memo/description from your bank feed. AI returns the nearest-match vendor and the appropriate QBO Chart of Account." />

      <div style={{ background: SHEEN }} className="glass-card p-7 rounded-2xl mt-6">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-4">
          <div className="md:col-span-1">
            <label className="text-xs uppercase tracking-wider font-bold text-slate-600 block mb-2">Industry Context</label>
            <select value={ctx} onChange={e => setCtx(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm font-medium focus:border-blue-500 outline-none">
              {['General', 'Construction', 'Restaurant', 'Trucking', 'Real Estate', 'E-commerce', 'Professional Services'].map(c => <option key={c}>{c}</option>)}
            </select>
          </div>
          <div className="md:col-span-3 flex items-end gap-2">
            <button onClick={() => setInput(sample)}
              className="text-xs px-4 py-2 rounded-lg bg-white border border-slate-300 hover:border-blue-400 text-slate-700 font-semibold">
              Load Sample Bank Memos
            </button>
            <div className="text-xs text-slate-500 italic">💡 Tip: Paste the memo/description column directly from your QBO bank feed.</div>
          </div>
        </div>

        <textarea value={input} onChange={e => setInput(e.target.value)}
          placeholder="Paste your bank feed memos here, one per line. Example: AMZN MKTP US*A123XY  -$87.45"
          className="w-full h-44 p-4 rounded-xl border border-slate-200 bg-white text-sm font-mono focus:border-blue-500 focus:ring-2 focus:ring-blue-200 outline-none resize-none" />

        <button onClick={analyze} disabled={busy}
          className="sheen-btn mt-4 text-white font-bold py-3 px-8 rounded-xl shadow-lg text-sm tracking-wide flex items-center gap-2 disabled:opacity-60">
          {busy ? <><Loader2 size={16} className="animate-spin" /> Analyzing with ProAdvisor AI...</> : <><Search size={16} /> Analyze Transactions</>}
        </button>
        {err && <div className="mt-3 text-xs text-red-600">{err}</div>}
      </div>

      {results.length > 0 && (
        <div className="mt-8 fade-in">
          <div className="text-sm text-slate-600 mb-3">{results.length} transactions analyzed · {results.filter(r => r.conf < 0.5).length} flagged for review</div>
          <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-lg">
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead style={{ background: INK.navy }} className="text-white">
                  <tr>
                    <th className="text-left px-3 py-3 text-xs uppercase tracking-wider font-semibold">Date</th>
                    <th className="text-left px-3 py-3 text-xs uppercase tracking-wider font-semibold">Bank Memo</th>
                    <th className="text-left px-3 py-3 text-xs uppercase tracking-wider font-semibold">Vendor</th>
                    <th className="text-left px-3 py-3 text-xs uppercase tracking-wider font-semibold">Suggested Account</th>
                    <th className="text-left px-3 py-3 text-xs uppercase tracking-wider font-semibold">Conf</th>
                    <th className="text-left px-3 py-3 text-xs uppercase tracking-wider font-semibold">ProAdvisor Note</th>
                  </tr>
                </thead>
                <tbody>
                  {results.map((r, i) => {
                    const flagged = r.conf < 0.5;
                    return (
                      <tr key={i} className={flagged ? 'bg-sky-50' : (i % 2 ? 'bg-slate-50' : 'bg-white')}>
                        <td className="px-3 py-3 font-mono text-xs text-slate-600">{r.date || '—'}</td>
                        <td className="px-3 py-3 font-mono text-xs text-slate-700 max-w-xs truncate">{r.line}</td>
                        <td className="px-3 py-3 font-semibold text-slate-800">{r.vendor}</td>
                        <td className="px-3 py-3">
                          <span className={`inline-block px-2.5 py-1 rounded-md text-xs font-semibold ${flagged ? 'bg-sky-200 text-blue-900' : 'bg-blue-100 text-blue-800'}`}>
                            {r.account}
                          </span>
                        </td>
                        <td className="px-3 py-3">
                          <span className={`text-xs font-bold ${r.conf >= 0.8 ? 'text-blue-700' : r.conf >= 0.5 ? 'text-sky-600' : 'text-slate-500'}`}>
                            {Math.round(r.conf * 100)}%
                          </span>
                        </td>
                        <td className="px-3 py-3 text-xs text-slate-600 max-w-md leading-relaxed">{r.note}</td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════
// COMPONENT: STATEMENT CONVERTER
// ═══════════════════════════════════════════════════════════════════

function StatementConverter() {
  const [raw, setRaw] = useState('');
  const [parsed, setParsed] = useState([]);
  const [bankFmt, setBankFmt] = useState('');
  const [beginBal, setBeginBal] = useState('');
  const [endBal, setEndBal] = useState('');
  const [processing, setProcessing] = useState(false);
  const [uploadStatus, setUploadStatus] = useState('');
  const [uploadedName, setUploadedName] = useState('');
  const [err, setErr] = useState('');
  const fileInputRef = useRef(null);

  const detectBank = (text) => {
    if (/chase|jpmorgan/i.test(text)) return 'Chase';
    if (/bank of america|bofa/i.test(text)) return 'Bank of America';
    if (/wells fargo/i.test(text)) return 'Wells Fargo';
    if (/citi|citibank/i.test(text)) return 'Citi';
    if (/american express|amex/i.test(text)) return 'American Express';
    if (/capital one/i.test(text)) return 'Capital One';
    if (/u\.?s\.? bank|usbank/i.test(text)) return 'US Bank';
    if (/pnc/i.test(text)) return 'PNC';
    if (/td bank/i.test(text)) return 'TD Bank';
    if (/truist/i.test(text)) return 'Truist';
    return 'Generic';
  };

  // Read file as base64 (used for PDFs and images)
  const fileToBase64 = (file) => new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result.split(',')[1]);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });

  // Read file as text (for .txt and .csv)
  const fileToText = (file) => new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result);
    reader.onerror = reject;
    reader.readAsText(file);
  });

  const handleFile = async (file) => {
    if (!file) return;
    setErr('');
    setUploadedName(file.name);
    setProcessing(true);
    setUploadStatus(`Reading ${file.name}...`);

    const ext = file.name.toLowerCase().split('.').pop();
    const mime = file.type;

    try {
      // Plain text — read directly
      if (ext === 'txt' || mime === 'text/plain') {
        const text = await fileToText(file);
        setRaw(text);
        setUploadStatus('Text loaded. Click "Parse Statement" to extract transactions.');
        setProcessing(false);
        return;
      }

      // PDF or image — use Claude vision/document
      if (ext === 'pdf' || ext === 'png' || ext === 'jpg' || ext === 'jpeg' ||
          mime === 'application/pdf' || mime.startsWith('image/')) {
        // base64 inflates ~33% and the AI proxy caps the request body at 5 MB, so guard the
        // raw file at 3.5 MB (→ ~4.7 MB encoded) with a clear message instead of a generic 413.
        if (file.size > 3.5 * 1024 * 1024) {
          setErr(`This file is ${(file.size / 1024 / 1024).toFixed(1)} MB. Please keep statement uploads under 3.5 MB — split a long PDF into fewer pages so it fits the AI extraction limit.`);
          setProcessing(false);
          return;
        }
        setUploadStatus(`Extracting transactions from ${ext.toUpperCase()} with AI...`);
        const b64 = await fileToBase64(file);

        const isPdf = ext === 'pdf' || mime === 'application/pdf';
        const sourceMime = isPdf ? 'application/pdf' :
                          ext === 'png' ? 'image/png' :
                          (ext === 'jpg' || ext === 'jpeg') ? 'image/jpeg' :
                          mime;

        const content = [
          {
            type: isPdf ? 'document' : 'image',
            source: { type: 'base64', media_type: sourceMime, data: b64 }
          },
          {
            type: 'text',
            text: `This is a bank or credit card statement. Extract EVERY transaction row into a plain text format with this exact column order separated by 4+ spaces:

DATE  DESCRIPTION  AMOUNT  BALANCE

Rules:
- Date format: MM/DD/YYYY (use the statement year)
- Description: the full memo/payee as shown
- Amount: negative for withdrawals/charges/debits, positive for deposits/credits. Format: -1234.56 or 1234.56 (no $ no commas)
- Balance: running balance if shown, otherwise omit that column
- One transaction per line, no headers, no totals, no summaries
- Skip footer text, ads, account numbers, and disclaimers

Also identify:
- Beginning balance (statement period opening)
- Ending balance (statement period closing)

Output format:
BEGIN_BALANCE: 1234.56
END_BALANCE: 2345.67
TRANSACTIONS:
01/05/2024  AMAZON MKTP US  -87.45  12362.55
01/06/2024  STARBUCKS #4521  -14.20  12348.35
...

Output ONLY this format. No markdown, no explanation.`
          }
        ];

        const { text: rawExtract, data: exData } = await callClaude(
          { max_tokens: 4000, messages: [{ role: 'user', content }] },
          { returnData: true }
        );
        // If the model ran out of output budget the transaction list is cut off mid-way — don't
        // present a partial extraction as complete (matches the guard in PainPoints/QBDiagnostic/etc.).
        if (exData?.stop_reason === 'max_tokens') {
          setErr('This statement is too long to extract in one pass — split it into fewer pages (or upload a shorter date range) and try again.');
          setProcessing(false);
          return;
        }
        const extracted = rawExtract.trim();

        // Parse the structured output
        const beginMatch = extracted.match(/BEGIN_BALANCE:\s*(-?[\d,]+\.\d{2})/i);
        const endMatch = extracted.match(/END_BALANCE:\s*(-?[\d,]+\.\d{2})/i);
        if (beginMatch) setBeginBal(beginMatch[1].replace(/,/g, ''));
        if (endMatch) setEndBal(endMatch[1].replace(/,/g, ''));

        const txnSection = extracted.split(/TRANSACTIONS:/i)[1] || extracted;
        setRaw(txnSection.trim());
        setUploadStatus(`✓ Extracted from ${file.name}. Click "Parse Statement" to confirm.`);
        setProcessing(false);
        return;
      }

      setErr('Unsupported file type. Use PDF, JPEG, PNG, or TXT.');
      setProcessing(false);
    } catch (e) {
      setErr('Failed to read file: ' + (e.message || 'unknown error'));
      setProcessing(false);
    }
  };

  const parse = () => {
    setProcessing(true);
    setTimeout(() => {
      const fmt = detectBank(raw);
      setBankFmt(fmt);

      const lines = raw.split('\n').map(l => l.trim()).filter(l => l);
      const rows = [];
      // Tolerant regex: date, description, amount, optional balance
      const rowRegex = /^(\d{1,2}\/\d{1,2}(?:\/\d{2,4})?)\s+(.+?)\s+(-?\$?[\d,]+\.\d{2})(?:\s+(-?\$?[\d,]+\.\d{2}))?$/;

      lines.forEach(line => {
        const m = line.match(rowRegex);
        if (m) {
          const amount = parseFloat(m[3].replace(/[$,]/g, ''));
          rows.push({
            date: m[1],
            desc: m[2].trim(),
            amount,
            type: amount >= 0 ? 'Deposit' : 'Withdrawal',
            balance: m[4] ? parseFloat(m[4].replace(/[$,]/g, '')) : null,
          });
        }
      });

      setParsed(rows);
      setProcessing(false);
    }, 600);
  };

  const totalDep = parsed.filter(r => r.amount > 0).reduce((s, r) => s + r.amount, 0);
  const totalWd  = parsed.filter(r => r.amount < 0).reduce((s, r) => s + r.amount, 0);
  const computed = parseFloat(beginBal || 0) + totalDep + totalWd;
  const expected = parseFloat(endBal || 0);
  const diff = Math.abs(computed - expected);
  const balanced = parsed.length > 0 && beginBal && endBal && diff < 0.01;

  const exportCSV = () => {
    if (!parsed || parsed.length === 0) {
      setErr('No transactions to export. Process a statement first.');
      return;
    }
    try {
      const header = ['Date', 'Description', 'Amount', 'Type'];
      const csv = [header, ...parsed.map(r => [r.date, r.desc, r.amount.toFixed(2), r.type])]
        .map(row => row.map(c => `"${String(c).replace(/"/g, '""')}"`).join(','))
        .join('\n');
      // Prepend BOM so Excel opens UTF-8 correctly
      const blob = new Blob(['\ufeff', csv], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `bank_statement_${Date.now()}.csv`;
      a.style.display = 'none';
      document.body.appendChild(a);  // CRITICAL: append to DOM before click()
      a.click();
      // Cleanup after slight delay so click() completes
      setTimeout(() => {
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
      }, 100);
    } catch (err) {
      console.error('CSV export error:', err);
      setErr('CSV export failed: ' + (err.message || 'unknown error'));
    }
  };

  return (
    <div>
      <SectionHead eyebrow="Tool 04" title="Statement Converter · PDF / Image / Text → CSV" desc="Upload a bank or credit card statement as PDF, JPEG, PNG, or TXT. AI extracts every transaction. Download a clean QBO-ready CSV." />

      <div style={{ background: SHEEN }} className="glass-card p-7 rounded-2xl mt-6">
        {/* Upload zone */}
        <div className="mb-5">
          <div className="text-xs uppercase tracking-wider font-bold text-slate-600 block mb-2">Upload Statement</div>
          <div
            role="button" tabIndex={0}
            aria-label="Upload bank statement (PDF, image, or text file)"
            onClick={() => fileInputRef.current?.click()}
            onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); fileInputRef.current?.click(); } }}
            onDragOver={(e) => { e.preventDefault(); e.stopPropagation(); }}
            onDrop={(e) => {
              e.preventDefault(); e.stopPropagation();
              const f = e.dataTransfer.files?.[0];
              if (f) handleFile(f);
            }}
            className="border-2 border-dashed border-slate-300 rounded-2xl p-8 text-center cursor-pointer hover:border-blue-500 hover:bg-blue-50/30 transition-all"
            style={{ background: 'rgba(255,255,255,0.5)' }}>
            <input
              ref={fileInputRef}
              type="file"
              accept=".pdf,.png,.jpg,.jpeg,.txt,application/pdf,image/png,image/jpeg,text/plain"
              onChange={(e) => handleFile(e.target.files?.[0])}
              className="hidden"
            />
            <div className="flex items-center justify-center gap-3 mb-3">
              <div style={{ background: `linear-gradient(135deg, ${ROYAL} 0%, ${CYAN} 100%)` }} className="w-12 h-12 rounded-xl flex items-center justify-center shadow-lg">
                <Upload size={20} className="text-white" />
              </div>
            </div>
            <div className="text-base font-semibold text-slate-700 mb-1">
              {uploadedName ? `📄 ${uploadedName}` : 'Drop file here or click to upload'}
            </div>
            <div className="text-xs text-slate-500 flex items-center justify-center gap-3 mt-2 flex-wrap">
              <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded bg-red-50 text-red-700 font-semibold"><FileText size={12} /> PDF</span>
              <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded bg-emerald-50 text-emerald-700 font-semibold"><ImageIcon size={12} /> JPEG / PNG</span>
              <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded bg-blue-50 text-blue-700 font-semibold"><FileType2 size={12} /> TXT</span>
            </div>
            {uploadStatus && (
              <div className="mt-3 text-xs font-semibold" style={{ color: ROYAL }}>
                {processing && <Loader2 size={12} className="inline animate-spin mr-1" />}
                {uploadStatus}
              </div>
            )}
            {err && <div className="mt-3 text-xs text-red-600 font-semibold">{err}</div>}
          </div>
        </div>

        <div className="mb-2 flex items-center justify-between">
          <div className="text-xs uppercase tracking-wider font-bold text-slate-600">Extracted Transactions (editable)</div>
          <div className="text-[10px] text-slate-400">Auto-filled after upload, or paste manually</div>
        </div>

        <textarea value={raw} onChange={e => setRaw(e.target.value)}
          placeholder="After upload, extracted transactions appear here. You can also paste text directly."
          className="w-full h-44 p-4 rounded-xl border border-slate-200 bg-white text-sm font-mono focus:border-blue-500 focus:ring-2 focus:ring-blue-200 outline-none resize-none" />

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mt-4">
          <div>
            <label className="text-xs uppercase tracking-wider font-bold text-slate-600 block mb-2">Beginning Balance</label>
            <input type="number" step="0.01" value={beginBal} onChange={e => setBeginBal(e.target.value)} placeholder="0.00"
              className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm font-mono focus:border-blue-500 outline-none" />
          </div>
          <div>
            <label className="text-xs uppercase tracking-wider font-bold text-slate-600 block mb-2">Ending Balance</label>
            <input type="number" step="0.01" value={endBal} onChange={e => setEndBal(e.target.value)} placeholder="0.00"
              className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm font-mono focus:border-blue-500 outline-none" />
          </div>
          <div className="flex items-end">
            <button onClick={parse} disabled={processing || !raw}
              className="sheen-btn w-full text-white font-bold py-3 rounded-xl shadow-lg text-sm tracking-wide flex items-center justify-center gap-2 disabled:opacity-60">
              {processing ? <><Loader2 size={16} className="animate-spin" /> Processing...</> : <><Search size={16} /> Parse Statement</>}
            </button>
          </div>
        </div>
      </div>

      {parsed.length > 0 && (
        <div className="mt-8 fade-in">
          <div className="flex justify-between items-center mb-4">
            <div>
              <div style={{ color: NAVY, fontFamily: fontDisplay }} className="text-2xl font-bold">Parsed Statement</div>
              <div className="text-sm text-slate-500">Format detected: <span className="font-semibold text-blue-700">{bankFmt}</span> · {parsed.length} transactions</div>
            </div>
            <button onClick={exportCSV}
              className="flex items-center gap-2 px-5 py-2.5 rounded-xl bg-white border border-slate-300 hover:border-blue-400 transition text-sm font-semibold text-slate-700 shadow-sm">
              <Download size={16} /> Download QBO-Ready CSV
            </button>
          </div>

          {/* Reconciliation banner */}
          {beginBal && endBal && (
            <div className={`mb-4 p-5 rounded-2xl border-l-4 ${balanced ? 'bg-emerald-50 border-emerald-500' : 'bg-red-50 border-red-500'}`}>
              <div className="flex items-center gap-3">
                {balanced
                  ? <CheckCircle2 size={24} className="text-emerald-600" />
                  : <AlertTriangle size={24} className="text-red-600" />}
                <div className="flex-1">
                  <div className={`font-bold text-sm uppercase tracking-wider ${balanced ? 'text-emerald-900' : 'text-red-900'}`}>
                    {balanced ? '✓ Reconciliation Balanced' : '⚠ Reconciliation Discrepancy'}
                  </div>
                  <div className={`text-sm mt-1 ${balanced ? 'text-emerald-700' : 'text-red-700'}`}>
                    Begin ${parseFloat(beginBal).toFixed(2)} + Deposits ${totalDep.toFixed(2)} + Withdrawals ${totalWd.toFixed(2)} = ${computed.toFixed(2)}
                    {balanced ? ' ✓ matches' : ` ⚠ vs ending balance $${expected.toFixed(2)} (diff: $${diff.toFixed(2)})`}
                  </div>
                </div>
              </div>
            </div>
          )}

          <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-lg">
            <div className="overflow-x-auto max-h-[450px] overflow-y-auto">
              <table className="w-full text-sm">
                <thead style={{ background: INK.navy }} className="text-white sticky top-0">
                  <tr>
                    <th className="text-left px-4 py-3 text-xs uppercase tracking-wider font-semibold">Date</th>
                    <th className="text-left px-4 py-3 text-xs uppercase tracking-wider font-semibold">Description</th>
                    <th className="text-right px-4 py-3 text-xs uppercase tracking-wider font-semibold">Amount</th>
                    <th className="text-left px-4 py-3 text-xs uppercase tracking-wider font-semibold">Type</th>
                    <th className="text-right px-4 py-3 text-xs uppercase tracking-wider font-semibold">Balance</th>
                  </tr>
                </thead>
                <tbody>
                  {parsed.map((r, i) => (
                    <tr key={i} className={i % 2 ? 'bg-slate-50' : 'bg-white'}>
                      <td className="px-4 py-2.5 font-mono text-xs text-slate-600">{r.date}</td>
                      <td className="px-4 py-2.5 text-slate-700">{r.desc}</td>
                      <td className={`px-4 py-2.5 text-right font-mono font-semibold ${r.amount >= 0 ? 'text-emerald-600' : 'text-red-600'}`}>
                        {r.amount >= 0 ? '+' : ''}{r.amount.toFixed(2)}
                      </td>
                      <td className="px-4 py-2.5">
                        <span className={`text-xs font-semibold px-2 py-0.5 rounded ${r.amount >= 0 ? 'bg-emerald-100 text-emerald-800' : 'bg-red-100 text-red-800'}`}>
                          {r.type}
                        </span>
                      </td>
                      <td className="px-4 py-2.5 text-right font-mono text-xs text-slate-500">
                        {r.balance ? r.balance.toFixed(2) : '—'}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════
// COMPONENT: PROADVISOR CHAT
// ═══════════════════════════════════════════════════════════════════

function ProChat() {
  const [messages, setMessages] = useState([
    { role: 'assistant', text: "Hi! I'm your ProAdvisor mentor — 15 years of QBO and US accounting in your corner. Ask me anything: clean-up scenarios, journal entries, sales tax, payroll, month-end close, you name it. What's on your mind today?" }
  ]);
  const [input, setInput] = useState('');
  const [busy, setBusy] = useState(false);
  const scrollRef = useRef(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, busy]);

  const suggestions = [
    "How do I clean up Undeposited Funds?",
    "How do I record an owner contribution?",
    "How do I fix negative A/R?",
    "Walk me through month-end close.",
    "How do I reconcile a credit card in QBO?",
    "Cash vs accrual — which should I use?",
    "How do I handle Stripe deposits in QBO?",
    "How do I split a Gusto payroll draw?",
  ];

  const send = async (text) => {
    const userText = text || input;
    if (!userText.trim() || busy) return;
    const userMsg = { role: 'user', text: userText };
    setMessages(m => [...m, userMsg]);
    setInput('');
    setBusy(true);

    try {
      const conv = [...messages, userMsg]
        .filter(m => m.role !== 'system')
        .map(m => ({ role: m.role === 'assistant' ? 'assistant' : 'user', content: m.text }));

      const sys = `You are a US Accountant and 15-year QuickBooks Online ProAdvisor mentoring a beginner remote bookkeeper. Answer in clear, step-by-step language. Cover QBO navigation, bookkeeping workflows, cleanup scenarios (uncategorized expenses, negative AR, double-booked income, undeposited funds stuck, beginning balance issues, bank rec discrepancies), journal entries, sales tax, payroll basics, 1099 prep, year-end close, and US GAAP basics. Always give the practical QBO click-path when relevant (e.g., "Go to ⚙️ Settings → Reconcile"). Be encouraging, warm, and direct. Keep responses focused — typically 150-300 words unless the topic genuinely needs more depth. Use short paragraphs and numbered steps when giving procedures. Never give legal or tax-advice — clarify that you're sharing bookkeeping best practices.`;

      const replyText = (await callClaude({ max_tokens: 1000, system: sys, messages: conv }))
        || "Sorry, I didn't catch that — could you try again?";
      setMessages(m => [...m, { role: 'assistant', text: replyText }]);
    } catch (err) {
      console.error('ProAdvisor chat failed:', err);
      setMessages(m => [...m, { role: 'assistant', text: "I'm having trouble reaching my brain right now — please try again in a moment." }]);
    }
    setBusy(false);
  };

  return (
    <div>
      <SectionHead eyebrow="Tool 05" title="ProAdvisor Chat Support" desc="Live mentor for QBO workflows, cleanup scenarios, journal entries, payroll, and US GAAP basics." />

      <div style={{ background: SHEEN }} className="glass-card rounded-2xl mt-6 overflow-hidden">
        {/* Header */}
        <div style={{ background: `linear-gradient(135deg, ${INK.navy} 0%, #0F2A5A 100%)` }} className="px-6 py-4 text-white flex items-center gap-3">
          <div style={{ background: `linear-gradient(135deg, ${ROYAL} 0%, ${CYAN} 100%)`, fontFamily: fontDisplay }} className="w-10 h-10 rounded-full flex items-center justify-center font-bold shadow-lg">
            <Crown size={18} className="text-white" />
          </div>
          <div>
            <div className="font-bold">ProAdvisor Mentor</div>
            <div className="text-xs text-blue-200 flex items-center gap-1.5">
              <span className="w-2 h-2 rounded-full bg-emerald-400 animate-pulse" />
              Online · 15+ years QBO experience
            </div>
          </div>
        </div>

        {/* Messages */}
        <div ref={scrollRef} className="h-[480px] overflow-y-auto p-6 space-y-4 bg-white">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] rounded-2xl px-5 py-3 text-sm leading-relaxed whitespace-pre-wrap ${
                m.role === 'user'
                  ? 'text-white shadow-md'
                  : 'bg-white border border-blue-200 text-slate-800 shadow-sm'
              }`}
              style={m.role === 'user' ? { background: `linear-gradient(135deg, ${ROYAL} 0%, ${CYAN} 100%)` } : {}}>
                {m.text}
              </div>
            </div>
          ))}
          {busy && (
            <div className="flex justify-start">
              <div className="bg-white border border-blue-200 rounded-2xl px-5 py-3 text-sm text-slate-500 flex items-center gap-2">
                <Loader2 size={14} className="animate-spin" /> Thinking...
              </div>
            </div>
          )}
        </div>

        {/* Suggestion chips */}
        {messages.length <= 2 && (
          <div className="px-6 py-3 bg-slate-50 border-t border-slate-200 flex flex-wrap gap-2">
            {suggestions.map(s => (
              <button key={s} onClick={() => send(s)} disabled={busy}
                className="text-xs px-3 py-1.5 rounded-full bg-white border border-slate-300 hover:border-blue-400 hover:bg-blue-50 text-slate-700 font-medium transition disabled:opacity-50">
                {s}
              </button>
            ))}
          </div>
        )}

        {/* Input */}
        <div className="p-4 border-t border-slate-200 bg-white flex gap-2">
          <input value={input} onChange={e => setInput(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && !e.shiftKey && send()}
            placeholder="Ask anything about QBO, bookkeeping, or cleanup..."
            disabled={busy}
            className="flex-1 px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm focus:border-blue-500 focus:ring-2 focus:ring-blue-200 outline-none disabled:opacity-50" />
          <button onClick={() => send()} disabled={busy || !input.trim()}
            className="sheen-btn text-white font-bold px-5 rounded-xl shadow-lg disabled:opacity-50 flex items-center gap-2">
            <Send size={16} />
          </button>
        </div>
      </div>
    </div>
  );
}

