function Form1099() {
  const [checked, setChecked] = useState(new Set());
  const [taxYear, setTaxYear] = useState('2026');
  const toggle = (i) => {
    const next = new Set(checked);
    if (next.has(i)) next.delete(i); else next.add(i);
    setChecked(next);
  };
  const progress = Math.round((checked.size / FORM_1099_CHECKLIST.length) * 100);

  const threshold = taxYear === '2025' ? 600 : 2000;

  return (
    <div>
      <SectionHead eyebrow="Tool 11" title="1099 Prep · Year-End Workflow" desc="Run this every January. Misses on 1099s cause audits, penalties, and angry clients." />

      {/* Year toggle and threshold callout */}
      <div style={{ background: SHEEN }} className="glass-card p-6 rounded-2xl mt-6 mb-4">
        <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
          <div>
            <div className="text-xs uppercase tracking-[0.2em] font-bold text-slate-600 mb-2">Tax Year</div>
            <div className="flex gap-2">
              {['2025', '2026'].map(y => (
                <button key={y} onClick={() => setTaxYear(y)}
                  className={`px-5 py-2.5 rounded-xl font-bold text-sm transition-all ${
                    taxYear === y
                      ? 'text-white shadow-lg'
                      : 'bg-white border border-slate-300 text-slate-700 hover:border-blue-400'
                  }`}
                  style={taxYear === y ? { background: `linear-gradient(135deg, ${ROYAL} 0%, ${CYAN} 100%)` } : {}}>
                  TY {y}
                </button>
              ))}
            </div>
          </div>
          <div className="flex-1 md:max-w-md p-4 rounded-xl border-l-4" style={{ background: 'var(--status-info-bg)', borderColor: ROYAL }}>
            <div className="text-xs font-bold uppercase tracking-wider" style={{ color: ROYAL }}>1099-NEC / 1099-MISC Threshold</div>
            <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-3xl font-bold mt-1">${threshold.toLocaleString()}</div>
            <div className="text-xs text-slate-700 mt-1 leading-relaxed">
              {taxYear === '2026'
                ? 'OBBBA-revised threshold, effective payments made on or after Jan 1, 2026. Indexed for inflation starting 2027.'
                : 'Legacy $600 threshold (unchanged since the 1950s). Last year under this rule.'}
            </div>
          </div>
        </div>
      </div>

      <div style={{ background: SHEEN }} className="glass-card p-6 rounded-2xl">
        <div className="flex items-center justify-between mb-3">
          <div>
            <div className="text-xs uppercase tracking-[0.2em] font-bold text-slate-600">Checklist Progress</div>
            <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-2xl font-bold">{checked.size} of {FORM_1099_CHECKLIST.length}</div>
          </div>
          <div style={{ color: ROYAL, fontFamily: fontDisplay }} className="text-4xl font-bold">{progress}%</div>
        </div>
        <div className="w-full h-2.5 bg-slate-200 rounded-full overflow-hidden">
          <div className="h-full transition-all duration-500" style={{ width: `${progress}%`, background: `linear-gradient(90deg, ${ROYAL}, ${CYAN})` }} />
        </div>
      </div>

      <div className="mt-6 space-y-2">
        {FORM_1099_CHECKLIST.map((c, i) => {
          const done = checked.has(i);
          // dynamically replace the threshold in step 1
          const task = i === 0 ? `Identify all vendors paid $${threshold.toLocaleString()}+ during the calendar year` : c.task;
          const detail = i === 0 ? `Run Vendor Contact List with payments report in QBO. Filter for ≥ $${threshold.toLocaleString()}. (TY ${taxYear} threshold)` : c.detail;
          return (
            <div key={i} className={`bg-white rounded-xl border transition p-4 flex items-start gap-4 ${done ? 'border-emerald-200 bg-emerald-50/30' : 'border-slate-200'}`}>
              <button onClick={() => toggle(i)} className="flex-shrink-0 mt-0.5">
                {done
                  ? <CheckCircle2 size={24} className="text-emerald-500" />
                  : <Circle size={24} className="text-slate-300 hover:text-blue-400 transition" />}
              </button>
              <div className="flex-1">
                <div className={`font-bold text-sm ${done ? 'text-emerald-900' : 'text-slate-800'}`}>{task}</div>
                <div className="text-xs text-slate-600 mt-1 leading-relaxed">{detail}</div>
              </div>
            </div>
          );
        })}
      </div>

      <div className="mt-6 p-5 rounded-2xl border-l-4" style={{ background: 'var(--status-info-bg)', borderColor: GOLD }}>
        <div className="flex gap-3">
          <Lightbulb size={20} style={{ color: GOLD }} className="flex-shrink-0 mt-0.5" />
          <div>
            <div className="font-bold text-blue-900 mb-1 text-sm uppercase tracking-wider">ProAdvisor Note</div>
            <div className="text-blue-900 text-sm leading-relaxed">
              {taxYear === '2026' ? (
                <>Under the One Big Beautiful Bill Act (OBBBA, signed July 2025), the 1099-NEC and 1099-MISC reporting threshold jumped from $600 to <strong>$2,000</strong> for payments made on or after January 1, 2026. Critical reminder: still collect W-9s from every vendor at onboarding. The filing threshold changed — the documentation discipline did not. Penalties for late filings start at $60 per form. Form 1099-K is unrelated — it returned to $20,000 AND 200 transactions.</>
              ) : (
                <>For TY 2025, the legacy $600 threshold still applies — file 1099-NEC for every non-corporate contractor paid $600 or more during the calendar year. The new $2,000 threshold doesn't kick in until 2026 payments. Penalties for late 1099 filings start at $60 per form and can rise to $310+ per form for intentional disregard.</>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

