// COMPONENT: EMAIL TEMPLATES GENERATOR
// ═══════════════════════════════════════════════════════════════════

// EMAIL_TEMPLATES now lives in src/data/email-templates.js (lazy-loaded — see useLazyData).

function EmailTemplates(props) {
  const { mod, err } = useLazyData(loadEmailTemplatesData);
  if (!mod) return <DataLoadingCard err={err} />;
  return <EmailTemplatesInner {...props} data={mod} />;
}
function EmailTemplatesInner({ data }) {
  const { EMAIL_TEMPLATES } = data;
  const [selected, setSelected] = useState(EMAIL_TEMPLATES[0].id);
  const [fieldValues, setFieldValues] = useState({});
  const [generated, setGenerated] = useState('');
  const [busy, setBusy] = useState(false);

  const tpl = EMAIL_TEMPLATES.find(t => t.id === selected);

  const updateField = (idx, value) => {
    setFieldValues(v => ({ ...v, [`${selected}_${idx}`]: value }));
  };

  const generate = async () => {
    setBusy(true);
    setGenerated('');
    try {
      const filledFields = tpl.fields.map((f, idx) => `- ${f}: ${fieldValues[`${selected}_${idx}`] || '[not provided]'}`).join('\n');

      const sys = `You are a 15-year QuickBooks ProAdvisor and US accountant who writes professional emails for remote bookkeepers serving US small business clients. Use clear, warm, confident language. Never use corporate clichés like "I hope this finds you well," "Just touching base," "Per my last email," etc. Be direct, specific, and respectful. American English. Include a subject line.`;

      const user = `Generate the following email:

TEMPLATE: ${tpl.label}
PURPOSE: ${tpl.desc}

CONTEXT FIELDS:
${filledFields}

INSTRUCTIONS: ${tpl.prompt}

Output format:
Subject: [subject line]

[email body]

Best regards,
[Your name]

Do not add any preamble or commentary. Output ONLY the email.`;

      const text = (await callClaude({ max_tokens: 1500, system: sys, messages: [{ role: 'user', content: user }] })).trim();
      setGenerated(text);
    } catch (e) {
      setGenerated('Error generating — please try again.');
    }
    setBusy(false);
  };

  const copy = () => navigator.clipboard.writeText(generated);

  return (
    <div>
      <SectionHead eyebrow="Tool 10" title="Email Templates Generator" desc="12 professional email templates for every situation a remote bookkeeper faces — financial statement delivery, collections, W-9 requests, salary raises, onboarding, and more." />

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mt-6">
        {/* Left: template list */}
        <div className="lg:col-span-1">
          <div style={{ background: SHEEN }} className="glass-card p-3 rounded-2xl">
            <div className="text-xs uppercase tracking-[0.2em] font-bold text-slate-600 px-3 py-2">Choose Template</div>
            <div className="space-y-1 max-h-[640px] overflow-y-auto">
              {EMAIL_TEMPLATES.map(t => (
                <button key={t.id} onClick={() => { setSelected(t.id); setGenerated(''); }}
                  className={`w-full text-left p-3 rounded-xl transition flex items-start gap-3 ${
                    selected === t.id ? 'text-white shadow-md' : 'bg-white hover:bg-blue-50 border border-transparent hover:border-blue-200'
                  }`}
                  style={selected === t.id ? { background: `linear-gradient(135deg, ${ROYAL} 0%, ${CYAN} 100%)` } : {}}>
                  <div className="text-xl flex-shrink-0">{t.icon}</div>
                  <div className="min-w-0">
                    <div className={`font-bold text-sm ${selected === t.id ? 'text-white' : 'text-slate-800'}`}>{t.label}</div>
                    <div className={`text-xs mt-0.5 ${selected === t.id ? 'text-blue-100' : 'text-slate-500'} leading-snug`}>{t.desc}</div>
                  </div>
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Right: form + output */}
        <div className="lg:col-span-2 space-y-6">
          <div style={{ background: SHEEN }} className="glass-card p-7 rounded-2xl">
            <div className="flex items-start gap-3 mb-5">
              <div className="text-3xl">{tpl.icon}</div>
              <div>
                <div style={{ color: NAVY, fontFamily: fontDisplay, letterSpacing: '-0.02em' }} className="text-2xl font-bold">{tpl.label}</div>
                <div className="text-sm text-slate-500">{tpl.desc}</div>
              </div>
            </div>

            <div className="space-y-3 mb-5">
              {tpl.fields.map((f, idx) => (
                <div key={idx}>
                  <label className="text-xs uppercase tracking-wider font-bold text-slate-600 block mb-1.5">{f}</label>
                  {f.toLowerCase().includes('list') ? (
                    <textarea value={fieldValues[`${selected}_${idx}`] || ''} onChange={e => updateField(idx, e.target.value)}
                      placeholder={`Enter ${f.toLowerCase()}`}
                      className="w-full h-24 px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm focus:border-blue-500 outline-none resize-none" />
                  ) : (
                    <input value={fieldValues[`${selected}_${idx}`] || ''} onChange={e => updateField(idx, e.target.value)}
                      placeholder={`Enter ${f.toLowerCase()}`}
                      className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm focus:border-blue-500 outline-none" />
                  )}
                </div>
              ))}
            </div>

            <button onClick={generate} disabled={busy}
              className="sheen-btn w-full text-white font-bold py-3 rounded-xl shadow-lg text-sm tracking-wide flex items-center justify-center gap-2 disabled:opacity-60">
              {busy ? <><Loader2 size={16} className="animate-spin" /> Drafting email...</> : <><Sparkles size={16} /> Generate Email</>}
            </button>
          </div>

          {generated && (
            <div className="fade-in">
              <div className="flex justify-between items-center mb-3">
                <div style={{ color: NAVY, fontFamily: fontDisplay }} className="text-lg font-bold">Generated Email</div>
                <button onClick={copy} className="flex items-center gap-2 px-4 py-2 rounded-xl bg-white border border-slate-300 hover:border-blue-400 transition text-sm font-semibold text-slate-700 shadow-sm">
                  📋 Copy to Clipboard
                </button>
              </div>
              <div className="glossy-card rounded-2xl p-7 border border-slate-200">
                <div className="whitespace-pre-wrap text-slate-800 text-sm leading-relaxed" style={{ fontFamily: fontBody }}>{generated}</div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

