// COMPONENT: MONTH-END CHECKLIST
// ═══════════════════════════════════════════════════════════════════

// MONTH_END_CHECKLIST now lives in src/data/workflows.js (lazy-loaded — see useLazyData).

function MonthEndChecklist(props) {
  const { mod, err } = useLazyData(loadWorkflowsData);
  if (!mod) return <DataLoadingCard err={err} />;
  return <MonthEndChecklistInner {...props} data={mod} />;
}
function MonthEndChecklistInner({ data }) {
  const { MONTH_END_CHECKLIST } = data;
  const [checked, setChecked] = useState(new Set());
  const [loaded, setLoaded] = useState(false);
  // Persist per-user so a multi-day close survives a refresh (keep-alive only covers tab switches).
  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        if (typeof window !== 'undefined' && window.storage) {
          const { value } = await window.storage.get('monthend:checked');
          if (!cancelled && value) { const arr = JSON.parse(value); if (Array.isArray(arr)) setChecked(new Set(arr)); }
        }
      } catch { /* ignore */ }
      if (!cancelled) setLoaded(true);
    })();
    return () => { cancelled = true; };
  }, []);
  useEffect(() => {
    if (!loaded) return;
    if (typeof window !== 'undefined' && window.storage) {
      window.storage.set('monthend:checked', JSON.stringify(Array.from(checked))).catch(() => {});
    }
  }, [checked, loaded]);
  const totalItems = MONTH_END_CHECKLIST.reduce((sum, s) => sum + s.items.length, 0);
  const progress = Math.round((checked.size / totalItems) * 100);

  const toggle = (key) => {
    const next = new Set(checked);
    next.has(key) ? next.delete(key) : next.add(key);
    setChecked(next);
  };

  const resetAll = () => setChecked(new Set());

  return (
    <div>
      <SectionHead eyebrow="Daily & Month-End · Tool" title="Month-End Close Checklist" desc="The complete close checklist — every account, every reconciliation, every step. Run this every month and you will never have a surprise journal entry in December." />

      <div style={{ background: SHEEN }} className="glass-card p-5 rounded-2xl mt-6 mb-5">
        <div className="flex items-center justify-between mb-2">
          <div>
            <div className="text-xs uppercase tracking-[0.2em] font-bold text-slate-600">Close Progress</div>
            <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-2xl font-bold">{checked.size} of {totalItems} complete</div>
          </div>
          <div className="flex items-center gap-3">
            <div className="text-right">
              <div style={{ color: ROYAL, fontFamily: fontDisplay }} className="text-3xl font-bold">{progress}%</div>
              <div className="text-[10px] text-slate-500 uppercase tracking-wider">{progress === 100 ? '✓ Books closed' : 'In progress'}</div>
            </div>
            {checked.size > 0 && (
              <button onClick={resetAll} className="text-xs font-bold px-3 py-2 rounded-lg bg-white border border-slate-300 hover:border-blue-400 text-slate-700">
                Reset
              </button>
            )}
          </div>
        </div>
        <div className="w-full h-2 bg-slate-200 rounded-full overflow-hidden">
          <div className="h-full transition-all duration-500" style={{ width: `${progress}%`, background: `linear-gradient(90deg, ${ROYAL}, ${CYAN}, ${SKY})` }} />
        </div>
      </div>

      <div className="space-y-3">
        {MONTH_END_CHECKLIST.map((sec, si) => {
          const sectionChecked = sec.items.filter((_, i) => checked.has(`${si}-${i}`)).length;
          const sectionTotal = sec.items.length;
          const sectionComplete = sectionChecked === sectionTotal;
          return (
            <div key={si} className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
              <div style={{ background: sectionComplete ? `linear-gradient(90deg, ${ROYAL} 0%, ${CYAN} 100%)` : `linear-gradient(90deg, ${INK.navy} 0%, #1A3568 100%)` }}
                className="px-5 py-3 text-white flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="text-2xl">{sec.icon}</div>
                  <div style={{ fontFamily: fontDisplay }} className="text-base font-bold">{sec.section}</div>
                </div>
                <div className="text-xs font-bold">{sectionChecked} / {sectionTotal}</div>
              </div>
              <div className="p-3 space-y-1">
                {sec.items.map((item, i) => {
                  const key = `${si}-${i}`;
                  const isChecked = checked.has(key);
                  return (
                    <button key={i} onClick={() => toggle(key)}
                      className={`w-full flex items-start gap-3 p-3 rounded-lg text-left transition ${isChecked ? 'bg-blue-50' : 'hover:bg-slate-50'}`}>
                      {isChecked
                        ? <CheckCircle2 size={18} style={{ color: ROYAL }} className="flex-shrink-0 mt-0.5" />
                        : <Circle size={18} className="text-slate-300 flex-shrink-0 mt-0.5" />}
                      <span className={`text-sm leading-snug ${isChecked ? 'text-slate-500 line-through' : 'text-slate-800'}`}>{item}</span>
                    </button>
                  );
                })}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

