// COMPONENT: INVOICE CREATOR (Client Onboarding)
// ═══════════════════════════════════════════════════════════════════

function InvoiceCreator() {
  const today = new Date();
  const fmt = (d) => d.toISOString().slice(0, 10);
  const due = new Date(today.getTime() + 14 * 24 * 60 * 60 * 1000);

  const [from, setFrom] = useState({
    name: 'Maria Cruz',
    business: 'Cruz Bookkeeping Services',
    email: 'maria@cruzbookkeeping.com',
    phone: '+63 917 123 4567',
    address: 'Manila, Philippines',
    paymentInfo: 'Wise: maria@cruzbookkeeping.com\nPayPal: maria@cruzbookkeeping.com\nUSD ACH: Routing 000000 / Acct 000000',
  });

  const [client, setClient] = useState({
    name: '',
    business: '',
    email: '',
    address: '',
  });

  const [meta, setMeta] = useState({
    number: `INV-${today.getFullYear()}${String(today.getMonth() + 1).padStart(2, '0')}-001`,
    date: fmt(today),
    dueDate: fmt(due),
    notes: 'Thank you for your business. Please send payment via the methods listed below.',
  });

  const [services, setServices] = useState([
    { id: 1, description: 'Monthly Bookkeeping Retainer — May 2026', quantity: 1, rate: 1500 },
  ]);

  const [timesheet, setTimesheet] = useState([
    { id: 1, date: fmt(today), description: 'Bank reconciliation — Operating account', hours: 2.5, rate: 35 },
    { id: 2, date: fmt(today), description: 'A/R aging review + collections emails', hours: 1.5, rate: 35 },
    { id: 3, date: fmt(today), description: 'Monthly close + financial statements', hours: 3, rate: 35 },
  ]);

  const [showTimesheet, setShowTimesheet] = useState(true);
  const [taxRate, setTaxRate] = useState(0);
  const [currency, setCurrency] = useState('USD');

  const currencySymbol = { USD: '$', PHP: '₱', EUR: '€', GBP: '£', AUD: 'A$', CAD: 'C$' }[currency] || '$';

  const addService = () => {
    const newId = Math.max(0, ...services.map(s => s.id)) + 1;
    setServices([...services, { id: newId, description: '', quantity: 1, rate: 0 }]);
  };
  const removeService = (id) => setServices(services.filter(s => s.id !== id));
  const updateService = (id, field, value) => {
    setServices(services.map(s => s.id === id ? { ...s, [field]: field === 'description' ? value : Number(value) } : s));
  };

  const addTime = () => {
    const newId = Math.max(0, ...timesheet.map(t => t.id)) + 1;
    setTimesheet([...timesheet, { id: newId, date: fmt(today), description: '', hours: 0, rate: 35 }]);
  };
  const removeTime = (id) => setTimesheet(timesheet.filter(t => t.id !== id));
  const updateTime = (id, field, value) => {
    setTimesheet(timesheet.map(t => t.id === id
      ? { ...t, [field]: (field === 'date' || field === 'description') ? value : Number(value) }
      : t));
  };

  const servicesSubtotal = services.reduce((sum, s) => sum + s.quantity * s.rate, 0);
  const timesheetSubtotal = showTimesheet ? timesheet.reduce((sum, t) => sum + t.hours * t.rate, 0) : 0;
  const subtotal = servicesSubtotal + timesheetSubtotal;
  const taxAmount = subtotal * (taxRate / 100);
  const total = subtotal + taxAmount;
  const totalHours = timesheet.reduce((sum, t) => sum + t.hours, 0);

  const formatCurrency = (n) => `${currencySymbol}${n.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;

  const downloadInvoice = () => {
    const esc = (s) => String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
    const html = `<!DOCTYPE html>
<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:w="urn:schemas-microsoft-com:office:word">
<head><meta charset="utf-8"><title>Invoice ${esc(meta.number)}</title>
<style>
@page { size: Letter; margin: 0.6in; }
body { font-family: 'Segoe UI', Arial, sans-serif; font-size: 11pt; color: #1A2540; line-height: 1.5; }
.header { display: table; width: 100%; margin-bottom: 24pt; }
.header-left, .header-right { display: table-cell; vertical-align: top; }
.header-right { text-align: right; }
.brand-name { font-size: 18pt; font-weight: bold; color: #0A1E3F; margin-bottom: 4pt; }
.brand-sub { font-size: 9pt; color: #64748b; }
.invoice-label { font-size: 28pt; font-weight: bold; color: #1E40AF; letter-spacing: -0.5pt; }
.invoice-num { font-size: 10pt; color: #64748b; margin-top: 2pt; }
.parties { display: table; width: 100%; margin-bottom: 18pt; }
.from, .bill-to { display: table-cell; vertical-align: top; width: 50%; padding-right: 12pt; }
.label { font-size: 8pt; text-transform: uppercase; letter-spacing: 1pt; color: #1E40AF; font-weight: bold; margin-bottom: 4pt; }
.party-name { font-weight: bold; font-size: 12pt; color: #0A1E3F; }
.meta { display: table; width: 100%; margin-bottom: 16pt; background: #F0F9FF; padding: 10pt; border-radius: 6pt; }
.meta-cell { display: table-cell; padding: 0 8pt; vertical-align: top; }
table.items { width: 100%; border-collapse: collapse; margin-bottom: 16pt; }
table.items th { background: #0A1E3F; color: white; padding: 8pt; text-align: left; font-size: 9pt; text-transform: uppercase; letter-spacing: 0.5pt; }
table.items td { padding: 8pt; border-bottom: 1pt solid #E5E7EB; font-size: 10pt; }
table.items .num { text-align: right; }
.section-header { background: #1E40AF; color: white; padding: 6pt 8pt; font-weight: bold; font-size: 10pt; text-transform: uppercase; letter-spacing: 1pt; }
.totals { float: right; width: 280pt; margin-top: 10pt; }
.totals-row { display: table; width: 100%; padding: 4pt 0; }
.totals-label { display: table-cell; text-align: right; padding-right: 16pt; font-size: 10pt; }
.totals-value { display: table-cell; text-align: right; width: 100pt; font-weight: bold; font-size: 10pt; }
.totals-grand { background: #0A1E3F; color: white; padding: 10pt 16pt; font-size: 14pt; font-weight: bold; margin-top: 4pt; }
.notes { clear: both; margin-top: 30pt; padding-top: 12pt; border-top: 2pt solid #1E40AF; }
.payment-info { background: #F0F9FF; padding: 12pt; margin-top: 10pt; border-radius: 6pt; font-size: 10pt; white-space: pre-line; }
.footer { margin-top: 30pt; padding-top: 12pt; border-top: 1pt solid #E5E7EB; text-align: center; font-size: 9pt; color: #94A3B8; }
</style></head>
<body>
<div class="header">
  <div class="header-left">
    <div class="brand-name">${esc(from.business)}</div>
    <div class="brand-sub">${esc(from.name)}<br>${esc(from.email)}<br>${esc(from.phone)}<br>${esc(from.address)}</div>
  </div>
  <div class="header-right">
    <div class="invoice-label">INVOICE</div>
    <div class="invoice-num">${esc(meta.number)}</div>
  </div>
</div>

<div class="meta">
  <div class="meta-cell"><div class="label">Issue Date</div><div>${esc(meta.date)}</div></div>
  <div class="meta-cell"><div class="label">Due Date</div><div>${esc(meta.dueDate)}</div></div>
  <div class="meta-cell"><div class="label">Currency</div><div>${esc(currency)}</div></div>
  <div class="meta-cell"><div class="label">Amount Due</div><div style="font-weight:bold; color:#1E40AF;">${formatCurrency(total)}</div></div>
</div>

<div class="parties">
  <div class="from">
    <div class="label">From</div>
    <div class="party-name">${esc(from.business)}</div>
    <div>${esc(from.name)}<br>${esc(from.email)}<br>${esc(from.address)}</div>
  </div>
  <div class="bill-to">
    <div class="label">Bill To</div>
    <div class="party-name">${esc(client.business || client.name || 'Client')}</div>
    <div>${esc(client.name)}<br>${esc(client.email)}<br>${esc(client.address).replace(/\n/g, '<br>')}</div>
  </div>
</div>

${services.length > 0 && servicesSubtotal > 0 ? `
<div class="section-header">Fixed-Fee Services</div>
<table class="items">
  <thead><tr><th style="width:55%;">Description</th><th class="num" style="width:10%;">Qty</th><th class="num" style="width:17%;">Rate</th><th class="num" style="width:18%;">Amount</th></tr></thead>
  <tbody>
  ${services.map(s => `<tr><td>${esc(s.description)}</td><td class="num">${s.quantity}</td><td class="num">${formatCurrency(s.rate)}</td><td class="num">${formatCurrency(s.quantity * s.rate)}</td></tr>`).join('')}
  </tbody>
</table>
` : ''}

${showTimesheet && timesheet.length > 0 && timesheetSubtotal > 0 ? `
<div class="section-header">Hourly Work · Timesheet</div>
<table class="items">
  <thead><tr><th style="width:14%;">Date</th><th style="width:46%;">Description</th><th class="num" style="width:10%;">Hours</th><th class="num" style="width:14%;">Rate</th><th class="num" style="width:16%;">Amount</th></tr></thead>
  <tbody>
  ${timesheet.map(t => `<tr><td>${esc(t.date)}</td><td>${esc(t.description)}</td><td class="num">${t.hours.toFixed(2)}</td><td class="num">${formatCurrency(t.rate)}</td><td class="num">${formatCurrency(t.hours * t.rate)}</td></tr>`).join('')}
  </tbody>
  <tfoot><tr><td colspan="2" style="font-weight:bold; padding-top:6pt;">Total Hours</td><td class="num" style="font-weight:bold; padding-top:6pt;">${totalHours.toFixed(2)}</td><td class="num" style="padding-top:6pt;">—</td><td class="num" style="font-weight:bold; padding-top:6pt;">${formatCurrency(timesheetSubtotal)}</td></tr></tfoot>
</table>
` : ''}

<div class="totals">
  <div class="totals-row"><div class="totals-label">Subtotal</div><div class="totals-value">${formatCurrency(subtotal)}</div></div>
  ${taxRate > 0 ? `<div class="totals-row"><div class="totals-label">Tax (${taxRate}%)</div><div class="totals-value">${formatCurrency(taxAmount)}</div></div>` : ''}
  <div class="totals-grand">TOTAL DUE: ${formatCurrency(total)}</div>
</div>

<div class="notes">
  <div class="label">Notes</div>
  <div>${esc(meta.notes).replace(/\n/g, '<br>')}</div>
  <div class="payment-info">
    <strong>Payment Information</strong><br>
    ${esc(from.paymentInfo)}
  </div>
</div>

<div class="footer">
  Invoice generated via Get Hired With Alex · US Bookkeeper Ultimate Tool Kits
</div>

</body></html>`;
    const blob = new Blob(['\ufeff', html], { type: 'application/msword' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `Invoice_${meta.number}_${(client.business || client.name || 'Client').replace(/[^a-zA-Z0-9]/g, '_')}.doc`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  const printInvoice = () => {
    window.print();
  };

  return (
    <div>
      <SectionHead eyebrow="Client Onboarding · Tool" title="Invoice Creator with Timesheet" desc="Send branded, professional invoices to your US clients — combining fixed-fee retainers with detailed hourly timesheet entries. Export to Word/PDF or print directly. Builds trust and gets you paid on time." />

      <div style={{ background: SHEEN }} className="glass-card p-5 rounded-2xl mt-6 mb-5">
        <div className="flex gap-3 items-start">
          <Lightbulb size={20} style={{ color: ROYAL }} className="flex-shrink-0 mt-0.5" />
          <div className="text-sm text-slate-700 leading-relaxed">
            <span className="font-bold" style={{ color: NAVY }}>Why this matters:</span> A clean, itemized invoice is a trust signal. Clients pay faster when they can see exactly what they're paying for — fixed-fee retainer line items + hourly timesheet entries with dates and descriptions. Send via email with a Wise/PayPal/ACH link and you collect in 5-10 days instead of 30+.
          </div>
        </div>
      </div>

      {/* Configuration grid */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 mb-5">
        {/* From */}
        <div style={{ background: SHEEN }} className="glass-card p-5 rounded-2xl">
          <div className="text-[10px] uppercase tracking-[0.2em] font-bold mb-3" style={{ color: ROYAL }}>👤 From (You)</div>
          <div className="space-y-2">
            <input className="w-full px-3 py-2 rounded-lg border border-slate-300 text-sm bg-white" placeholder="Your name" value={from.name} onChange={e => setFrom({ ...from, name: e.target.value })} />
            <input className="w-full px-3 py-2 rounded-lg border border-slate-300 text-sm bg-white" placeholder="Business name" value={from.business} onChange={e => setFrom({ ...from, business: e.target.value })} />
            <input className="w-full px-3 py-2 rounded-lg border border-slate-300 text-sm bg-white" placeholder="Email" value={from.email} onChange={e => setFrom({ ...from, email: e.target.value })} />
            <input className="w-full px-3 py-2 rounded-lg border border-slate-300 text-sm bg-white" placeholder="Phone" value={from.phone} onChange={e => setFrom({ ...from, phone: e.target.value })} />
            <input className="w-full px-3 py-2 rounded-lg border border-slate-300 text-sm bg-white" placeholder="Address" value={from.address} onChange={e => setFrom({ ...from, address: e.target.value })} />
            <textarea className="w-full px-3 py-2 rounded-lg border border-slate-300 text-sm bg-white" rows="3" placeholder="Payment info (Wise, PayPal, ACH...)" value={from.paymentInfo} onChange={e => setFrom({ ...from, paymentInfo: e.target.value })} />
          </div>
        </div>

        {/* Bill To */}
        <div style={{ background: SHEEN }} className="glass-card p-5 rounded-2xl">
          <div className="text-[10px] uppercase tracking-[0.2em] font-bold mb-3" style={{ color: ROYAL }}>🏢 Bill To (Client)</div>
          <div className="space-y-2">
            <input className="w-full px-3 py-2 rounded-lg border border-slate-300 text-sm bg-white" placeholder="Contact name" value={client.name} onChange={e => setClient({ ...client, name: e.target.value })} />
            <input className="w-full px-3 py-2 rounded-lg border border-slate-300 text-sm bg-white" placeholder="Client business name" value={client.business} onChange={e => setClient({ ...client, business: e.target.value })} />
            <input className="w-full px-3 py-2 rounded-lg border border-slate-300 text-sm bg-white" placeholder="Client email" value={client.email} onChange={e => setClient({ ...client, email: e.target.value })} />
            <textarea className="w-full px-3 py-2 rounded-lg border border-slate-300 text-sm bg-white" rows="3" placeholder="Client billing address" value={client.address} onChange={e => setClient({ ...client, address: e.target.value })} />
          </div>
        </div>
      </div>

      {/* Meta */}
      <div style={{ background: SHEEN }} className="glass-card p-5 rounded-2xl mb-5">
        <div className="text-[10px] uppercase tracking-[0.2em] font-bold mb-3" style={{ color: ROYAL }}>📋 Invoice Details</div>
        <div className="grid grid-cols-2 md:grid-cols-5 gap-2">
          <div>
            <label className="text-[10px] text-slate-500 block mb-1">Invoice #</label>
            <input className="w-full px-3 py-2 rounded-lg border border-slate-300 text-sm bg-white" value={meta.number} onChange={e => setMeta({ ...meta, number: e.target.value })} />
          </div>
          <div>
            <label className="text-[10px] text-slate-500 block mb-1">Issue Date</label>
            <input type="date" className="w-full px-3 py-2 rounded-lg border border-slate-300 text-sm bg-white" value={meta.date} onChange={e => setMeta({ ...meta, date: e.target.value })} />
          </div>
          <div>
            <label className="text-[10px] text-slate-500 block mb-1">Due Date</label>
            <input type="date" className="w-full px-3 py-2 rounded-lg border border-slate-300 text-sm bg-white" value={meta.dueDate} onChange={e => setMeta({ ...meta, dueDate: e.target.value })} />
          </div>
          <div>
            <label className="text-[10px] text-slate-500 block mb-1">Currency</label>
            <select className="w-full px-3 py-2 rounded-lg border border-slate-300 text-sm bg-white" value={currency} onChange={e => setCurrency(e.target.value)}>
              <option value="USD">USD ($)</option>
              <option value="PHP">PHP (₱)</option>
              <option value="EUR">EUR (€)</option>
              <option value="GBP">GBP (£)</option>
              <option value="AUD">AUD (A$)</option>
              <option value="CAD">CAD (C$)</option>
            </select>
          </div>
          <div>
            <label className="text-[10px] text-slate-500 block mb-1">Tax %</label>
            <input type="number" min="0" step="0.5" className="w-full px-3 py-2 rounded-lg border border-slate-300 text-sm bg-white" value={taxRate} onChange={e => setTaxRate(Number(e.target.value))} />
          </div>
        </div>
        <div className="mt-3">
          <label className="text-[10px] text-slate-500 block mb-1">Notes / Payment Terms</label>
          <textarea className="w-full px-3 py-2 rounded-lg border border-slate-300 text-sm bg-white" rows="2" value={meta.notes} onChange={e => setMeta({ ...meta, notes: e.target.value })} />
        </div>
      </div>

      {/* Fixed-fee services */}
      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden mb-4">
        <div style={{ background: `linear-gradient(90deg, ${INK.navy} 0%, ${ROYAL} 100%)` }} className="px-5 py-3 text-white flex items-center justify-between">
          <div style={{ fontFamily: fontDisplay }} className="text-base font-bold">💼 Fixed-Fee Services / Retainer</div>
          <button onClick={addService} className="text-xs font-bold px-3 py-1.5 rounded-lg bg-white/20 hover:bg-white/30 transition">+ Add Line</button>
        </div>
        <div className="p-3">
          {services.map((s) => (
            <div key={s.id} className="grid grid-cols-12 gap-2 mb-2 items-center">
              <input className="col-span-7 px-3 py-2 rounded-lg border border-slate-200 text-sm" placeholder="Service description (e.g., Monthly Bookkeeping Retainer — May 2026)" value={s.description} onChange={e => updateService(s.id, 'description', e.target.value)} />
              <input type="number" min="0" step="0.5" className="col-span-1 px-2 py-2 rounded-lg border border-slate-200 text-sm text-right" placeholder="Qty" value={s.quantity} onChange={e => updateService(s.id, 'quantity', e.target.value)} />
              <input type="number" min="0" step="50" className="col-span-2 px-2 py-2 rounded-lg border border-slate-200 text-sm text-right" placeholder="Rate" value={s.rate} onChange={e => updateService(s.id, 'rate', e.target.value)} />
              <div className="col-span-1 text-right text-sm font-bold" style={{ color: NAVY }}>{formatCurrency(s.quantity * s.rate)}</div>
              <button onClick={() => removeService(s.id)} className="col-span-1 text-red-400 hover:text-red-600 text-sm">✕</button>
            </div>
          ))}
          <div className="mt-2 pt-2 border-t border-slate-100 flex justify-between items-center text-sm">
            <span className="text-slate-500 font-semibold">Services Subtotal</span>
            <span className="font-bold" style={{ color: NAVY }}>{formatCurrency(servicesSubtotal)}</span>
          </div>
        </div>
      </div>

      {/* Timesheet */}
      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden mb-4">
        <div style={{ background: `linear-gradient(90deg, ${ROYAL} 0%, ${CYAN} 100%)` }} className="px-5 py-3 text-white flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div style={{ fontFamily: fontDisplay }} className="text-base font-bold">⏱️ Hourly Timesheet</div>
            <label className="flex items-center gap-1.5 cursor-pointer text-xs">
              <input type="checkbox" checked={showTimesheet} onChange={e => setShowTimesheet(e.target.checked)} className="w-3.5 h-3.5" />
              <span>Include on invoice</span>
            </label>
          </div>
          {showTimesheet && <button onClick={addTime} className="text-xs font-bold px-3 py-1.5 rounded-lg bg-white/20 hover:bg-white/30 transition">+ Add Entry</button>}
        </div>
        {showTimesheet && (
          <div className="p-3">
            <div className="grid grid-cols-12 gap-2 mb-2 text-[10px] uppercase tracking-wider font-bold text-slate-500 px-1">
              <div className="col-span-2">Date</div>
              <div className="col-span-5">Description of Work</div>
              <div className="col-span-1 text-right">Hours</div>
              <div className="col-span-2 text-right">Rate</div>
              <div className="col-span-1 text-right">Amount</div>
              <div className="col-span-1"></div>
            </div>
            {timesheet.map((t) => (
              <div key={t.id} className="grid grid-cols-12 gap-2 mb-2 items-center">
                <input type="date" className="col-span-2 px-2 py-2 rounded-lg border border-slate-200 text-xs" value={t.date} onChange={e => updateTime(t.id, 'date', e.target.value)} />
                <input className="col-span-5 px-3 py-2 rounded-lg border border-slate-200 text-sm" placeholder="What you did (e.g., Bank reconciliation — Operating account)" value={t.description} onChange={e => updateTime(t.id, 'description', e.target.value)} />
                <input type="number" min="0" step="0.25" className="col-span-1 px-2 py-2 rounded-lg border border-slate-200 text-sm text-right" placeholder="Hrs" value={t.hours} onChange={e => updateTime(t.id, 'hours', e.target.value)} />
                <input type="number" min="0" step="5" className="col-span-2 px-2 py-2 rounded-lg border border-slate-200 text-sm text-right" placeholder="Rate" value={t.rate} onChange={e => updateTime(t.id, 'rate', e.target.value)} />
                <div className="col-span-1 text-right text-sm font-bold" style={{ color: NAVY }}>{formatCurrency(t.hours * t.rate)}</div>
                <button onClick={() => removeTime(t.id)} className="col-span-1 text-red-400 hover:text-red-600 text-sm">✕</button>
              </div>
            ))}
            <div className="mt-2 pt-2 border-t border-slate-100 flex justify-between items-center text-sm">
              <span className="text-slate-500 font-semibold">Total Hours: <span className="font-bold" style={{ color: NAVY }}>{totalHours.toFixed(2)}</span></span>
              <span className="font-bold" style={{ color: NAVY }}>Timesheet Subtotal: {formatCurrency(timesheetSubtotal)}</span>
            </div>
          </div>
        )}
      </div>

      {/* Live preview / totals */}
      <div className="bg-white rounded-2xl border-2 shadow-lg overflow-hidden mb-5" style={{ borderColor: CYAN }}>
        <div style={{ background: `linear-gradient(90deg, ${INK.navy} 0%, ${ROYAL} 100%)` }} className="px-6 py-3 text-white">
          <div style={{ fontFamily: fontDisplay }} className="text-base font-bold">📄 Invoice Preview</div>
        </div>
        <div className="p-6">
          <div className="flex justify-between items-start mb-6 pb-4 border-b-2" style={{ borderColor: ROYAL }}>
            <div>
              <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-xl font-bold">{from.business}</div>
              <div className="text-xs text-slate-600 mt-1 whitespace-pre-line">{from.name}<br />{from.email}<br />{from.phone}</div>
            </div>
            <div className="text-right">
              <div style={{ color: ROYAL, fontFamily: fontDisplay }} className="text-3xl font-bold tracking-tight">INVOICE</div>
              <div className="text-xs text-slate-500 mt-1">{meta.number}</div>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4 mb-4 text-sm">
            <div>
              <div className="text-[10px] uppercase tracking-wider font-bold mb-1" style={{ color: ROYAL }}>Bill To</div>
              <div className="font-bold" style={{ color: NAVY }}>{client.business || client.name || 'Client Name'}</div>
              <div className="text-xs text-slate-600 whitespace-pre-line">{client.name}<br />{client.email}<br />{client.address}</div>
            </div>
            <div className="text-right">
              <div className="text-[10px] uppercase tracking-wider font-bold mb-1" style={{ color: ROYAL }}>Amount Due</div>
              <div style={{ color: NAVY, fontFamily: fontDisplay }} className="text-3xl font-bold">{formatCurrency(total)}</div>
              <div className="text-xs text-slate-500 mt-1">Due: {meta.dueDate}</div>
            </div>
          </div>

          <div className="bg-slate-50 rounded-lg p-3 grid grid-cols-2 gap-2 text-sm mb-3">
            <div className="flex justify-between"><span className="text-slate-600">Services Subtotal</span><span className="font-semibold">{formatCurrency(servicesSubtotal)}</span></div>
            {showTimesheet && <div className="flex justify-between"><span className="text-slate-600">Timesheet ({totalHours.toFixed(1)}h)</span><span className="font-semibold">{formatCurrency(timesheetSubtotal)}</span></div>}
            <div className="flex justify-between"><span className="text-slate-600">Subtotal</span><span className="font-semibold">{formatCurrency(subtotal)}</span></div>
            {taxRate > 0 && <div className="flex justify-between"><span className="text-slate-600">Tax ({taxRate}%)</span><span className="font-semibold">{formatCurrency(taxAmount)}</span></div>}
          </div>
          <div className="flex justify-between items-center p-3 rounded-lg text-white" style={{ background: INK.navy }}>
            <span className="text-sm font-bold tracking-wider uppercase">Total Due</span>
            <span style={{ fontFamily: fontDisplay }} className="text-2xl font-bold">{formatCurrency(total)}</span>
          </div>
        </div>
      </div>

      {/* Actions */}
      <div className="flex gap-3 justify-end">
        <button onClick={printInvoice} className="px-5 py-2.5 rounded-xl bg-white border border-slate-300 hover:border-slate-400 text-sm font-bold text-slate-700 transition flex items-center gap-2">
          <Printer size={16} /> Print
        </button>
        <button onClick={downloadInvoice} className="px-5 py-2.5 rounded-xl text-white text-sm font-bold transition flex items-center gap-2 shadow-lg" style={{ background: `linear-gradient(135deg, ${ROYAL} 0%, ${CYAN} 100%)` }}>
          <Download size={16} /> Download Invoice (.doc)
        </button>
      </div>

      {/* Pro Tip */}
      <div className="mt-5 p-4 rounded-xl border-l-4" style={{ background: 'var(--status-info-bg)', borderColor: ROYAL }}>
        <div className="flex gap-3 items-start">
          <Lightbulb size={18} style={{ color: ROYAL }} className="flex-shrink-0 mt-0.5" />
          <div className="text-sm text-slate-700 leading-relaxed">
            <span className="font-bold" style={{ color: NAVY }}>ProAdvisor Tip:</span> Numbering convention: <span className="font-mono text-xs">INV-YYYYMM-XXX</span> (e.g., INV-202605-001). Reset to 001 each month so your bookkeeping mirrors what your clients see. Always send invoices on the same day each month — predictability builds trust and gets you paid faster.
          </div>
        </div>
      </div>
    </div>
  );
}



