// COMPONENT: DIFFICULT CLIENT PLAYBOOK (Client Success & Growth)
// ═══════════════════════════════════════════════════════════════════

// DIFFICULT_SCENARIOS now lives in src/data/difficult-clients.js (lazy-loaded — see useLazyData).

function DifficultClientPlaybook(props) {
  const { mod, err } = useLazyData(loadDifficultClientsData);
  if (!mod) return <DataLoadingCard err={err} />;
  return <DifficultClientPlaybookInner {...props} data={mod} />;
}
function DifficultClientPlaybookInner({ data }) {
  const { DIFFICULT_SCENARIOS } = data;
  const [activeScenario, setActiveScenario] = useState(DIFFICULT_SCENARIOS[0].id);
  const scenario = DIFFICULT_SCENARIOS.find(s => s.id === activeScenario);

  return (
    <div>
      <SectionHead eyebrow="Client Success · Tool" title="Difficult Client Playbook" desc="The 4 most common difficult-client scenarios and how to handle each. For each scenario you get: warning signs, a salvage-vs-fire decision tree, exact steps for both paths, and a ready-to-send email template. Most bookkeepers wait too long to fire bad clients — this playbook gives you permission and language." />

      <div className="grid grid-cols-2 md:grid-cols-4 gap-2 mt-6 mb-5">
        {DIFFICULT_SCENARIOS.map(s => {
          const isActive = activeScenario === s.id;
          return (
            <button key={s.id} onClick={() => setActiveScenario(s.id)}
              className={`p-3 rounded-2xl transition text-left ${isActive ? 'text-white shadow-lg' : 'bg-white border border-slate-200 hover:border-blue-300'}`}
              style={isActive ? { background: `linear-gradient(135deg, ${ROYAL} 0%, ${CYAN} 100%)` } : {}}>
              <div className="text-2xl mb-1">{s.icon}</div>
              <div className={`text-xs font-bold leading-tight ${isActive ? 'text-white' : 'text-slate-800'}`}>{s.title}</div>
            </button>
          );
        })}
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div style={{ background: `linear-gradient(135deg, ${INK.navy} 0%, ${ROYAL} 100%)` }} className="px-6 py-4 text-white flex items-center gap-3">
          <div className="text-3xl">{scenario.icon}</div>
          <div>
            <div style={{ fontFamily: fontDisplay }} className="text-xl font-bold">{scenario.title}</div>
            <div className="text-xs text-blue-200">Warning signs · Decision tree · Action steps · Email template</div>
          </div>
        </div>
        <div className="p-6 space-y-5">
          <div className="p-4 rounded-xl border-l-4 bg-amber-50" style={{ borderColor: '#D97706' }}>
            <div className="text-xs uppercase tracking-wider font-bold mb-2 text-amber-800">🚩 Warning Signs</div>
            <ul className="space-y-1 text-sm text-amber-900">
              {scenario.signs.map((s, i) => (
                <li key={i} className="flex gap-2"><AlertTriangle size={14} className="text-amber-700 flex-shrink-0 mt-0.5" />{s}</li>
              ))}
            </ul>
          </div>

          <div className="p-4 rounded-xl border-l-4" style={{ background: 'var(--status-info-bg)', borderColor: ROYAL }}>
            <div className="text-xs uppercase tracking-wider font-bold mb-2" style={{ color: ROYAL }}>🤔 Salvage vs Fire Decision</div>
            <div className="text-sm text-slate-700">{scenario.decision}</div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="p-4 rounded-xl border border-slate-200 bg-emerald-50">
              <div className="text-xs uppercase tracking-wider font-bold mb-3" style={{ color: 'var(--status-ok-fg)' }}>✅ Salvage Path</div>
              <ol className="space-y-2 text-sm text-emerald-900 list-decimal list-inside">
                {scenario.salvageSteps.map((s, i) => (
                  <li key={i} className="leading-relaxed">{s}</li>
                ))}
              </ol>
            </div>
            <div className="p-4 rounded-xl border border-slate-200 bg-red-50">
              <div className="text-xs uppercase tracking-wider font-bold mb-3" style={{ color: 'var(--status-danger-fg)' }}>🔥 Fire Path</div>
              <ol className="space-y-2 text-sm text-red-900 list-decimal list-inside">
                {scenario.fireSteps.map((s, i) => (
                  <li key={i} className="leading-relaxed">{s}</li>
                ))}
              </ol>
            </div>
          </div>

          <div>
            <div className="text-xs uppercase tracking-wider font-bold mb-2 flex items-center justify-between">
              <span style={{ color: ROYAL }}>📧 Email Template (customize before sending)</span>
              <button onClick={() => navigator.clipboard.writeText(scenario.emailTemplate)} className="text-[10px] font-bold px-2 py-1 rounded bg-slate-100 hover:bg-slate-200 flex items-center gap-1"><Copy size={10} /> Copy</button>
            </div>
            <div className="text-sm text-slate-800 leading-relaxed whitespace-pre-wrap p-5 rounded-lg" style={{ background: ICE, fontFamily: 'ui-monospace, monospace' }}>{scenario.emailTemplate}</div>
          </div>
        </div>
      </div>
    </div>
  );
}



