// COMPONENT: CAPACITY PLANNER (Run Your Practice)
// ═══════════════════════════════════════════════════════════════════

function CapacityPlanner() {
  const [targetHours, setTargetHours] = useState(40);
  const [targetMRR, setTargetMRR] = useState(8000);
  const [clients, setClients] = useState([
    { id: 1, name: 'Sunrise E-Commerce', hours: 8, fee: 1500 },
    { id: 2, name: 'Ramirez Real Estate', hours: 5, fee: 800 },
    { id: 3, name: 'Bright Path Marketing', hours: 12, fee: 2000 },
  ]);
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    (async () => {
      try {
        const c = await window.storage.get('capacity:clients');
        if (c?.value) setClients(JSON.parse(c.value));
        const t = await window.storage.get('capacity:targets');
        if (t?.value) {
          const parsed = JSON.parse(t.value);
          setTargetHours(parsed.hours || 40); setTargetMRR(parsed.mrr || 8000);
        }
      } catch {}
      setLoaded(true);
    })();
  }, []);
  useEffect(() => { if (loaded) window.storage.set('capacity:clients', JSON.stringify(clients)).catch(()=>{}); }, [clients, loaded]);
  useEffect(() => { if (loaded) window.storage.set('capacity:targets', JSON.stringify({ hours: targetHours, mrr: targetMRR })).catch(()=>{}); }, [targetHours, targetMRR, loaded]);

  const addClient = () => {
    const id = Math.max(0, ...clients.map(c => c.id)) + 1;
    setClients([...clients, { id, name: '', hours: 0, fee: 0 }]);
  };
  const updateClient = (id, field, value) => setClients(clients.map(c => c.id === id ? { ...c, [field]: field === 'name' ? value : Number(value) } : c));
  const removeClient = (id) => setClients(clients.filter(c => c.id !== id));

  const totalHours = clients.reduce((s, c) => s + c.hours, 0);
  const totalMRR = clients.reduce((s, c) => s + c.fee, 0);
  const avgRate = totalHours > 0 ? totalMRR / totalHours : 0;
  const hoursUtilization = (totalHours / targetHours) * 100;
  const mrrUtilization = (totalMRR / targetMRR) * 100;
  const remainingHours = Math.max(0, targetHours - totalHours);
  const remainingMRR = Math.max(0, targetMRR - totalMRR);

  // Recommendations
  const recommendations = [];
  if (hoursUtilization >= 100 && mrrUtilization < 100) {
    recommendations.push({ icon: '💰', label: 'At capacity but under MRR target', detail: 'You\'re hitting your hours but not your revenue. Time to RAISE RATES on existing clients (start with lowest-rate clients) or replace your lowest-effective-rate client with a higher-paying one. Don\'t take more clients — you\'ll burn out.', urgency: 'high' });
  }
  if (hoursUtilization >= 90 && hoursUtilization < 100) {
    recommendations.push({ icon: '⚠️', label: 'Near capacity', detail: 'You can take 1 more small client OR consider hiring a sub-bookkeeper. Hiring math: pay a sub $8-15/hr to do 10 hours of work for you, freeing you to take a $1,500/mo client at $300+ effective rate.', urgency: 'medium' });
  }
  if (hoursUtilization >= 100 && mrrUtilization >= 100) {
    recommendations.push({ icon: '🚀', label: 'Hitting both targets', detail: 'Time to SCALE UP. Options: (1) hire a sub-bookkeeper and take 2-3 more clients (2) raise your targets and your rates by 20% (3) build a course/SOPs to productize and exit the hour-trading model.', urgency: 'low' });
  }
  if (hoursUtilization < 70 && mrrUtilization < 70) {
    recommendations.push({ icon: '📈', label: 'Plenty of capacity', detail: `You have ~${Math.round(remainingHours)} hours/week and ~${Math.round(remainingMRR).toLocaleString()} in MRR room. Focus on lead generation — Coach Alex AI, proposal generator, LinkedIn outreach. Target 1 new client this month.`, urgency: 'low' });
  }
  if (avgRate > 0 && avgRate < 50) {
    recommendations.push({ icon: '🔻', label: 'Effective rate below $50/hr', detail: `Your blended effective rate is $${avgRate.toFixed(0)}/hr — you're leaving money on the table. Either raise rates or fire your lowest-rate clients to make room for better ones. The Price Raise Toolkit can help.`, urgency: 'high' });
  }
  if (avgRate >= 100) {
    recommendations.push({ icon: '🌟', label: 'Strong effective rate', detail: `$${avgRate.toFixed(0)}/hr blended — you're operating like a top-tier remote bookkeeper. Keep optimizing for fewer-but-higher-paying clients rather than more clients.`, urgency: 'low' });
  }
  if (clients.some(c => c.hours > 0 && c.fee / c.hours < 30)) {
    recommendations.push({ icon: '🚨', label: 'You have underwater clients', detail: 'At least one client is earning you less than $30/hr effective. That\'s below PH-market for accounting work. Read the Difficult Client Playbook on when to raise their rate vs. fire them.', urgency: 'high' });
  }

  const fmt = (n) => `$${Number(n).toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 })}`;

  return (
    <div>
      <SectionHead eyebrow="Run Your Practice · Tool" title="Capacity Planner" desc="The math that tells you when to take new clients, when to raise rates, and when to hire help. Most Filipino bookkeepers operate on vibes (they 'feel busy' or 'feel slow'). This puts real numbers behind those feelings." />

      {/* Targets */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-3 mt-6 mb-5">
        <div style={{ background: SHEEN }} className="glass-card p-5 rounded-2xl">
          <div className="text-[10px] uppercase tracking-wider font-bold text-slate-500 mb-1">Target Weekly Hours</div>
          <input type="number" className="w-full px-3 py-2 rounded-lg border border-slate-300 text-2xl font-bold" value={targetHours} onChange={e => setTargetHours(Number(e.target.value))} style={{ color: NAVY, fontFamily: fontDisplay }} />
          <div className="text-xs text-slate-500 mt-2">A healthy full-time freelancer targets 32-40 billable hours/week. 40+ is burnout territory long-term.</div>
        </div>
        <div style={{ background: SHEEN }} className="glass-card p-5 rounded-2xl">
          <div className="text-[10px] uppercase tracking-wider font-bold text-slate-500 mb-1">Target Monthly MRR ($)</div>
          <input type="number" className="w-full px-3 py-2 rounded-lg border border-slate-300 text-2xl font-bold" value={targetMRR} onChange={e => setTargetMRR(Number(e.target.value))} style={{ color: NAVY, fontFamily: fontDisplay }} />
          <div className="text-xs text-slate-500 mt-2">Most PH bookkeepers should target $5K-$15K/mo MRR for a comfortable life + savings.</div>
        </div>
      </div>

      {/* Current state cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-3 mb-5">
        <div className="p-5 rounded-2xl bg-white border border-slate-200 shadow-sm">
          <div className="text-[10px] uppercase tracking-wider font-bold text-slate-500">Active Clients</div>
          <div style={{ color: NAVY, fontFamily: fontDisplay }} className="text-3xl font-bold mt-1">{clients.length}</div>
        </div>
        <div className="p-5 rounded-2xl bg-white border border-slate-200 shadow-sm">
          <div className="text-[10px] uppercase tracking-wider font-bold text-slate-500">Weekly Hours</div>
          <div style={{ color: hoursUtilization > 100 ? '#DC2626' : NAVY, fontFamily: fontDisplay }} className="text-3xl font-bold mt-1">{totalHours.toFixed(1)}</div>
          <div className="text-xs text-slate-500 mt-1">{hoursUtilization.toFixed(0)}% of target</div>
          <div className="mt-2 h-2 bg-slate-100 rounded-full overflow-hidden">
            <div className="h-full transition-all" style={{ width: `${Math.min(100, hoursUtilization)}%`, background: hoursUtilization > 100 ? '#DC2626' : hoursUtilization > 90 ? '#F59E0B' : ROYAL }} />
          </div>
        </div>
        <div className="p-5 rounded-2xl bg-white border border-slate-200 shadow-sm">
          <div className="text-[10px] uppercase tracking-wider font-bold text-slate-500">Current MRR</div>
          <div style={{ color: NAVY, fontFamily: fontDisplay }} className="text-3xl font-bold mt-1">{fmt(totalMRR)}</div>
          <div className="text-xs text-slate-500 mt-1">{mrrUtilization.toFixed(0)}% of target</div>
          <div className="mt-2 h-2 bg-slate-100 rounded-full overflow-hidden">
            <div className="h-full transition-all" style={{ width: `${Math.min(100, mrrUtilization)}%`, background: ROYAL }} />
          </div>
        </div>
        <div className="p-5 rounded-2xl text-white shadow-lg" style={{ background: `linear-gradient(135deg, ${ROYAL} 0%, ${CYAN} 100%)` }}>
          <div className="text-[10px] uppercase tracking-wider font-bold opacity-80">Blended Effective Rate</div>
          <div style={{ fontFamily: fontDisplay }} className="text-3xl font-bold mt-1">${avgRate.toFixed(0)}/hr</div>
          <div className="text-xs opacity-80 mt-1">{avgRate >= 100 ? 'Excellent' : avgRate >= 50 ? 'Solid' : avgRate >= 30 ? 'Below market' : 'Critical'}</div>
        </div>
      </div>

      {/* Recommendations */}
      {recommendations.length > 0 && (
        <div className="mb-5 space-y-2">
          <div className="text-[10px] uppercase tracking-[0.2em] font-bold text-slate-500 mb-2">🎯 Recommendations for You</div>
          {recommendations.map((r, i) => {
            const colorMap = { high: { bg: 'var(--status-danger-bg)', border: 'var(--c-red)' }, medium: { bg: 'var(--status-warn-bg)', border: 'var(--c-amber)' }, low: { bg: 'var(--status-info-bg)', border: ROYAL } };
            const c = colorMap[r.urgency];
            return (
              <div key={i} className="p-4 rounded-xl border-l-4" style={{ background: c.bg, borderColor: c.border }}>
                <div className="flex gap-3 items-start">
                  <span className="text-2xl">{r.icon}</span>
                  <div>
                    <div className="font-bold text-slate-800 mb-1">{r.label}</div>
                    <div className="text-sm text-slate-700 leading-relaxed">{r.detail}</div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Client list */}
      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="px-5 py-3 border-b border-slate-200 flex items-center justify-between">
          <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-base font-bold">📋 Your Client Roster</div>
          <button onClick={addClient} className="text-xs font-bold px-3 py-1.5 rounded-lg text-white" style={{ background: ROYAL }}>+ Add Client</button>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead className="bg-slate-50">
              <tr>
                <th className="px-4 py-2 text-left text-[10px] uppercase font-bold text-slate-600">Client</th>
                <th className="px-4 py-2 text-right text-[10px] uppercase font-bold text-slate-600">Est. Weekly Hours</th>
                <th className="px-4 py-2 text-right text-[10px] uppercase font-bold text-slate-600">Monthly Fee</th>
                <th className="px-4 py-2 text-right text-[10px] uppercase font-bold text-slate-600">Effective $/hr</th>
                <th className="px-4 py-2"></th>
              </tr>
            </thead>
            <tbody>
              {clients.map(c => {
                const eff = c.hours > 0 ? c.fee / (c.hours * 4.33) : 0; // weekly hrs × 4.33 weeks/mo
                const isLow = eff > 0 && eff < 40;
                return (
                  <tr key={c.id} className="border-t border-slate-100">
                    <td className="px-4 py-2"><input className="w-full px-2 py-1 rounded border border-slate-200 text-sm" value={c.name} onChange={e => updateClient(c.id, 'name', e.target.value)} placeholder="Client name" /></td>
                    <td className="px-4 py-2"><input type="number" step="0.5" className="w-20 px-2 py-1 rounded border border-slate-200 text-sm text-right" value={c.hours} onChange={e => updateClient(c.id, 'hours', e.target.value)} /></td>
                    <td className="px-4 py-2"><input type="number" className="w-24 px-2 py-1 rounded border border-slate-200 text-sm text-right" value={c.fee} onChange={e => updateClient(c.id, 'fee', e.target.value)} /></td>
                    <td className="px-4 py-2 text-right font-bold font-mono" style={{ color: isLow ? '#DC2626' : eff >= 100 ? '#059669' : NAVY }}>
                      {eff > 0 ? `$${eff.toFixed(0)}` : '—'}
                    </td>
                    <td className="px-4 py-2 text-right"><button onClick={() => removeClient(c.id)} className="text-red-400 hover:text-red-600 text-sm">✕</button></td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}



// ═══════════════════════════════════════════════════════════════════
// COMPONENT: PAYMENT TRACKER (Run Your Practice)
// ═══════════════════════════════════════════════════════════════════

function PaymentTracker() {
  const cur = useCurrency();
  const [invoices, setInvoices] = useState([
    { id: 1, client: 'Sunrise E-Commerce', invoiceNum: 'INV-2026-014', amount: 1500, issueDate: '2026-05-01', dueDate: '2026-05-15', status: 'paid', paidDate: '2026-05-12' },
    { id: 2, client: 'Bright Path Marketing', invoiceNum: 'INV-2026-015', amount: 2000, issueDate: '2026-05-01', dueDate: '2026-05-15', status: 'overdue', paidDate: null },
    { id: 3, client: 'Ramirez Real Estate', invoiceNum: 'INV-2026-016', amount: 800, issueDate: '2026-05-10', dueDate: '2026-05-25', status: 'sent', paidDate: null },
  ]);
  const [loaded, setLoaded] = useState(false);
  const [showAdd, setShowAdd] = useState(false);
  const [draft, setDraft] = useState({ client: '', invoiceNum: '', amount: 0, issueDate: new Date().toISOString().slice(0,10), dueDate: '', status: 'sent' });

  useEffect(() => {
    (async () => {
      try { const r = await window.storage.get('payments:invoices'); if (r?.value) setInvoices(JSON.parse(r.value)); } catch {}
      setLoaded(true);
    })();
  }, []);
  useEffect(() => { if (loaded) window.storage.set('payments:invoices', JSON.stringify(invoices)).catch(()=>{}); }, [invoices, loaded]);

  const today = new Date().toISOString().slice(0, 10);
  const daysOverdue = (dueDate) => {
    const diff = (new Date(today) - new Date(dueDate)) / (1000 * 60 * 60 * 24);
    return Math.max(0, Math.floor(diff));
  };

  // Auto-update status
  const computedInvoices = invoices.map(inv => {
    if (inv.status === 'paid') return inv;
    if (today > inv.dueDate) return { ...inv, status: 'overdue' };
    return inv;
  });

  const addInvoice = () => {
    if (!draft.client || !draft.amount) return;
    const id = Math.max(0, ...invoices.map(i => i.id)) + 1;
    setInvoices([...invoices, { ...draft, id, paidDate: null }]);
    setDraft({ client: '', invoiceNum: '', amount: 0, issueDate: today, dueDate: '', status: 'sent' });
    setShowAdd(false);
  };
  const markPaid = (id) => setInvoices(invoices.map(i => i.id === id ? { ...i, status: 'paid', paidDate: today } : i));
  const markUnpaid = (id) => setInvoices(invoices.map(i => i.id === id ? { ...i, status: 'sent', paidDate: null } : i));
  const removeInvoice = (id) => setInvoices(invoices.filter(i => i.id !== id));

  // Totals
  const outstanding = computedInvoices.filter(i => i.status !== 'paid').reduce((s, i) => s + Number(i.amount), 0);
  const overdueTotal = computedInvoices.filter(i => i.status === 'overdue').reduce((s, i) => s + Number(i.amount), 0);
  const overdueCount = computedInvoices.filter(i => i.status === 'overdue').length;
  const paidThisMonth = computedInvoices.filter(i => i.status === 'paid' && i.paidDate && i.paidDate >= today.slice(0,7)+'-01').reduce((s, i) => s + Number(i.amount), 0);

  // Dunning email templates
  const dunningTemplates = {
    1: { subject: 'Friendly reminder — Invoice [INVOICE_NUMBER]', body: `Hi [CLIENT_FIRST_NAME],\n\nJust a friendly reminder that invoice [INVOICE_NUMBER] for $[AMOUNT] was due on [DUE_DATE]. I know things get busy — could you let me know when I can expect payment?\n\nThanks,\n[YOUR_NAME]` },
    7: { subject: 'Invoice [INVOICE_NUMBER] now 7 days past due', body: `Hi [CLIENT_FIRST_NAME],\n\nI wanted to follow up — invoice [INVOICE_NUMBER] for $[AMOUNT] is now 7 days overdue. \n\nIf there's any issue with the invoice or if you'd prefer a different payment method (Wise, PayPal, ACH), please let me know and I'll send updated payment details.\n\nLooking forward to your response.\n\nBest,\n[YOUR_NAME]` },
    14: { subject: 'Invoice [INVOICE_NUMBER] — 2 weeks overdue', body: `Hi [CLIENT_FIRST_NAME],\n\nInvoice [INVOICE_NUMBER] for $[AMOUNT] is now 14 days past due. I haven't heard back on my last reminder.\n\nI want to make sure there isn't a billing issue or something I'm missing on my end. Could we get this resolved this week? \n\nIf payment isn't received by [DEADLINE], I'll need to pause work on your account until we get current. I'd much rather not — let's get this sorted.\n\nThanks,\n[YOUR_NAME]` },
    30: { subject: 'Account paused — Invoice [INVOICE_NUMBER] (30+ days past due)', body: `Hi [CLIENT_FIRST_NAME],\n\nAs of today, invoice [INVOICE_NUMBER] is 30+ days past due, and I haven't received a response to my previous emails.\n\nPer our engagement letter, I'm pausing all bookkeeping work on your account effective immediately. I'll resume once the outstanding balance of $[AMOUNT] is cleared.\n\nIf there's something going on, please let me know — I'm always willing to work out a payment plan. But silence isn't an option going forward.\n\n[YOUR_NAME]` },
  };
  const [showDunning, setShowDunning] = useState(null);

  const fmt = (n) => cur.fmt2(n);

  const exportCSV = () => {
    const headers = ['Client', 'Invoice #', 'Amount', 'Issue Date', 'Due Date', 'Status', 'Paid Date'];
    const rows = computedInvoices.map(i => [i.client, i.invoiceNum, i.amount, i.issueDate, i.dueDate, i.status, i.paidDate || '']);
    const csv = [headers, ...rows].map(r => r.map(x => `"${String(x).replace(/"/g, '""')}"`).join(',')).join('\n');
    downloadFile(csv, `payment_tracker_${today}.csv`, 'text/csv');
  };

  return (
    <div>
      <SectionHead eyebrow="Run Your Practice · Tool" title="Payment Tracker · Who Owes YOU" desc="The other side of Invoice Creator. Track who has paid you, who's late, and when to send dunning emails. Filipino bookkeepers lose 10-30% of their income to slow-pay and no-pay clients. This tool surfaces those losses immediately." />

      <div className="mt-6 flex justify-end">
        <CurrencyToggle {...cur} />
      </div>

      {/* Summary cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-3 mt-3 mb-5">
        <div className="p-5 rounded-2xl bg-white border border-slate-200 shadow-sm">
          <div className="text-[10px] uppercase tracking-wider font-bold text-slate-500">Outstanding</div>
          <div style={{ color: NAVY, fontFamily: fontDisplay }} className="text-2xl font-bold mt-1">{fmt(outstanding)}</div>
          <div className="text-xs text-slate-500 mt-1">{computedInvoices.filter(i => i.status !== 'paid').length} unpaid invoices</div>
        </div>
        <div className="p-5 rounded-2xl text-white shadow-lg" style={{ background: overdueTotal > 0 ? 'linear-gradient(135deg, #DC2626 0%, #EF4444 100%)' : `linear-gradient(135deg, #94A3B8 0%, #CBD5E1 100%)` }}>
          <div className="text-[10px] uppercase tracking-wider font-bold opacity-80">Overdue</div>
          <div style={{ fontFamily: fontDisplay }} className="text-2xl font-bold mt-1">{fmt(overdueTotal)}</div>
          <div className="text-xs opacity-80 mt-1">{overdueCount} {overdueCount === 1 ? 'invoice' : 'invoices'} past due</div>
        </div>
        <div className="p-5 rounded-2xl bg-white border border-slate-200 shadow-sm">
          <div className="text-[10px] uppercase tracking-wider font-bold text-slate-500">Paid This Month</div>
          <div style={{ color: '#059669', fontFamily: fontDisplay }} className="text-2xl font-bold mt-1">{fmt(paidThisMonth)}</div>
        </div>
        <div className="p-5 rounded-2xl bg-white border-2 shadow-md" style={{ borderColor: CYAN }}>
          <div className="text-[10px] uppercase tracking-wider font-bold" style={{ color: ROYAL }}>Total Invoices</div>
          <div style={{ color: NAVY, fontFamily: fontDisplay }} className="text-2xl font-bold mt-1">{computedInvoices.length}</div>
        </div>
      </div>

      {/* Add invoice */}
      <div className="mb-5">
        {!showAdd ? (
          <button onClick={() => setShowAdd(true)} className="px-4 py-2.5 rounded-lg text-white text-sm font-bold shadow" style={{ background: `linear-gradient(135deg, ${ROYAL} 0%, ${CYAN} 100%)` }}>+ Add Invoice</button>
        ) : (
          <div style={{ background: SHEEN }} className="glass-card p-5 rounded-2xl">
            <div className="text-[10px] uppercase tracking-[0.2em] font-bold mb-3" style={{ color: ROYAL }}>New Invoice</div>
            <div className="grid grid-cols-1 md:grid-cols-6 gap-2">
              <input placeholder="Client name" className="md:col-span-2 px-3 py-2 rounded-lg border border-slate-300 text-sm" value={draft.client} onChange={e => setDraft({ ...draft, client: e.target.value })} />
              <input placeholder="Invoice #" className="px-3 py-2 rounded-lg border border-slate-300 text-sm" value={draft.invoiceNum} onChange={e => setDraft({ ...draft, invoiceNum: e.target.value })} />
              <input type="number" placeholder="Amount (USD)" className="px-3 py-2 rounded-lg border border-slate-300 text-sm" value={draft.amount || ''} onChange={e => setDraft({ ...draft, amount: Number(e.target.value) })} />
              <input type="date" className="px-3 py-2 rounded-lg border border-slate-300 text-sm" value={draft.issueDate} onChange={e => setDraft({ ...draft, issueDate: e.target.value })} />
              <input type="date" placeholder="Due date" className="px-3 py-2 rounded-lg border border-slate-300 text-sm" value={draft.dueDate} onChange={e => setDraft({ ...draft, dueDate: e.target.value })} />
            </div>
            <div className="flex gap-2 mt-3">
              <button onClick={addInvoice} disabled={!draft.client || !draft.amount} className="px-4 py-2 rounded-lg text-white text-sm font-bold disabled:opacity-50" style={{ background: ROYAL }}>Save</button>
              <button onClick={() => setShowAdd(false)} className="px-4 py-2 rounded-lg bg-white border border-slate-300 text-sm font-bold">Cancel</button>
            </div>
          </div>
        )}
      </div>

      {/* Invoice list */}
      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden mb-5">
        <div className="px-5 py-3 border-b border-slate-200 flex items-center justify-between">
          <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-base font-bold">📋 All Invoices</div>
          {computedInvoices.length > 0 && (
            <button onClick={exportCSV} className="text-xs font-bold px-3 py-1.5 rounded-lg border border-slate-300 hover:border-blue-400 text-slate-700 flex items-center gap-1.5">
              <Download size={12} /> CSV
            </button>
          )}
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead className="bg-slate-50">
              <tr>
                <th className="px-4 py-2 text-left text-[10px] uppercase font-bold text-slate-600">Client / Invoice</th>
                <th className="px-4 py-2 text-right text-[10px] uppercase font-bold text-slate-600">Amount</th>
                <th className="px-4 py-2 text-center text-[10px] uppercase font-bold text-slate-600">Issue / Due</th>
                <th className="px-4 py-2 text-center text-[10px] uppercase font-bold text-slate-600">Status</th>
                <th className="px-4 py-2 text-right text-[10px] uppercase font-bold text-slate-600">Actions</th>
              </tr>
            </thead>
            <tbody>
              {computedInvoices.sort((a,b) => {
                if (a.status !== b.status) {
                  if (a.status === 'overdue') return -1;
                  if (b.status === 'overdue') return 1;
                  if (a.status === 'paid') return 1;
                  if (b.status === 'paid') return -1;
                }
                return b.dueDate.localeCompare(a.dueDate);
              }).map(inv => {
                const overdueDays = inv.status === 'overdue' ? daysOverdue(inv.dueDate) : 0;
                const statusColor = inv.status === 'paid' ? 'var(--status-ok-fg)' : inv.status === 'overdue' ? 'var(--status-danger-fg)' : 'var(--status-info-fg)';
                const statusBg = inv.status === 'paid' ? 'var(--status-ok-bg)' : inv.status === 'overdue' ? 'var(--status-danger-bg)' : 'var(--status-info-bg)';
                return (
                  <tr key={inv.id} className="border-t border-slate-100">
                    <td className="px-4 py-3">
                      <div className="font-semibold text-slate-800">{inv.client}</div>
                      <div className="text-xs text-slate-500">{inv.invoiceNum}</div>
                    </td>
                    <td className="px-4 py-3 text-right font-bold font-mono" style={{ color: NAVY }}>{fmt(inv.amount)}</td>
                    <td className="px-4 py-3 text-center text-xs text-slate-600">
                      <div>{inv.issueDate}</div>
                      <div className="text-slate-400">→ {inv.dueDate}</div>
                    </td>
                    <td className="px-4 py-3 text-center">
                      <span className="px-2 py-1 rounded-md text-xs font-bold" style={{ background: statusBg, color: statusColor }}>
                        {inv.status === 'paid' ? `✓ Paid` : inv.status === 'overdue' ? `${overdueDays}d overdue` : 'Sent'}
                      </span>
                    </td>
                    <td className="px-4 py-3 text-right">
                      <div className="flex justify-end gap-1">
                        {inv.status === 'overdue' && (
                          <button onClick={() => setShowDunning(inv)} className="text-xs font-bold px-2 py-1 rounded-md bg-amber-100 text-amber-700 hover:bg-amber-200">📧 Dun</button>
                        )}
                        {inv.status !== 'paid' ? (
                          <button onClick={() => markPaid(inv.id)} className="text-xs font-bold px-2 py-1 rounded-md text-white" style={{ background: '#059669' }}>✓ Paid</button>
                        ) : (
                          <button onClick={() => markUnpaid(inv.id)} className="text-xs font-bold px-2 py-1 rounded-md bg-slate-200 text-slate-700">Undo</button>
                        )}
                        <button onClick={() => removeInvoice(inv.id)} className="text-xs px-1.5 py-1 text-red-400 hover:text-red-600">✕</button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Dunning email modal */}
      {showDunning && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6" style={{ background: 'rgba(15, 23, 42, 0.6)' }} onClick={() => setShowDunning(null)}>
          <div className="bg-white rounded-2xl max-w-3xl w-full max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
            <div className="px-6 py-4 border-b border-slate-200 flex items-center justify-between" style={{ background: SHEEN }}>
              <div>
                <div className="text-[10px] uppercase tracking-[0.2em] font-bold" style={{ color: ROYAL }}>Dunning Email Templates</div>
                <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-lg font-bold">{showDunning.client} · {fmt(showDunning.amount)} · {daysOverdue(showDunning.dueDate)} days overdue</div>
              </div>
              <button onClick={() => setShowDunning(null)} className="text-slate-400 hover:text-slate-700"><X size={20} /></button>
            </div>
            <div className="p-6 space-y-4">
              {Object.entries(dunningTemplates).map(([days, tpl]) => {
                const isApplicable = daysOverdue(showDunning.dueDate) >= Number(days);
                const subject = tpl.subject.replace('[INVOICE_NUMBER]', showDunning.invoiceNum);
                const body = tpl.body
                  .replace(/\[CLIENT_FIRST_NAME\]/g, showDunning.client.split(' ')[0])
                  .replace(/\[INVOICE_NUMBER\]/g, showDunning.invoiceNum)
                  .replace(/\[AMOUNT\]/g, '$' + Number(showDunning.amount).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 }))
                  .replace(/\[DUE_DATE\]/g, showDunning.dueDate)
                  .replace(/\[DEADLINE\]/g, new Date(Date.now() + 7*86400000).toISOString().slice(0,10))
                  .replace(/\[YOUR_NAME\]/g, '[Your Name]');
                return (
                  <div key={days} className={`p-4 rounded-xl border-2 ${isApplicable ? 'border-blue-400 bg-blue-50/40' : 'border-slate-200 opacity-60'}`}>
                    <div className="flex items-center justify-between mb-2">
                      <div className="font-bold text-slate-800">{days} Days Overdue Template {isApplicable && <span className="text-xs text-blue-600 ml-2">← Use this one</span>}</div>
                      <button onClick={() => { navigator.clipboard.writeText(`Subject: ${subject}\n\n${body}`); }} className="text-xs font-bold px-3 py-1 rounded-md text-white" style={{ background: ROYAL }}>📋 Copy</button>
                    </div>
                    <div className="text-xs font-bold text-slate-600 mb-1">Subject: <span className="font-normal">{subject}</span></div>
                    <div className="text-sm text-slate-700 whitespace-pre-wrap bg-white p-3 rounded-lg border border-slate-200">{body}</div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}



